void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 center = vec2(0.5);
    vec2 p = (uv - center) * 2.0;

    // Isometric projection setup
    vec3 pos;
    pos.x = p.x - p.y;
    pos.y = (p.x + p.y) * 0.707;
    pos.z = sin(iTime * 3.1415) * 0.5; // Floating slab

    // 2-second loop factor for cooking cycle
    float t = mod(iTime, 2.0);
    float cook = sin(t * 3.1415); // 0 to 1 to 0

    // Generate grid-like noise for the "crust" texture
    vec3 q = pos * 4.0;
    float grid = abs(sin(q.x)) + abs(sin(q.y)) + abs(sin(q.z));
    grid = 1.0 - smoothstep(0.3, 0.8, grid);

    // Simulate Maillard reaction: Heat spreads from surface/edges
    float heat = 1.0 - length(pos.xy);
    heat *= (1.0 - abs(pos.z)); // Center is hottest

    // Pulsewave effect
    float pulse = cos(t * 6.28 + grid * 10.0);
    pulse = smoothstep(-0.8, 0.8, pulse);

    // Color mixing: Raw (white/pink) -> Maillard (tan/brown) -> Char (black)
    vec3 raw = vec3(0.95, 0.85, 0.80);
    vec3 seared = vec3(0.65, 0.45, 0.25);
    vec3 charred = vec3(0.05, 0.02, 0.01);

    vec3 color = mix(raw, seared, smoothstep(0.0, 0.6, cook));
    color = mix(color, charred, smoothstep(0.6, 1.0, cook * heat * pulse));

    // Add depth shading to the isometric block
    float depth = 1.0 - smoothstep(-1.0, 1.0, pos.z);
    color *= depth * 0.5 + 0.5;

    // Add grid lines overlay
    if (grid > 0.7) {
        color = mix(color, vec3(0.0), 0.4);
    }

    // Vignette for scientific focus
    float vignette = 1.0 - length(p) * 0.6;
    color *= vignette;

    fragColor = vec4(color, 1.0);
}

// Helper to create grid lines
float gridLine(vec2 uv, float freq, float w, float h) {
    vec2 f = fract(uv * freq);
    float x = step(w, f.x);
    float y = step(h, f.y);
    return step(1.9, x + y); // Returns 1.0 only if both lines overlap (intersection) or adjust logic
    // Actually, let's do a grid of cells:
    // return (step(w, f.x) + step(h, f.y)) >= 1.0 ? 1.0 : 0.0;
}

// Corrected grid function returning float
float makeGrid(vec2 uv, float s, float w, float h) {
    vec2 f = fract(uv * s);
    float gx = step(w, f.x);
    float gy = step(h, f.y);
    // Create a grid pattern: 1.0 where lines cross or fill
    return step(1.9, gx + gy); 
}

float pulse(float t) {
    return smoothstep(0.4, 0.8, abs(sin(t * 3.14159)));
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    uv = (uv - 0.5) * 2.0;
    uv.x *= iResolution.x / iResolution.y;

    float t = iTime;
    float loopedT = t * 2.0; // 2.0s loop
    float p = pulse(loopedT); // 0.0 to 1.0 pulse

    float freq = 12.0 + 10.0 * p;

    // Base background (dark obsidian)
    vec3 col = vec3(0.02, 0.02, 0.04);

    // Layer 1: Cyan (Cold)
    vec2 uv1 = uv;
    float g1 = makeGrid(uv1, freq, 0.2, 0.2);
    vec3 ink1 = vec3(0.2, 0.6, 0.9);
    col += ink1 * g1 * (0.5 + 0.5 * p);

    // Layer 2: Magenta (Heat) - Shifted
    vec2 uv2 = uv + vec2(0.04, -0.04) * p;
    float g2 = makeGrid(uv2, freq * 0.8, 0.25, 0.25);
    vec3 ink2 = vec3(0.9, 0.2, 0.4);
    col += ink2 * g2 * p;

    // Layer 3: Yellow (Resonance) - Opposite Shift
    vec2 uv3 = uv + vec2(-0.04, 0.04) * p;
    float g3 = makeGrid(uv3, freq * 1.2, 0.15, 0.15);
    vec3 ink3 = vec3(0.8, 0.9, 0.2);
    col += ink3 * g3 * (1.0 - p);

    // Layer 4: Deep Black (Void)
    float g4 = makeGrid(uv, freq * 0.5, 0.4, 0.4);
    vec3 ink4 = vec3(0.05, 0.0, 0.05);
    col += ink4 * g4 * (1.0 - smoothstep(0.0, 0.5, p));

    // Risograph Quantization: Hard steps
    // We manually quantize the result to 4-5 levels to mimic ink bands
    int steps = 5;
    col = floor(col * float(steps)) / float(steps);

    // Vignette
    float vign = 1.0 - length(uv) * 0.5;
    col *= smoothstep(0.0, 1.0, vign);

    fragColor = vec4(col, 1.0);
}

vec3 hsv2rgb(vec3 c) {
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

vec2 rotate(vec2 x, float a) {
    float s = sin(a), c = cos(a);
    return mat2(c, -s, s, c) * x;
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// Fuzzy evergreen-like noise layer
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for(int i = 0; i < 5; i++) {
        v += a * noise(p);
        p *= 2.0;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Aspect ratio correction handled by dividing by iResolution.y, 
    // but we need to scale x to match y for circular symmetry if desired, 
    // or keep it stretched. Let's keep it circular relative to Y.
    uv.x *= iResolution.y / iResolution.x;

    float t = iTime;
    float loop = mod(t, 2.0);

    vec2 p = uv;
    float dist = length(uv);

    // Infographic-style grid background (faint)
    vec2 grid = fract(uv * 10.0);
    float gridVal = smoothstep(0.45, 0.5, abs(grid.x - 0.5)) + smoothstep(0.45, 0.5, abs(grid.y - 0.5));
    gridVal *= 0.05; // Subtle

    // Color Confinement: 3 Quark Colors
    float hueBase = fract(loop / 2.0);
    vec3 col1 = hsv2rgb(vec3(hueBase, 0.8, 1.0));
    vec3 col2 = hsv2rgb(vec3(hueBase + 0.33, 0.8, 1.0));
    vec3 col3 = hsv2rgb(vec3(hueBase + 0.66, 0.8, 1.0));

    vec3 finalColor = vec3(0.0);

    // Spirograph logic with fuzzy confinement
    for(int i = 0; i < 3; i++) {
        vec3 qCol = (i==0) ? col1 : (i==1) ? col2 : col3;

        // Rotate quarks around center
        float angle = (float(i) * 2.0 * 3.14159 / 3.0) + loop * 3.0;
        vec2 qPos = rotate(vec2(0.25, 0.0), angle);

        // Spirograph motion (hypotrochoid-ish)
        vec2 offset = qPos + rotate(vec2(0.1), -loop * 5.0 + float(i)*2.0) + rotate(vec2(0.05), loop * 8.0 + float(i));

        // Distance to current quark spiral
        float d = length(p - offset);

        // "Confinement" effect: The further from the center, the tighter the pull/blur
        float confinement = 1.0 - smoothstep(0.0, 1.5, dist);

        // Fuzzy edge based on noise
        float fuzz = fbm(p * 20.0 - loop * 5.0);

        // Draw the "Flux Tube"
        float intensity = (1.0 - smoothstep(0.02, 0.06, d)) * (1.0 + fuzz * 0.5);

        // Add interference pattern for "Color Charge" visualization
        float interference = sin(p.x * 20.0 - loop * 10.0) * sin(p.y * 20.0 + loop * 10.0);
        intensity += (interference * 0.1) * (1.0 - length(p - offset) * 5.0);
        intensity = max(0.0, intensity);

        // Bloom effect
        intensity = pow(intensity, 0.7);

        finalColor += qCol * intensity * 0.8 * confinement;
    }

    // Central "Gluon" core
    float core = 1.0 - smoothstep(0.0, 0.15, dist);
    finalColor += vec3(1.0, 1.0, 1.0) * pow(core, 3.0) * 1.2;

    // Combine with background grid and vignette
    finalColor += vec3(0.02, 0.02, 0.02) * gridVal;
    finalColor *= 1.0 / (1.0 + dist * dist * 0.5);

    // Tone mapping
    finalColor = pow(finalColor, vec3(0.9));

    fragColor = vec4(finalColor, 1.0);
}

vec2 hash21(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return -1.0 + 2.0 * fract(sin(p) * 43758.5453123);
}

float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    vec2 a = hash21(i);
    return mix(a[1] - a[0], a[0] - a[1], f.x);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 p = (uv - 0.5) * 2.0;

    // Aspect correction
    p.x *= iResolution.x / iResolution.y;

    float t = iTime;
    float loopT = sin(t * 3.14159); // -1 to 1 over 2 seconds

    // Quantum Zeno "Freeze" factor: near peaks of sine, time slows/stops
    float zeno = smoothstep(0.9, 1.0, abs(loopT));

    // Base radius pulsing
    float r = length(p);
    float baseFreq = 8.0 - loopT * 2.0; // 6 to 10

    // Spirograph/Fuzzy Evergreen structure
    float angle = atan(p.y, p.x) + t * 0.5;
    float arm = sin(angle * 7.0 + t * 2.0);

    // The "Measurement" field
    float field = sin(r * baseFreq * 4.0 - t * 4.0) * arm;

    // Dot Matrix Logic
    // Grid coordinates
    vec2 grid = gl_FragCoord.xy * 0.15; // Dot spacing
    vec2 gridF = fract(grid);

    // Create a circular dot shape at the center of each grid cell
    float dist = length(gridF - 0.5);
    float dotMask = 1.0 - smoothstep(0.15, 0.3, dist);

    // Thresholding the field against noise to create the Zeno effect
    // High noise makes it fuzzy/chaotic. Low noise (Zeno active) makes it crisp.
    float n = noise(p * 15.0 + t);

    // Zeno Effect: When 'zeno' is high, the pattern becomes extremely sharp and static
    // When 'zeno' is low, it dissolves into noise.
    float threshold = 0.2 + n * 0.4 * (1.0 - zeno);

    // The pattern itself
    float pattern = sin(field) * 0.5 + 0.5;

    // Combine: Only show dots where the pattern is high and we pass the threshold
    // This creates the "printing" effect
    float val = smoothstep(threshold - 0.1, threshold, pattern) * dotMask;

    // Color: Monochrome thermal paper vibe
    vec3 col = vec3(0.1, 0.1, 0.15) + val * vec3(1.0, 0.9, 0.8);

    // Add a slight scanline flicker for the "printer" feel
    float scan = step(0.95, sin(gl_FragCoord.y * 0.1 + t * 10.0)) * 0.05;
    col -= scan;

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);
    float t = iTime;

    // Loop t to 0.0 - 2.0 exactly
    float loopT = mod(t, 2.0);
    float p = loopT * 2.0 * 3.14159; // 0 to 4PI over 2 seconds

    // Sprio-fuzzy base coordinate
    vec2 pUV = uv * 3.0;
    float dist = length(pUV);

    // Time-warped rotation
    float angle = (pUV.y / pUV.x + dist) * (2.0 + sin(p * 1.5));
    float s = sin(angle);
    float c = cos(angle);

    vec2 rot = vec2(pUV.x * c - pUV.y * s, pUV.x * s + pUV.y * c);

    // Fractal flocking compression (The "War")
    float f = 0.0;
    for(float i = 0.0; i < 4.0; i++) {
        rot = fract(rot * 1.5) - 0.5;
        float d = length(rot);
        f += sin(d * 10.0 + p * 3.0 + i) / (i + 1.0);
    }

    // Color Palette: Outback (Ochre, Green, Rust)
    vec3 col1 = vec3(0.4, 0.15, 0.05); // Dust/Rust
    vec3 col2 = vec3(0.05, 0.25, 0.05); // Evergreen
    vec3 col3 = vec3(0.8, 0.1, 0.0); // Alert Red

    // Mix based on time and distance
    float mixF = smoothstep(0.2, 0.8, dist + f * 0.2);
    vec3 base = mix(col2, col1, mixF);

    // Add the "Emu" stampede energy
    float energy = sin(f * 5.0 + t * 10.0);
    base += col3 * max(0.0, energy) * 0.3;

    // Final Bloom/Compression effect
    float glow = exp(-length(uv) * 2.0) * 0.1;
    base += glow * vec3(1.0, 0.8, 0.6);

    // Tone mapping
    fragColor = vec4(base + 0.1 * sin(loopT * 10.0), 1.0);
}

void main() {
    float loopTime = fract(iTime * 0.5);
    float phase = iTime * 2.0;

    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);
    uv.x *= 1.5;

    float baseY = sin(uv.x * 6.0 + phase * 3.0);

    float noiseX = sin(uv.x * 100.0 + iTime * 50.0) * cos(uv.x * 120.0);
    float stepShift = step(0.0, sin(iTime * 4.0 + uv.x * 10.0));

    float distortion = (noiseX * 0.02) + (stepShift * 0.04 * sin(uv.x * 20.0 + iTime * 10.0));
    float finalY = baseY + distortion;

    float dist = abs(uv.y - finalY);

    float width = 0.003 + distortion * 0.5;
    float trace = 1.0 - smoothstep(0.0, width * 4.0, dist);

    float fuzz = 0.0;
    if (dist < width * 10.0) {
        fuzz = smoothstep(width * 10.0, width * 2.0, dist) * (0.5 + 0.5 * sin(iTime * 20.0 + uv.x * 50.0));
    }

    vec3 colorBase = vec3(0.1, 0.9, 0.2);
    vec3 colorDark = vec3(0.0, 0.4, 0.1);

    float intensity = trace * 1.2 + fuzz * 0.3;
    vec3 finalColor = mix(vec3(0.0), colorBase, intensity) + (fuzz * 0.2 * colorDark);

    float vignette = 1.0 - smoothstep(0.5, 2.0, length(uv));
    float scanline = abs(sin(gl_FragCoord.y * 1.5 + iTime * 50.0)) * 0.05;

    finalColor *= vignette;
    finalColor += scanline * vec3(0.1);

    finalColor = pow(finalColor, vec3(0.9));

    fragColor = vec4(finalColor, 1.0);
}

void mainImage(vec2 fragCoord, vec2 resolution, float time, out vec4 fragColor) {
    vec2 uv = fragCoord / resolution;
    vec2 uv0 = uv - 0.5;
    uv0.x *= resolution.x / resolution.y;

    float t = time;
    float loopT = fract(t * 0.5); // 2-second loop cycle

    // Base darkboard
    vec3 col = vec3(0.05, 0.05, 0.06);

    // Silo structural memory: concentric vertical rings that fade
    float d = length(uv0);
    float rings = 1.0 - smoothstep(0.4, 0.6, d);

    // Evergreen spirograph fuzz
    vec2 p = uv0;
    float s = 0.0;
    float n = 0.0;

    // Time modulation for loop
    float a = loopT * 6.2831;
    float b = (1.0 - loopT) * 6.2831;

    for (float i = 0.0; i < 5.0; i++) {
        p = fract(p * 1.5) - 0.5;
        float f = length(p) * 2.0;

        // Shift colors based on loop phase
        float green = sin(f * 10.0 - t * 2.0) * 0.5 + 0.5;
        float chart = cos(f * 10.0 - t * 3.0) * 0.5 + 0.5;

        // Structural memory: vertical lines that turn into curves
        float vert = sin(p.y * 20.0 - t * 5.0) * 0.5 + 0.5;
        float curve = sin(length(p) * 15.0 + t * 2.0) * 0.5 + 0.5;

        s += (green * 0.4 + chart * 0.2) * (1.0 - d);

        // Silo geometry overlay
        s += vert * curve * (0.1 / (i + 1.0));
    }

    // Add chalk dust texture
    float noise = sin(uv.x * 100.0 + t) * sin(uv.y * 100.0 - t);
    float dust = smoothstep(0.8, 1.0, noise + s);

    // Color grading: Green everywhere
    vec3 baseGreen = vec3(0.1, 0.4, 0.2);
    vec3 highlight = vec3(0.2, 0.9, 0.4);

    col = mix(baseGreen, highlight, s * rings);
    col = mix(col, vec3(0.0), 1.0 - dust);

    // Add "chalk" opacity
    col += vec3(0.8, 0.9, 0.7) * dust * 0.3;

    fragColor = vec4(col, 1.0);
}

void main() {
    mainImage(gl_FragCoord.xy, iResolution.xy, iTime, fragColor);
}

void main() {
    // Normalize coordinates centered on screen
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    vec2 uv0 = uv;

    // Loop time: 2 seconds
    float t = mod(iTime, 2.0);

    // Sonic Boom Phase: 0.0 to 1.0 (Explosion), 1.0 to 2.0 (Calm/Reset)
    // We want a sharp "boom" in the middle.
    float cycle = mod(t * 3.0, 1.0); 
    // FIX: Use smoothstep or conditional logic instead of boolean in math context if needed,
    // but here we just need a float factor.
    float boomFactor = 1.0 - step(0.5, cycle); // 1.0 during "boom" (0-0.5), 0.0 during reset

    // Motion: Oscillating spirograph/vortex movement
    float s = sin(t);
    float c = cos(t);

    // The "Boom" distortion factor
    float dist = 0.0;
    if (cycle < 0.5) {
        // Explosion phase: lines get pushed outward violently
        dist = (1.0 - cycle * 2.0) * 4.0 * (1.0 - length(uv0) * 0.8);
    } else {
        // Reset phase: calm, slight vibration
        dist = (cycle - 0.5) * 2.0;
    }

    float f = dist + 0.2;

    // 19th Century Plate: Layered Noise and Grayscale
    vec3 col = vec3(0.0);

    // Background: Sepia/Stone Paper
    float bg = 0.12 + 0.08 * sin(uv.x * 10.0 + uv.y * 5.0);

    // The "Plunger" Shape & Sonic Rings
    for (float i = 0.0; i < 6.0; i++) {
        uv = abs(uv) - 1.0; // Folding space for spirograph symmetry

        // Distort radius based on the boom
        vec2 p = vec2(
            cos(f * 1.0) * uv.x - sin(f * 1.0) * uv.y,
            sin(f * 1.0) * uv.x + cos(f * 1.0) * uv.y
        );

        // Add a "plunger" bell shape
        float d = length(p) - (0.5 - dist * 0.2);

        // Sonic Wave Rings
        float wave = sin(length(p) * 20.0 - t * 20.0 + i);

        // Copperplate lines: high frequency noise
        float detail = fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);

        // Combine into an engraved line look
        float line = smoothstep(0.0, 0.02, abs(d)) * (0.1 + detail * 0.9);

        // Color palette: Verdigris (Green) + Oxidized Copper + White Ink
        // Base: Dark Green/Slate
        vec3 ink = vec3(0.1, 0.3, 0.25); 
        vec3 paper = vec3(0.95, 0.92, 0.85);
        vec3 highlight = vec3(0.9, 1.0, 0.9);

        // Mix colors based on the "boom" intensity
        float boomColor = smoothstep(0.4, 0.6, cycle);
        vec3 color = mix(paper, ink, 0.9 - boomColor * 0.5);

        // Apply the lines
        color = mix(color, highlight, line);

        // Add "fuzzy evergreen" noise to the lines
        color += vec3(0.1, 0.4, 0.2) * detail * boomFactor;

        col = max(col, color * 0.4); // Additive blending for layers
    }

    // Final vignette to focus the center
    float vignette = 1.0 - length(uv0) * 0.5;
    col *= vignette;

    // Scanline/Plate artifacting
    float scan = sin(gl_FragCoord.y * 2.0 - iTime) * 0.05;
    col += scan;

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = iTime;

    // 2-second loop cycle
    float loop = fract(t * 0.5); 
    float pulse = sin(loop * 6.283) * 0.5 + 0.5;

    // Base woodblock background (copper/green oxidation)
    vec3 base = mix(vec3(0.2, 0.3, 0.1), vec3(0.4, 0.6, 0.2), loop);

    // Concentric rings (The Coin)
    float dist = length(uv);
    float rings = fract(dist * 15.0 - loop * 4.0);
    float ringMask = smoothstep(0.0, 0.02, rings);

    // Spiral/Fibonacci drift (Silk Road path)
    float angle = atan(uv.y, uv.x);
    float spiral = sin(angle * 8.0 + dist * 10.0 - loop * 5.0);
    float spiralMask = smoothstep(-0.2, -0.1, spiral);

    // Wood grain texture (Fuzzy evergreen nudge)
    float noise = fract(sin(dot(uv, vec2(12.9898, 78.233)) * 43758.5453));
    float grain = smoothstep(0.4, 0.6, noise);

    // Combine elements
    float pattern = mix(ringMask, spiralMask, sin(t * 3.0) * 0.5 + 0.5);

    // "Ink Drift" effect
    vec3 ink = vec3(0.05, 0.2, 0.1); // Deep green ink
    float alpha = pattern * pulse * (0.5 + 0.5 * sin(dist * 20.0 - t * 4.0));

    // Woodblock relief lighting
    float relief = (grain - 0.5) * 0.2;

    vec3 finalColor = mix(base, ink, alpha);
    finalColor += vec3(relief * (1.0 - alpha));

    // Vignette for the paper edge
    float vig = smoothstep(1.5, 0.5, length(uv));
    finalColor *= vig;

    fragColor = vec4(finalColor, 1.0);
}

float sin2d(vec2 p) {
    return sin(p.x * 3.0 + p.y * 2.0) * cos(p.y * 3.0 - p.x * 2.0) * 0.5 + 0.5;
}

float osc(float t) {
    float cycle = mod(t, 2.0) / 2.0;
    float wave = sin(cycle * 6.2831 * 3.5); 

    // Apnea event: flatten the wave after t=1.4s
    float flatness = smoothstep(0.68, 0.72, cycle);

    // Smooth transition back to start for loop
    float reset = smoothstep(0.98, 1.0, cycle);

    float signal = mix(wave, 0.0, flatness + reset);
    return signal;
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    vec2 p = uv;

    float time = iTime;
    float tNorm = mod(time, 2.0);

    // Render the history: p.x maps to time offset across the screen
    // We scale p.x so the full 2s loop fits nicely on screen
    float signalHist = osc(tNorm + p.x * 2.0);

    // Add fuzzy spirograph distortion to the history line
    float fuzz = sin2d(vec2(tNorm * 20.0, p.y * 20.0)) * 0.05;

    // Calculate local cycle to determine if we are in the "flat" zone
    float localCycle = mod(tNorm + p.x * 2.0, 2.0) / 2.0;
    float localFlatness = smoothstep(0.68, 0.72, localCycle);
    float localReset = smoothstep(0.98, 1.0, localCycle);

    // Only add fuzz if the signal is active (not flat)
    signalHist += fuzz * (1.0 - localFlatness - localReset);

    // Distance from the center line (signal) to the pixel Y
    float d = abs(p.y - signalHist);

    // Glow profile (CRT style)
    float glow = 0.0;

    // Base line width
    float lineWidth = 0.02;

    // Apnea visual cue: The line becomes razor sharp and flat
    lineWidth = mix(lineWidth, 0.002, localFlatness);

    // Invert logic: higher sharpness = lower decay in exp
    float decayRate = 20.0 + localFlatness * 100.0;
    glow = exp(-d * decayRate);

    // Color: Neon Green / Phosphor
    vec3 colorBase = vec3(0.0, 0.8, 0.4);
    vec3 colorFlat = vec3(0.1, 0.5, 0.2); // Dimmer green for apnea

    // Mix color based on signal activity (flat = dead)
    vec3 finalColor = mix(colorBase, colorFlat, localFlatness + localReset);

    // Add a slight scanline effect
    float scanlines = sin(p.y * 100.0 + time) * 0.02;

    // Final composition
    vec4 outColor = vec4(finalColor, 1.0) * glow;
    outColor.rgb += vec3(scanlines);

    // Vignette
    float vig = 1.0 - length(p * 0.8);
    outColor.rgb *= vig;

    fragColor = outColor;
}

float hash(float n) { return fract(sin(n) * 1e4); }
float noise(vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n = p.x + p.y * 57.0;
    return mix(mix(hash(n + 0.0), hash(n + 1.0), f.x),
               mix(hash(n + 57.0), hash(n + 58.0), f.x), f.y);
}
float fbm(vec2 uv) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 4; ++i) {
        v += a * noise(uv);
        uv = rot * uv * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // 2-second loop, key strike at 0.5s relative to loop
    float t = fract(iTime / 2.0); 
    float beat = smoothstep(0.0, 0.1, t) - smoothstep(0.09, 0.11, t); 
    // Normalize beat to 0..1 pulse
    float p = (smoothstep(0.0, 0.1, t) + 0.2) * sin(t * 62.8); 
    if(t < 0.1) p = 0.0; // Reset

    // Museum glass distortion
    float dist = fbm(uv * 1.5 + vec2(iTime * 0.1));
    uv += dist * 0.05;

    // Center "Key" position
    vec2 center = vec2(0.0);

    // Radial distance for ripples
    float r = length(uv - center);

    // Sound wave propagation
    float wave = sin(r * 80.0 - p * 100.0);
    wave = max(0.0, wave);

    // Fuzzy spirograph overlay
    vec2 spiro = uv * 2.0;
    float spiro_val = sin(spiro.x * spiro.y * 20.0 + p * 10.0);
    spiro_val = max(0.0, spiro_val);

    // Vitrine lighting gradient (darker at corners)
    float vignette = 1.0 - length(uv * 0.8);
    vignette = pow(vignette, 1.5);

    // Color composition: Deep forest green to neon lime
    vec3 base = vec3(0.02, 0.08, 0.05);
    vec3 highlight = vec3(0.1, 0.4, 0.2);

    // Mix wave, spiro, and light
    float intensity = (wave * 0.5 + spiro_val * 0.2) * vignette;

    // The "Strike" flash
    float flash = smoothstep(0.99, 0.5, 1.0 - abs(t - 0.5)); // Simple loop trigger
    float impact = smoothstep(0.0, 0.2, p) * 0.8;

    vec3 col = base + intensity * vec3(0.2, 0.8, 0.4) * 4.0;
    col += vec3(0.3, 0.9, 0.5) * impact * (1.0 - r * 0.5); // Key glow

    // Add noise grain for film texture
    float grain = fract(sin(dot(uv, vec2(12.9898, 78.233) + iTime)) * 43758.5453);
    col += grain * 0.02;

    // Final Vignette application
    col *= vignette;

    // Tone mapping
    col = col / (col + vec3(1.0));

    fragColor = vec4(col, 1.0);
}

// Helper: Simple pseudo-random based on coords and time
float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}

// 2D Value Noise
float noise(vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n00 = hash(p);
    float n10 = hash(p + vec2(1.0, 0.0));
    float n01 = hash(p + vec2(0.0, 1.0));
    float n11 = hash(p + vec2(1.0, 1.0));
    return mix(mix(n00, n10, f.x), mix(n01, n11, f.x), f.y);
}

// Fractal Brownian Motion for organic detail
float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 5; i++) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

// Signed distance to a rough organic shape (the glaze pool)
float sdGlaze(vec2 p, float t) {
    float d = length(p) - 0.35;
    // Wobble the edge based on time and noise
    float w = fbm(p * 5.0 + vec2(t * 0.5));
    d += w * 0.05;
    return d;
}

// Distance to the crack network (Voronoi-like but organic)
float crackField(vec2 p, float t) {
    // Create a grid of seeds
    vec2 i = floor(p * 4.0);
    vec2 f = fract(p * 4.0) - 0.5;

    // Move seeds slightly based on time to animate the cracks
    vec2 seed = vec2(hash(i), hash(i + 1.0)) * 0.2;

    float d = length(f - seed);

    // Modulate distance by a noise field to make cracks branch and fade
    float n = fbm(p * 3.0 + vec2(t * 2.0));
    d += n * 0.15;

    return d;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    // Normalize time to 2.0s loop
    float t = mod(iTime, 2.0);

    // --- Base Clay Texture ---
    vec3 clay = vec3(0.65, 0.42, 0.25);
    float noiseClay = fbm(uv * 20.0 + vec2(t * 0.1));
    clay *= 0.9 + 0.1 * noiseClay; // Subtle paper/clay texture

    // --- Glaze Pool ---
    float distGlaze = sdGlaze(uv * 1.5, t);
    float glazeMask = smoothstep(0.0, 0.02, distGlaze) - smoothstep(0.05, 0.07, distGlaze);
    glazeMask = clamp(glazeMask, 0.0, 1.0);

    // Inside the glaze, calculate cracks (crawling effect)
    float crackDist = crackField(uv * 8.0, t);

    // The "Crawling" effect: cracks widen/narrow over time
    float timePulse = sin(t * 3.14159 * 2.0) * 0.5 + 0.5;
    float crackWidth = 0.008 + timePulse * 0.012;

    float crackMask = 1.0 - smoothstep(crackWidth, crackWidth * 2.0, crackDist);

    // --- Color Composition ---
    // 1. The Glaze Color (Deep Evergreen/Teal)
    vec3 glazeColor = vec3(0.05, 0.45, 0.35); // Forest Green base
    // Add vitrified highlight
    glazeColor += vec3(0.2, 0.6, 0.5) * smoothstep(-0.02, 0.0, distGlaze);

    // 2. The Cracks (Burnt Orange/Brown showing through)
    vec3 crackColor = vec3(0.5, 0.2, 0.05);

    // 3. Fuzzy Edge for Field Guide Illustration look
    float edgeFuzz = smoothstep(0.02, 0.03, abs(distGlaze));

    // Combine
    vec3 finalColor = mix(clay, glazeColor, glazeMask);

    // Apply cracks: where cracks are, reveal the clay color or a darker shadow
    // Crawling implies the glaze is pulling away, revealing clay underneath
    finalColor = mix(finalColor, mix(clay, crackColor, 0.3), crackMask * glazeMask);

    // Add "Field Guide" overlay lines (subtle crosshatch or sketch lines)
    float grid = abs(sin(uv.x * 100.0)) * abs(cos(uv.y * 100.0));
    float sketchLine = smoothstep(0.95, 1.0, grid);
    finalColor -= sketchLine * 0.05; // Darken slightly where grid hits

    // Final brightness adjustment for screen
    fragColor = vec4(finalColor, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 p = (uv - 0.5) * 2.0;
    p.x *= iResolution.x / iResolution.y;

    // 2-second loop time
    float t = mod(iTime, 2.0);

    // Background: Textured parchment
    float noise = sin(p.x * 100.0) * cos(p.y * 100.0) * 0.05;
    vec3 bg = vec3(0.95, 0.92, 0.85) + noise * 0.02;

    // Field Guide Border (faint ink)
    float border = 1.0 - length(p * vec2(1.0, iResolution.y / iResolution.x)) / 1.2;
    border = clamp(border, 0.0, 1.0);
    bg -= border * 0.1;

    // Market Flow Lines (The Invisible Hand)
    vec2 flowUV = p * 8.0 + vec2(t * 3.0, t * 1.5);
    float flow = sin(flowUV.x + sin(flowUV.y * 2.0)) * sin(flowUV.y + cos(flowUV.x * 2.0));
    float flowLines = smoothstep(0.8, 1.0, abs(flow)) * 0.8;
    vec3 marketColor = vec3(1.0, 0.85, 0.3) * flowLines * 0.4; // Golden glow

    // Foliage (Spirograph Ferns)
    float totalGreen = 0.0;
    for(float i = 0.0; i < 4.0; i++) {
        // Breathing motion
        float breath = 0.5 + 0.5 * sin(t * 3.14159 * 2.0 + i);
        float scale = 3.0 * breath;

        // Center of each quadrant
        vec2 center = vec2(0.0, 0.0);
        if(i < 1.0) center = vec2(-0.8, -0.8);
        else if(i < 2.0) center = vec2(0.8, -0.8);
        else if(i < 3.0) center = vec2(-0.8, 0.8);
        else center = vec2(0.8, 0.8);

        vec2 q = p - center;

        // Spirograph logic for fern-like shapes
        float angle = atan(q.y, q.x);
        float dist = length(q);

        // Create leaf veins/spirals
        float spiral = sin(angle * 5.0 + dist * 10.0 - t * 2.0);
        float leafShape = exp(-dist * 2.0) * (0.5 + 0.5 * sin(spiral * 3.0 + dist * 5.0));

        // Add variation
        leafShape *= 1.0 + sin(t * 5.0 + dist * 20.0) * 0.1;

        totalGreen += leafShape;
    }

    // Color grading for foliage
    vec3 foliageColor = vec3(0.05, 0.45, 0.15); // Deep Evergreen
    foliageColor += vec3(0.1, 0.3, 0.05) * totalGreen * 0.5; // Lighter highlights
    foliageColor *= vec3(0.8, 0.9, 0.6); // Green tint overlay

    // Combine layers
    vec3 finalColor = bg + marketColor + foliageColor * 0.4;

    // Add subtle ink splatter/noise for field guide feel
    float ink = sin(p.x * 200.0 + t * 10.0) * sin(p.y * 200.0 - t * 8.0);
    finalColor += vec3(ink * 0.02 * (1.0 - border));

    // Vignette
    float vignette = 1.0 - length(p);
    finalColor *= vignette;

    fragColor = vec4(finalColor, 1.0);
}

float noise(vec3 x) {
    vec3 p = floor(x);
    vec3 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    vec3 u = p + vec3(0.0, 0.0, 1.0);
    vec3 v = p + vec3(0.0, 1.0, 0.0);
    vec3 w = p + vec3(1.0, 0.0, 0.0);
    // Pseudo-random hash
    vec3 a = p + vec3(0.0); 
    a = fract(a * 0.1031); 
    a += dot(a, vec3(12.9898, 4.1417, 7.464));
    a = fract(a * a);

    // Simple gradient mix for speed
    return mix(mix(mix(dot(u, a), dot(v, a), f.y), mix(dot(w, a), dot(p + vec3(1.0, 1.0, 0.0) + a, a), f.y), f.x),
               mix(mix(dot(u + vec3(0.0, 0.0, 1.0), a), dot(v + vec3(0.0, 0.0, 1.0), a), f.y), mix(dot(w + vec3(0.0, 0.0, 1.0), a), dot(p + vec3(1.0, 1.0, 1.0) + a, a), f.y), f.x), f.z);
}

// Fractal Brownian Motion
float fbm(vec3 p) {
    float f = 0.0;
    float w = 0.5;
    for(int i = 0; i < 5; i++) {
        f += w * noise(p);
        p *= 2.0;
        w *= 0.5;
    }
    return f;
}

// Distortion field for the "Fight or Flight" jitter
vec2 distortion(vec2 uv, float time) {
    float t = time * 4.0; // Speed up time for the 2s loop
    // Create a "panic" wave that expands and contracts violently
    float panic = sin(t + 0.5) * 0.5 + 0.5; // 0 to 1 panic level

    vec2 d = vec2(0.0);
    // Layer 1: Global tremor (high freq)
    d += vec2(noise(vec3(uv * 20.0, t + 1.0)), noise(vec3(uv * 20.0, t + 2.0))) * 0.02 * panic;
    // Layer 2: Structural cracks (mid freq)
    float crackNoise = fbm(vec3(uv * 3.0, t * 0.5));
    d += vec2(crackNoise, crackNoise) * 0.1 * panic;

    // Layer 3: Caustic refraction (low freq)
    float caustic = sin(dot(uv, vec2(2.0, -1.0)) * 10.0 + t) * 0.05;
    d += vec2(caustic, caustic) * (1.0 - panic) + vec2(0.1, 0.1) * panic; // Shifts based on panic

    return uv + d;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Time loop: 2.0 seconds
    float time = fract(iTime * 0.5); // 0.0 to 1.0 over 2 seconds

    // Apply the biological distortion
    vec2 distortedUV = distortion(uv, time);

    // Base color: Deep, murky biological green
    vec3 base = vec3(0.02, 0.15, 0.05);

    // Glass layer calculation
    float glassDepth = fbm(vec3(distortedUV * 4.0, time));

    // Simulate internal scattering (subsurface)
    float scatter = smoothstep(0.3, 0.9, glassDepth);
    vec3 scatterColor = vec3(0.0, 0.8, 0.3); // Bright green light inside

    // Add "cracks" based on the panic level
    float panic = sin(time * 6.28) * 0.5 + 0.5;
    float cracks = step(0.95, fract(glassDepth * 10.0 + time * 3.0));

    // Combine: Dark base + Light scattering + Sharp cracks
    vec3 col = base + scatterColor * scatter * 0.6;

    // Fracture edges: bright white/blue highlights on "cracks"
    if(cracks > 0.5) {
        col += vec3(1.0, 0.9, 0.8) * 0.4; // White spark
    }

    // Add a "heartbeat" vignette that pulses with the panic
    float dist = length(distortedUV);
    float vignette = 1.0 - smoothstep(0.0, 1.5, dist);
    col *= vignette;

    // Intensify the panic spike (middle of the loop)
    float spike = sin(time * 3.14); // 0->1->0
    col += vec3(0.1, 0.4, 0.1) * spike * 1.5;

    // Final glass glint
    col += vec3(0.2, 0.3, 0.5) * smoothstep(0.8, 0.95, glassDepth) * panic;

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    // Center and aspect correct
    vec2 p = (uv - 0.5) * vec2(iResolution.x / iResolution.y, 1.0);

    float t = iTime * 3.14159; // Slow motion
    float loop = sin(iTime * 3.14159); // 0 to 1 to 0 over 2 seconds

    // Base spirograph logic
    float angle = length(p) * 15.0 + t * loop;
    vec2 q = p * 4.0;

    // Weaving/Textile simulation using noise-like trig functions
    float w = sin(q.x * 2.0) * cos(q.y * 2.0) + 0.5;
    float weave = abs(sin(p.x * 30.0 + w * 10.0) + sin(p.y * 30.0 + w * 10.0));

    // Spirograph distortion
    float spiro = sin(angle) * cos(angle * 0.5);
    float distortion = (spiro + 0.5) * 2.0;

    // Fuzzy texture generation
    float noise = fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
    float fuzz = smoothstep(0.3, 0.8, noise + distortion * 0.2);

    // Color mixing: Sulfur green to Void
    vec3 sulfur = vec3(0.3, 0.7, 0.2); // Acid green
    vec3 deep = vec3(0.05, 0.1, 0.05); // Dark green/black
    vec3 highlight = vec3(0.6, 1.0, 0.8); // Pale lime

    vec3 col = mix(deep, sulfur, weave * fuzz);

    // Add spirograph glow
    float glow = smoothstep(0.8, 1.0, distortion);
    col += highlight * glow * 0.5;

    // Subtle breathing animation on saturation
    float breath = 0.5 + 0.5 * sin(iTime * 3.14159 * 2.0 + p.x * 5.0);
    col *= vec3(breath, breath * 0.8, breath * 1.2);

    // Final vignette for "microscope" look
    float vignette = 1.0 - smoothstep(0.0, 1.2, length(p));
    col *= vignette;

    fragColor = vec4(col, 1.0);
}

float rand(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float a = rand(i);
    float b = rand(i + vec2(1.0, 0.0));
    float c = rand(i + vec2(0.0, 1.0));
    float d = rand(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 4; i++) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

float spiro(vec2 uv, float t) {
    float r = length(uv);
    float a = atan(uv.y, uv.x);
    float s = sin(a * 5.0 + r * 2.0 + t);
    float s2 = sin(a * -7.0 - r * 1.5 + t * 1.5);
    return r * 0.1 + s * 0.2 + s2 * 0.1;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    uv.x *= iResolution.x / iResolution.y;

    vec2 p = uv;
    float t = iTime;
    float loop = mod(t, 2.0);

    float timeAnim = sin(loop * 3.14159);

    float sp = spiro(p, loop * 2.0);
    float dist = abs(sp - 0.4);

    float n = fbm(p * 5.0 + vec2(loop));
    float detail = noise(p * 12.0) * 0.1;

    vec3 col = vec3(0.1, 0.15, 0.1); // Paper background

    // Ink texture overlay
    col += (fbm(p * 2.0) - 0.5) * 0.02;
    col += vec3(0.02, 0.04, 0.01) * step(0.8, rand(p));

    // The Amber Resin (Green)
    float resin = smoothstep(0.05, 0.0, dist) * 0.8;
    resin *= (1.0 - smoothstep(0.0, 0.5, n));

    vec3 amber = vec3(0.05, 0.15, 0.05); // Dark green
    vec3 amberLight = vec3(0.1, 0.4, 0.1); // Light green

    col = mix(col, amber, resin);
    col += amberLight * resin * (n + 0.5) * 0.3;

    // The Liquid Gold
    float goldFlow = sin(p.x * 10.0 - loop * 4.0 + sp * 5.0);
    float goldMask = smoothstep(0.0, 0.015, dist);
    goldMask *= (0.5 + 0.5 * sin(loop * 3.0 + length(p) * 10.0));

    vec3 gold = vec3(1.0, 0.8, 0.1);
    vec3 goldDark = vec3(0.3, 0.2, 0.0);

    float goldVal = (goldFlow + 1.0) * 0.5;
    vec3 goldCol = mix(goldDark, gold, goldVal * 0.5);

    // Combine
    col = mix(col, goldCol, goldMask * resin);

    // Add highlight/glare
    float glare = smoothstep(0.95, 1.0, n);
    col += vec3(0.2, 0.3, 0.1) * glare * resin * 0.5;

    // Vignette
    float vig = 1.0 - length(uv) * 0.6;
    col *= vig;

    fragColor = vec4(col, 1.0);
}

// Kintsugi: Moss-Weave Lattice
// A procedural stained-glass moss landscape where gold fills the cracks of a spirograph grid.

vec2 hash(vec2 p) {
    return fract(sin(vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)))) * 43758.5453);
}

// 2D Noise based on spirograph-like interference
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    vec2 u = f * f * (3.0 - 2.0 * f);

    vec2 a = hash(i);
    vec2 b = hash(i + vec2(1.0, 0.0));
    vec2 c = hash(i + vec2(0.0, 1.0));
    vec2 d = hash(i + vec2(1.0, 1.0));

    return mix(mix(a.x, b.x, u.x), mix(c.x, d.x, u.x), u.y);
}

// FBM to create the "fuzzy moss" texture
float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 4; ++i) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

// The "Shard" logic: creates a grid of broken shapes using trigonometric interference
float getShardDist(vec2 uv, float t) {
    // Create a distorted grid that breathes
    float x = uv.x * 3.0;
    float y = uv.y * 3.0;

    // Spirograph-like interference term
    float spiro = sin(x + t * 2.0) * sin(y - t * 1.5) + cos(x - y + t);

    // Soften the grid lines to look like organic cracks
    float grid = sin(x) + sin(y);

    // Combine to create "crack" positions where values are low
    float crack = abs(grid * 0.5 + spiro * 0.3 + t);

    // Invert so cracks are valleys (0) and shards are peaks (1)
    return 1.0 - smoothstep(0.0, 0.4, abs(crack));
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Time looped exactly at 2.0s
    float t = iTime;
    float loopedT = mod(t, 2.0);

    // Base geometry
    float shardVal = getShardDist(uv, loopedT * 3.14);

    // Moss texture generation
    vec2 mossUV = uv * 8.0 + vec2(noise(uv * 2.0 + loopedT), noise(uv * 2.0 - loopedT));
    float mossNoise = fbm(mossUV);

    // Stained Glass Logic:
    // The "Crack" (Kintsugi) is the gold vein.
    // The "Pottery" is the mossy glass.

    // Gold Vein Color
    vec3 gold = vec3(1.0, 0.65, 0.0) * (0.8 + 0.2 * sin(loopedT * 6.28)); // Pulsing gold

    // Moss Colors (Deep greens to lime)
    vec3 mossBase = vec3(0.05, 0.25, 0.1) * (1.0 - shardVal);
    vec3 mossHighlight = vec3(0.1, 0.6, 0.2) * smoothstep(0.5, 1.0, mossNoise);
    vec3 mossDark = vec3(0.01, 0.08, 0.04) * (1.0 - smoothstep(0.2, 0.8, mossNoise));

    // Glass Stain: Add color bleeding at edges
    float glassEdge = smoothstep(0.0, 0.2, 1.0 - abs(fract(uv.x * 5.0) - 0.5));

    vec3 finalColor = vec3(0.0);

    // Mix Logic
    if (shardVal < 0.15) {
        // Crack area: Pure Gold with a slight glow
        finalColor = gold * (1.5 + 0.5 * sin(loopedT * 3.14));
    } else {
        // Shard area: Moss texture
        float mossMix = smoothstep(0.0, 0.8, mossNoise);
        vec3 shardColor = mix(mossDark, mossHighlight, mossMix);

        // Add the "Green Everywhere" tint
        finalColor = shardColor * (0.8 + 0.2 * sin(loopedT * 3.14));

        // Stained glass edge effect (darker lines between shards)
        float edgeDarkness = smoothstep(0.0, 0.1, glassEdge);
        finalColor *= (1.0 - edgeDarkness * 0.4);
    }

    // Vignette to focus center
    float vignette = 1.0 - length(uv) * 0.4;
    finalColor *= vignette;

    // Gamma correction for better visual pop
    fragColor = vec4(pow(finalColor, vec3(0.4545)), 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Normalize time to 0-1 loop over 2 seconds
    float t = fract(iTime * 0.5);

    // Base peach skin organic flow
    vec2 p = uv;
    float noise = sin(p.x * 15.0) * cos(p.y * 10.0) + 
                  sin(p.x * 32.0 - 2.0) * cos(p.y * 24.0);

    // Dot matrix grid generation
    float gridSize = 0.012;
    vec2 grid = fract(p * 40.0);
    float dotMask = smoothstep(0.4, 0.6, grid.x) * smoothstep(0.4, 0.6, grid.y);

    // Freeze wave propagation
    float freezeWave = sin(t * 6.28 + length(uv) * 10.0);
    float frostFactor = smoothstep(-1.0, 0.8, freezeWave);

    // Peach fuzz vs Ice spikes
    vec3 peachColor = vec3(1.0, 0.55, 0.3);
    vec3 iceColor = vec3(0.3, 0.8, 0.95);
    vec3 bgColor = vec3(0.05, 0.1, 0.12);

    vec3 mainColor = mix(peachColor, iceColor, frostFactor);

    // Add dot-matrix artifacting based on freeze state
    float matrixIntensity = 1.0 - (dotMask * (0.5 + 0.5 * sin(noise * 10.0)));
    matrixIntensity *= (0.8 + 0.2 * frostFactor); // Dots get clearer as it freezes

    // Final composition with organic distortion
    float intensity = noise * 0.3 + 0.7;
    intensity = pow(intensity, 2.5);

    // Jitter the grid slightly to simulate thermal printer vibration
    float jitter = sin(t * 100.0) * 0.002;

    vec3 finalColor = mix(bgColor, mainColor, intensity * matrixIntensity);

    // Vignette to focus center
    float vignette = 1.0 - length(uv) * 0.4;
    finalColor *= smoothstep(0.0, 1.0, vignette);

    fragColor = vec4(finalColor, 1.0);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 5; ++i) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Loop time 0.0 to 1.0 over 2 seconds
    float t = fract(iTime / 2.0);

    // Camera movement
    vec3 camPos = vec3(0.0, 3.0 + sin(t * 6.28) * 0.5, 4.0);

    // Ray direction setup for isometric view
    vec3 rd = normalize(vec3(uv.x, -uv.y + 1.5, -2.0));
    vec3 ro = camPos;

    vec3 col = vec3(0.05, 0.08, 0.1); // Deep void background
    float accum = 0.0;

    // Raymarching the "Forest"
    float stepSize = 0.15;

    for(int i = 0; i < 60; ++i) {
        vec3 p = ro + rd * float(i) * stepSize;

        // Forest SDF approximation using FBM
        // "Needles" are tall thin spikes
        float n = fbm(p.xz * 10.0 + vec2(iTime * 0.2, p.y * 2.0));
        float height = 1.5 + n * 0.8;

        float alpha = 0.0;
        vec3 pixelCol = vec3(0.0);

        // Cutaway logic: Focus on the slice around Y=1.5
        if (p.y > 0.5 && p.y < 2.0) {
            // Dense forest volume
            float densityMap = smoothstep(0.2, 0.5, n) * smoothstep(2.0, 1.0, p.y);
            alpha = densityMap * 0.15;

            // Haptic Ghost Effect: A wave of high saturation cyan passing through
            float wave = sin(p.x * 20.0 + p.z * 10.0 - t * 40.0);
            float ghost = smoothstep(0.5, 1.0, wave);
            vec3 ghostColor = vec3(0.0, 0.8, 0.9) * ghost;

            // Base green
            vec3 base = vec3(0.05, 0.2, 0.08);

            // Mix base and ghost
            pixelCol = mix(base, ghostColor, 0.7);

            // Isometric lighting
            vec3 light = normalize(vec3(-1.0, 1.0, -1.0));
            vec3 normal = normalize(vec3(0.0, 1.0, 0.0)); 

            float diff = max(dot(normal, light), 0.0);
            pixelCol += vec3(0.15) * diff;

            col += pixelCol * alpha;
            accum += alpha;
        } 
        else if (p.y > 2.0 && p.y < height + 0.5) {
             // Top needles
             float nTop = fbm(p.xz * 15.0);
             float alphaTop = smoothstep(0.6, 0.8, nTop);
             vec3 topCol = vec3(0.02, 0.15, 0.05);
             col += topCol * alphaTop * 0.2;
        }

        if (accum > 0.9) break;
    }

    // Apply final tone mapping and gamma
    col = col + vec3(0.02, 0.05, 0.03) * (1.0 - accum); // Background fill

    // Haptic glow bloom
    float glow = pow(accum, 2.0) * 0.5;
    col += vec3(0.0, 0.3, 0.4) * glow * 0.5;

    // Output
    fragColor = vec4(col, 1.0);
}

vec2 rot(float a, vec2 p) {
    float s = sin(a), c = cos(a);
    return vec2(p.x * c - p.y * s, p.x * s + p.y * c);
}

float noise(vec2 x) {
    vec2 p = fract(x) * 6.0;
    vec2 i = floor(x);
    p = p * p * (3.0 - 2.0 * p);
    float k = 57.0;
    float n = sin(dot(p + i, vec2(k, k+1.0)));
    return mix(n, sin(dot(p + vec2(1.0, 0.0) + i, vec2(k, k+1.0))), p.x);
}

void main() {
    // Loop time strictly between 0 and 2 seconds
    float t = mod(iTime, 2.0);
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Spiral transformation
    float s = 2.0 + t * 3.0;
    float a = atan(uv.y, uv.x);
    float r = length(uv);

    // Spirograph-like rotation based on radius and time
    float ang = a + (t * 3.0) + (0.5 / (r + 0.1));
    float rad = r * s;

    vec2 q = vec2(cos(ang) * rad, sin(ang) * rad);

    // Zoom into the texture space to create filaments
    float zoom = 15.0 + sin(t * 3.14159) * 5.0;
    vec2 p = q * zoom;

    // Add rotational motion to the pattern itself
    p = rot(t * 0.5, p);

    // Procedural "Silk" Noise
    float n = 0.0;
    float f = 1.0;
    for (int i = 0; i < 4; i++) {
        float scale = 1.2;
        p *= scale;
        n += noise(p + vec2(t, t * 1.5)) * f;
        f *= 0.5;
    }

    // False Color Ultraviolet Palette
    // Mapping noise to a high-contrast UV spectrum (Purple -> Cyan -> Lime)
    vec3 color1 = vec3(0.2, 0.0, 0.4); // Deep Violet (Silk base)
    vec3 color2 = vec3(0.0, 0.9, 0.6); // Neon Lime (Dust)
    vec3 color3 = vec3(0.8, 0.2, 1.0); // Magenta (Highlight)

    // Create a soft, glowing edge based on noise threshold
    float d = smoothstep(0.3, 0.4, n);
    float glow = 1.0 - smoothstep(-0.2, 0.2, n - 0.3);

    // Mix colors
    vec3 col = mix(color1, color2, d);
    col = mix(col, color3, d * d * 0.5);

    // Add radial gradient for "Caravan" focus
    float vignette = smoothstep(1.5, 0.0, length(uv));
    col *= vignette * 1.2;

    // Add a pulse effect
    col *= 1.0 + 0.2 * sin(t * 3.0 + length(uv) * 10.0);

    fragColor = vec4(col, 1.0);
}

// Submarine Galley Botanical Field Note
// A field-guide style illustration of a submarine sink blooming with evergreen life.

float hash(vec2 p) { return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453); }

float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

float fbm(vec2 x) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 5; i++) {
        v += a * noise(x);
        x *= 2.05; // Slight stretch for organic feel
        a *= 0.5;
    }
    return v;
}

// "Hand-drawn" line variation
float penTip(vec2 p, float thickness) {
    float n = noise(p * 10.0);
    return smoothstep(0.0, thickness, abs(p.x - n * 0.2));
}

float sinkBasin(vec2 uv, float time) {
    // Distorted grid representing the chrome basin
    uv -= 0.5;
    float dist = length(uv) - 0.45;
    float curve = dist - length(uv) * 0.2; 
    return smoothstep(0.01, 0.05, abs(curve)) + smoothstep(-0.1, 0.0, -dist);
}

float evergreenFuzz(vec2 uv, float time) {
    vec2 q = uv * 8.0;
    float n = noise(q);
    float f = fbm(q);

    // Create needle-like structures
    float needles = 0.0;
    for (int i = 0; i < 4; i++) {
        float angle = float(i) * 0.5 + time * 0.5;
        vec2 rot = mat2(cos(angle), -sin(angle), sin(angle), cos(angle)) * (uv - 0.5);
        float d = abs(rot.x) + length(rot);
        needles += smoothstep(0.1, 0.05, d) * n;
    }
    return f * needles * 2.0;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 p = uv - 0.5;

    // Base Paper Color
    vec3 color = vec3(0.95, 0.94, 0.90);

    // Time loop: 2.0 seconds
    float t = iTime * 1.57; 

    // Ink Color (Deep Teal/Black)
    vec3 ink = vec3(0.1, 0.2, 0.25);

    // 1. Draw the Sink Basin (Geometric foundation)
    float basin = sinkBasin(p, t);
    float basinEdge = smoothstep(0.0, 1.0, basin);

    // Add "Field Note" cross-hatching to the basin
    float hatch = 0.0;
    if (basinEdge > 0.5) {
        float h = sin(p.y * 80.0 - t) + sin(p.x * 80.0 + t);
        if (h > 1.5) hatch = 0.8;
    }

    // 2. The "Flora" (Evergreen fuzz erupting from center)
    // Mask flora to the center of the sink
    vec2 local = p * 2.0;
    float bloomMask = smoothstep(0.5, 0.4, length(local));

    float fuzz = evergreenFuzz(p, t);

    // Green Color Palette
    vec3 deepGreen = vec3(0.05, 0.3, 0.2);
    vec3 lightGreen = vec3(0.2, 0.7, 0.4);

    // 3. Combine
    // Mix Ink for basin lines
    color = mix(color, ink, basinEdge * 0.3);

    // Mix Hatching
    color = mix(color, ink, hatch * 0.4);

    // Mix Evergreen
    float vegetationDensity = smoothstep(0.0, 0.5, fuzz) * bloomMask;
    vec3 vegColor = mix(deepGreen, lightGreen, smoothstep(0.2, 0.8, fuzz));
    color = mix(color, vegColor, vegetationDensity * 0.8);

    // Add a subtle "damp" vignette
    float vig = smoothstep(1.2, 0.0, length(p));
    color *= 1.0 - vig * 0.1;

    fragColor = vec4(color, 1.0);
}

float mod2pi(float t) { return t - 6.2831853 * floor(t / 6.2831853); }

vec2 rotate(vec2 p, float a) {
    float s = sin(a), c = cos(a);
    return vec2(p.x * c - p.y * s, p.x * s + p.y * c);
}

float distSphere(vec2 uv, vec2 c, float r) {
    return length(uv - c) - r;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    uv = (uv - 0.5) * 2.0;
    float ar = iResolution.x / iResolution.y;
    uv.x *= ar;

    float t = iTime;
    float loopT = mod(t, 2.0);
    float normT = loopT * 0.5; // 0 to 1 over 2s

    // Camera/Scene rotation
    uv = rotate(uv, sin(loopT * 3.1415) * 0.2 + 0.5);

    // Wet Asphalt Base
    vec3 col = vec3(0.05, 0.05, 0.08);
    float noise = fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453);
    col += vec3(0.0, 0.02, 0.05) * noise * 0.5; // slight green tint to asphalt

    // Spacing and count for the "doughnut" field
    vec2 grid = vec2(0.6, 0.6) + vec2(0.0, 0.2);
    vec2 p = mod(uv + 0.5, grid) - 0.5 * grid;
    vec2 p0 = floor((uv + 0.5) / grid);
    vec2 p1 = p0 * grid;

    float dist = 1.0;
    float accum = 0.0;

    // Iterate neighbors for field effect
    for(float y = -1.0; y <= 1.0; y+=1.0) {
        for(float x = -1.0; x <= 1.0; x+=1.0) {
            vec2 offset = vec2(x, y) * grid;
            vec2 pp = p + offset;

            // Zero-G drift for each sphere
            float driftX = sin(p0.x * 3.14 + loopT * 2.0) * 0.1;
            float driftY = cos(p0.y * 3.14 - loopT * 2.0) * 0.1;
            vec2 pos = p1 + offset + vec2(driftX, driftY);

            float d = length(uv - pos);

            // Procedural "Fuzzy Evergreen" Doughnut
            // Inner hole expands and contracts
            float hole = 0.15 + sin(loopT * 4.0 + p0.x) * 0.05;
            float shell = 0.25 + cos(loopT * 3.0 + p0.y) * 0.05;

            if (d < shell + 0.2) {
                // Spirograph texture inside the shell
                float angle = atan(pp.y, pp.x) + loopT;
                float r = d;
                float spiro = sin(r * 12.0 + angle * 5.0 + loopT * 4.0);
                spiro = (spiro + 1.0) * 0.5;

                // Shape: Doughnut ring with fuzzy edges
                float ring = smoothstep(shell, shell - 0.15, d) - smoothstep(hole, hole - 0.15, d);
                float fuzzy = smoothstep(0.0, 0.05, d - hole); // inner fuzz
                float outerFuzz = smoothstep(shell, shell + 0.1, d); // outer glow

                float intensity = ring * (1.0 + spiro * 0.5);
                intensity += outerFuzz * 0.4; // glow bleed

                // Color: Neon Green/Cyan core to Magenta edge (Wet Asphalt reflection)
                vec3 sphereCol = mix(vec3(0.0, 1.2, 0.8), vec3(1.0, 0.2, 0.8), spiro);

                // Additive blending for neon effect
                vec3 contrib = sphereCol * intensity * 2.5;

                // "Wet" reflection falloff towards bottom of sphere
                float wetMask = smoothstep(-0.2, 0.2, uv.y - (pos.y * ar));
                contrib += vec3(0.8, 0.1, 0.9) * 0.3 * smoothstep(0.0, 0.1, wetMask);

                col += contrib;
            }
        }
    }

    // Global Bloom / Wet Street Glow
    col = mix(col, vec3(0.0, 0.5, 0.4), smoothstep(2.0, 0.0, length(uv)) * 0.3);

    // Vignette for focus
    float vig = 1.0 - smoothstep(0.5, 1.2, length(uv));
    col *= vig;

    fragColor = vec4(col, 1.0);
}

// Creative Director Assignment: Liquid Mercury Thermal Expansion Anomaly
// Interpretation: Snoop's Mercury Silhouette Bloom

float hash(float n) {
    return fract(sin(n) * 43758.5453123);
}

float noise(vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n = p.x + p.y * 57.0;
    return mix(mix(hash(n + 0.0), hash(n + 1.0), f.x),
               mix(hash(n + 57.0), hash(n + 58.0), f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 5; i++) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

vec2 snoopProfile(vec2 p) {
    // Abstract fractal silhouette of a profile/head
    float d1 = length(p - vec2(0.5, 0.2));
    float d2 = length(p - vec2(0.7, 0.6));
    float d3 = length(p - vec2(0.4, 0.5));

    // Combine to form a rough head shape
    float profile = smoothstep(0.15, 0.14, d1 + d2 * 0.5 + d3 * 0.2);

    // Add fractal detail to the edge
    float detail = fbm(p * 5.0 + vec2(iTime, 0.0));
    return vec2(profile, detail);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 q = vec2(
        dot(uv, vec2(1.0, 1.0)),
        dot(uv, vec2(-1.0, 1.0))
    );

    float t = iTime * 1.0; // 2.0 second loop logic inside functions
    float period = 2.0;
    float loopT = fract(t / period);

    // Thermal expansion anomaly: breathing scale
    float expansion = 1.0 + 0.15 * sin(loopT * 6.2831);

    vec2 p = q * expansion;

    // Mercury fluid simulation via FBM
    float fluid = fbm(p * 4.0 + vec2(t * 0.5, 0.0));

    // Snoop Fractal Silhouette
    vec2 prof = snoopProfile(uv * expansion);

    // Negative Space Logic:
    // Background is the "Liquid" (dark)
    // Subject is the "Void" (light) carved out by the silhouette

    float distField = length(uv) * expansion;
    float silhouette = smoothstep(0.05, 0.0, distField - prof.y * 0.05);

    // Combine mercury flow with silhouette
    float mercury = smoothstep(-0.2, 0.2, fluid);

    // Anomaly: Thermal glow at the expansion peaks
    float heat = pow(smoothstep(0.8, 1.0, loopT), 3.0);

    // Color Palette: Deep Indigo to Electric Teal to White
    vec3 cDark = vec3(0.02, 0.02, 0.05); // Deep Void
    vec3 cMercury = vec3(0.1, 0.15, 0.25); // Cool Silver/Indigo
    vec3 cGlow = vec3(0.0, 1.0, 1.0); // Electric Teal

    vec3 col = mix(cDark, cMercury, mercury);

    // Cut out the silhouette in negative space
    // If inside silhouette, make it very dark (void) or very bright (glow)
    // We choose "Void" for the silhouette itself to contrast the mercury
    if (silhouette > 0.9) {
        col = vec3(0.0); 
    } else {
        // Add thermal glow to the mercury surface
        col = mix(col, cGlow, heat * mercury * 0.5);
        // Add highlights
        col += vec3(0.1, 0.2, 0.3) * smoothstep(0.5, 0.9, fluid);
    }

    // Final contrast boost for the "Silhouette" aesthetic
    col = smoothstep(0.4, 0.6, col) * col * 1.5;

    fragColor = vec4(col, 1.0);
}

float random2d(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    return mix(mix(random2d(i), random2d(i + vec2(1, 0)), f.x),
               mix(random2d(i + vec2(0, 1)), random2d(i + vec2(1, 1)), f.x), f.y);
}
void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // 2-second loop logic
    float t = mod(iTime, 2.0);
    float pulse = sin(t * 3.14159);

    // Fractal coordinates
    vec2 p = uv;
    float dist = 0.0;
    float fold = 0.0;
    float iterations = 8.0;
    float scale = 1.5 + pulse * 0.5;

    for(float i = 0.0; i < iterations; i++) {
        p = fract(p * 1.5 + 0.2) - 0.5;
        p *= scale;
        p = abs(p);

        // Snoop-inspired swirl distortion
        float angle = atan(p.y, p.x);
        float r = length(p);
        float swirl = sin(angle * 3.0 + t * 4.0 + i * 0.5);

        p.x += swirl * r * 0.1;
        p.y += cos(angle * 3.0 + t * 4.0 + i * 0.5) * r * 0.1;

        dist = min(dist, length(p));
        fold += 0.1 / length(p + 0.01);
    }

    // Base chalkboard noise
    float board = 0.05 + noise(uv * 5.0) * 0.02 + noise(uv * 25.0) * 0.01;

    // Fermented fish sauce colors (Brine Green, Slime, Chalk White)
    vec3 brine = vec3(0.1, 0.3, 0.25); 
    vec3 foam = vec3(0.8, 0.9, 0.85);
    vec3 deep = vec3(0.02, 0.02, 0.03);

    // Fractal glow
    float glow = 1.0 / (dist * 10.0 + 0.1);
    glow = pow(glow, 2.5);

    // Smudge effect for chalk texture
    float smudge = noise(p * 20.0 + t) * 0.2;
    glow *= (1.0 - smudge * 0.3);

    // Color mixing
