float mandala(vec2 uv, float t) {
    float angle = atan(uv.y, uv.x);
    float r = length(uv);
    // Leaf-like symmetry (5-fold)
    float sect = mod(angle, 2.0 * 3.14159 / 5.0) - 1.57;
    vec2 p = uv / length(uv) * length(uv);
    p.x *= cos(sect) - 0.3 * sin(sect);
    p.y *= cos(sect) - 0.3 * sin(sect);

    float d = length(p);
    // Fractal branching
    float branch = fbm(p * 2.0 - vec2(d, t));
    float vein = sin(d * 10.0 - t * 5.0) * 0.5 + 0.5;

    // Amalgamation fluid dynamics
    float flow = sin(t * 3.14159) * 0.5 + 0.5;
    float temp = smoothstep(0.4, 0.0, branch) * vein;

    return temp * flow;
}

