void main() {
    float t = iTime;
    float loopT = sin(t * PI); 
    float timeSq = (sin(t * PI) + 1.0) * 0.5;

    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    float angle = loopT * 0.6;
    float s = cos(angle);
    float cVal = sin(angle);
    uv.x *= s; 
    vec2 uvRot = vec2(uv.x - uv.y * cVal, uv.y * s + uv.x * cVal);

    vec3 ro = vec3(0.0, 1.5, -8.0);
    vec3 rd = normalize(vec3(uvRot, 1.0));

    float d = 8.0;
    vec3 col = vec3(0.1, 0.05, 0.0); 

    for(float i = 0.0; i < 8.0; i++) {
        float offset = i * 1.5 + timeSq * 0.5;
        vec3 p = ro + rd * offset;

        float n = noise(p.xy * 0.5 + vec2(2.0, 1.5) * timeSq);
        float n2 = noise(p.xz * 0.4);

        // Define layer type: even = books (planes), odd = pipes (cylinders)
        bool isBook = (i < 3.0) || (i > 5.0);

        float planeDist = abs(p.y - (sin(i + timeSq) * 0.8));
        float tubeDist = length(p.xz) - 0.15;

        float finalDist = isBook ? planeDist : tubeDist;

        if(finalDist < 0.05) {
            d = min(d, finalDist * 0.01); 

            vec3 light = normalize(vec3(1.0, 1.0, 1.0));

            // Fix: Ensure normal is always vec3
            vec3 normalY = vec3(0.0, sign(p.y - (sin(i + timeSq) * 0.8)), 0.0);
            vec3 normalXZ = normalize(vec3(p.x, 0.0, p.z)); // Fixed: was p.xz which is vec2

            vec3 normal = isBook ? normalY : normalXZ;

            float diff = max(dot(normal, light), 0.0) * 0.6;
            float spec = pow(max(dot(reflect(-light, normal), -rd), 0.0), 32.0) * 0.8;

            vec3 base = vec3(0.2, 0.1, 0.05);
            vec3 specColor = vec3(0.8, 0.7, 0.5);

            vec3 layerCol = base + diff * vec3(0.4) + spec * specColor;
            col = mix(col, layerCol, smoothstep(0.02, 0.0, finalDist));
        }
    }

    col = col * (1.0 - exp(-0.1 * d));

    float grain = hash(uv * 1000.0 + timeSq * 500.0);
    float vignette = 1.0 - dot(uv, uv) * 0.8;

    col = mix(col, vec3(0.8, 0.8, 0.8), grain * 0.03); 
    col *= vignette;

    fragColor = vec4(col, 1.0);
}

vec2 rot(vec2 p, float a) {
    float s = sin(a), c = cos(a);
    return vec2(p.x * c - p.y * s, p.x * s + p.y * c);
