    float tMod = sin(t * 3.14159); // 2s loop modulation

    // Animate camera/scene
    p.z -= sin(t * 1.57) * 4.0;
    p.xy = rot(p.xy, t * 0.2 + tMod * 0.1);

    float d = 100.0; // Distance accumulator
    vec3 col = bg;

    // Construct the "Gated Club" Grid of Pipes
    // We iterate a 3D grid of cylinders
    float steps = 15.0;
    float range = 8.0;

    for(float z = -range; z < range; z += range/steps) {
        vec3 pos = vec3(0.0, 0.0, z);
        float distZ = abs(p.z - z);

        if(distZ < 0.3) {
            // Map to XY grid
            vec2 grid = p.xy / 0.8;
            vec2 iGrid = round(grid);
            vec2 u = fract(grid) - 0.5;

            // The "Velvet Rope" Paradox:
            // A wave function that creates a "gate" or "rope" moving through the grid
            float rope = sin(u.x * 6.0 + u.y * 3.0 + t * 4.0);
            float gate = smoothstep(0.0, 0.2, abs(rope - 0.5)); // High gate = blocked

            // Pipe Geometry (Cylinder radius)
