            // Intersection
            float pipe = r - rad;

            // Logic: If we are inside the pipe (gated), it's dark/void.
            // If we are outside but close, we see the "Velvet" texture or glowing data.
            if(pipe < 0.05) {
                // Pipe surface
                // The "Data Artist" aspect: The pipe isn't just metal, it's a data stream
                float stream = sin(u.y * 20.0 + t * 10.0 - u.x * 20.0);
                float flow = smoothstep(-0.5, 0.5, stream);

                // Cyanotype Inversion: Bright where data is dense
                vec3 pipeCol = vec3(0.8, 1.0, 1.2) * flow * (1.0 - gate); 

                // Add "Velvet Rope" occlusion
                pipeCol *= (1.0 - smoothstep(-0.2, 0.0, rope));

                col = max(col, pipeCol * 0.5 + pipeCol * pipeCol * 0.8);
            }
        }
    }

    // Atmospheric depth / Bloom
    float depth = 1.0 / (1.0 + abs(p.z) * 0.1);
    col *= depth;

    // Final Cyanotype Tone Mapping
