    float exposure = 1.2;
    col = pow(col, vec3(exposure));

    // Add a vignette for the "Camera" feel
    float vig = 1.0 - length(uv) * 0.5;
    col *= clamp(vig, 0.0, 1.0);

    fragColor = vec4(col, 1.0);
