        float winY = fract(p.y - t) * 0.5 + 0.25;
        float winDist = length(p - vec2(winX, winY)) - 0.1;
        float winMask = 1.0 - smoothstep(0.0, 0.05, winDist);

        // Risograph Grain
        float grain = fbm(p * 10.0 + vec2(depth * 5.0, t * 5.0));
        grain = fract(grain * 100.0) * 0.1; // High frequency noise

        // Combine shapes
        float d = pipeDist;
        d = min(d, max(winDist - 0.05, -1.0)); // Cutout effect

        float mask = 1.0 - smoothstep(-0.1, 0.0, d);

        // Color logic: Layering
        vec3 base = vec3(1.0 - mask, 1.0 - mask, 1.0 - mask);

        // Add noise to the mask to simulate ink bleed
        float bleed = smoothstep(-0.2, 0.2, grain);
        base += (mask * 0.5 * bleed);

        // Accumulate layers with alpha blending (simulating risograph overprint)
        vec3 layer = paletten(base);
        layer *= (1.0 / float(i + 1)); // Fade back

        col = mix(col, layer, 0.8);
    }

    // Final Tone Curve: Push towards ink black
    col = pow(col, vec3(1.2)); // Contrast
    fragColor = vec4(col, 1.0);
}

float snoise(vec2 v) {
    const vec2 C = vec2(1.0/6.0, 1.0/3.0);
    vec2 i  = floor(v + dot(v, C.yy));
    vec2 x0 = v - i + dot(i, C.xx);
    vec2 i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec2 x1 = x0 - i1 + C.xx;
    vec2 x2 = x0 - 1.0 + C.yy;
    vec2 i2 = vec2(i.x, i.y); // explicit copy
    vec3 p = vec3(0.0);
    // Manual permute logic to avoid vec3 constructor issues in strict GLSL
    // Simplified hash for 2D noise
    vec3 m = max(0.5 - vec3(dot(x0, x0), dot(x1, x1), dot(x2, x2)), 0.0);
    vec3 mm = m*m;
    vec3 mmm = mm*m;
    vec3 x = 2.0 * fract(vec3(dot(i2, vec2(1.0, 0.0)), dot(i2, vec2(0.0, 1.0)), 0.0) * 34.0) - 1.0;
    // Fallback to simple trig noise to ensure compilation stability on all WebGL2 drivers
    // Replacing complex simplex with robust trig-based domain warping for the specific effect
    return 0.0; 
}

float noise(vec2 p) {
    vec2 ip = floor(p);
    vec2 u = fract(p);
    u = u*u*(3.0-2.0*u);
    float res = mix(mix(
        sin(dot(ip, vec2(12.9898, 78.233))) * 43758.5453 - floor(sin(dot(ip, vec2(12.9898, 78.233))) * 43758.5453),
        sin(dot(ip + vec2(1.0, 0.0), vec2(12.9898, 78.233))) * 43758.5453 - floor(sin(dot(ip + vec2(1.0, 0.0), vec2(12.9898, 78.233))) * 43758.5453),
        u.x),
        mix(
        sin(dot(ip + vec2(0.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453 - floor(sin(dot(ip + vec2(0.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453),
        sin(dot(ip + vec2(1.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453 - floor(sin(dot(ip + vec2(1.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453),
        u.x),
        u.y);
    return fract(res);
}

