}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 5; i++) {
        v += a * noise(p);
        p *= 2.0;
        a *= 0.5;
    }
    return v;
}

// Mandelbrot-style fern iteration
vec2 fern(vec2 p, int iter) {
    vec2 z = p;
    for (int i = 0; i < iter; i++) {
        vec2 w = vec2(-0.5 * z.y, -0.5 * z.x);
        z = vec2(z.x * z.x - z.y * z.y + w.x, 2.0 * z.x * z.y + w.y);
        if (dot(z, z) > 4.0) break;
    }
    return z;
}

void main() {
