        float m = dot(z, z);
        if (m > 4.0) {
            // Escape time coloring
            float iter = float(i) + (1.0 - log2(m) / log2(2.0)); 
            val = iter / 20.0;
            break;
        }
        if (i == 19) val = 1.0;
    }

    // Combine fractal structure with the "heat" gradient
    // If val is low (background), color is dark/raw
    // If val is high (fractal arms), color changes based on heat

    vec3 c;

    // Raw state (Green)
    vec3 raw = vec3(0.1, 0.6, 0.3); 

    // Maillard Transition (Yellow -> Orange -> Brown -> Black)
    // Using a polynomial to simulate the chemical change
    float gold = 0.45 + 0.55 * heat;
    vec3 cooked = vec3(
        mix(0.8, 0.2, heat), // R: Light to Dark
        mix(0.8, 0.1, heat), // G: Light to Dark
        mix(0.4, 0.05, heat) // B: Blue tint to Black
    );

    // Interpolate based on fractal density
    // High density (val ~ 1) gets the color, low density gets dark background
    float alpha = smoothstep(0.0, 1.0, val * 1.5);

    // Mix raw vs cooked based on time, but modulate by the fractal shape
    // This makes the fern "cook" over time
    vec3 finalColor = mix(raw, cooked, alpha * heat);

    // Add a "char" effect if heat is maxed
    if (heat > 0.9 && alpha > 0.8) {
        finalColor = mix(finalColor, vec3(0.0), (heat - 0.9) * 2.0);
    }

    // Soft vignette
    float vign = 1.0 - 0.5 * length(uv);
    fragColor = vec4(finalColor * vign, 1.0);
}

float hash(vec2 p) { return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453); }
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float n = i.x + i.y * 57.0;
    float a = hash(i + vec2(0,0));
    float b = hash(i + vec2(1,0));
    float c = hash(i + vec2(0,1));
    float d = hash(i + vec2(1,1));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

vec3 stainedGlass(float d) {
    // Palette: Deep Purple -> Sulfur Yellow -> Fiery Orange -> Red
    vec3 c1 = vec3(0.2, 0.05, 0.2); // Purple
    vec3 c2 = vec3(0.4, 0.8, 0.0); // Sulfur
    vec3 c3 = vec3(1.0, 0.5, 0.1); // Orange
    vec3 c4 = vec3(0.8, 0.1, 0.0); // Red
    vec3 c = c1 + (c2 - c1) * smoothstep(0.2, 0.4, d) 
           + (c3 - c2) * smoothstep(0.5, 0.7, d)
           + (c4 - c3) * smoothstep(0.8, 1.0, d);
    return c * (1.0 + 0.3 * sin(d * 10.0)); // Glint
}

