// Iterative fractal fern/branch structure with ink diffusion
float drawInkBranch(vec2 uv, float depth) {
    float totalInk = 0.0;
    float baseScale = 1.0;

    // Iterate up to max depth (simulating recursion)
    float maxDepth = 4.0;
    float currentDepth = 0.0;

    // We accumulate ink by transforming the coordinate space iteratively
    // This is a simplified "marching" approach to avoid actual recursion

    // Instead of true recursion, we use a loop to draw branches at different scales
    // by transforming the UV space relative to a "root"

    vec2 p = uv;
    float w = 0.15;
    float h = 1.0;

    // Main trunk
    float dist = abs(p.x) * (1.0 / w) - h * 2.0;
    float branch = 1.0 - smoothstep(0.0, 1.5, dist);
    totalInk += branch;

    // Iterative sub-branches
    for(float i = 1.0; i <= maxDepth; i++) {
        float scale = 0.65;
        float angle = 0.4 * i;
        float intensity = 0.7 * (1.0 - i / maxDepth);

        // Simulate branching logic by checking multiple "virtual" branches
        // We transform the point into the local space of a potential branch
        vec2 localP = rotate(p, angle) * vec2(scale, scale) + vec2(0.3, -0.2);
        float dL = abs(localP.x) * (1.0 / (w * scale)) - (h * scale) * 2.0;
        float bL = 1.0 - smoothstep(0.0, 1.5, dL);

        localP = rotate(p, -angle) * vec2(scale, scale) - vec2(0.3, -0.2);
        float dR = abs(localP.x) * (1.0 / (w * scale)) - (h * scale) * 2.0;
        float bR = 1.0 - smoothstep(0.0, 1.5, dR);

        totalInk += (bL + bR) * intensity;

        // Update p for next iteration (simplified)
        p = rotate(p, angle * 0.5) * vec2(scale, scale);
    }

    // Ink wash diffusion effect
    float diffusion = smoothstep(0.0, 0.2, totalInk) * (1.0 - smoothstep(0.0, 0.5, totalInk));

    return clamp(totalInk + diffusion * 0.3, 0.0, 1.0);
}

float getSwarm(vec2 uv) {
    float total = 0.0;
    float t = iTime;
    float loopT = fract(t / 2.0);

    // Create a "phalanx" of emus/ferns
    for(int i = 0; i < 12; i++) {
        float phase = float(i) * 0.3;
        vec2 offset = vec2(float(i) * 0.4, sin(t * 4.0 + phase) * 0.3);

        // Loop the motion every 2 seconds
        offset.y *= sin(loopT * 3.14159); // Rise and fall

        vec2 localUV = uv + offset;
        // Time-based warping for the "charge" effect
        localUV.y -= sin(t + localUV.x * 2.0) * 0.1;
        localUV.x += cos(t + localUV.y * 2.0) * 0.05;

        float ink = drawInkBranch(localUV, 4.0);
        total += ink * (1.0 - float(i) * 0.05); // Fade back
    }

    // Add background "mist" from the battle
    float mist = 0.05 + 0.1 * sin(uv.y * 5.0 + iTime) * sin(uv.x * 3.0 - iTime);

    return clamp(total + mist, 0.0, 1.0);
}

