float map(vec2 p) {
    // Iterative fern mapping (Barnsley-like but simplified for weave)
    float s = 0.0;
    float scale = 0.98;
    vec2 q = p;

    // Create the fractal structure
    for(float i = 0.0; i < 5.0; i++) {
        // Fern-like branching logic
        float a = (q.y - 3.0);
        if (a < 0.1) {
            q = vec2(0.1 * q.x - 0.3 * q.y + 0.0, 0.3 * q.x + 0.05 * q.y + 1.6);
        } else {
            q = vec2(0.85 * q.x + 0.04 * q.y, -0.04 * q.x + 0.85 * q.y + 1.6);
        }

        // Map distance to "thread" thickness
        float d = length(q - p);
        // Soften the edges for a glowing thread look
        s = max(s, exp(-8.0 * d));
        p = q * 0.5; // Zoom out for next iteration
    }
