        float d = length(p) * 0.9;
        d = abs(d - 0.1);

        // Fern-like distortion
        float distortion = sin(p.x * 50.0 + p.y * 30.0 + t * 20.0 + float(i));
        p.x += distortion * 0.05;

        // Pulse and Trauma spike
        d -= breathe * 0.05 * (1.0 + float(i) * 0.2) - trauma;
        d = abs(d) * (1.0 + length(uv) * 0.5);

        // Color blending based on depth
        vec3 c1 = vec3(0.1, 0.1, 0.4); // Cold present
        vec3 c2 = vec3(1.2, 0.6, 0.1); // Hot memory

        float mixVal = smoothstep(0.0, 1.0, (1.0 - d) * 2.0);
        vec3 lum = mix(c1, c2, sin(t * 3.14 + mixVal) * 0.5 + 0.5);

        d = pow(0.01 / d, 1.2);
        col += lum * d * 0.3;
        p = rotate(p, 0.3);
    }

    // Vignette and noise overlay
    float vig = 1.0 - length(uv) * 0.6;
    vig = pow(vig, 3.0);
    col *= vig;

    // Add grain to simulate memory degradation
    float grain = hash(floor(gl_FragCoord.y * 1000.0) + floor(gl_FragCoord.x * 1000.0));
    col += vec3(grain * 0.05);

    fragColor = vec4(pow(col, vec3(0.9)), 1.0);
}

vec2 rotate(vec2 p, float a) {
    float s = sin(a), c = cos(a);
    return vec2(p.x * c - p.y * s, p.x * s + p.y * c);
}

float fbm(vec2 st) {
    float value = 0.0;
    float amplitude = 0.5;
    float frequency = 2.0;
    for (int i = 0; i < 4; i++) {
        value += amplitude * sin(st.x * frequency + st.y * frequency * 1.1);
        st *= 2.0;
        frequency *= 2.0;
        amplitude *= 0.5;
    }
    return value;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 p0 = uv;
    float time = iTime * 3.14159; // Fast timelapse

    // Timelapse compression: zoom out then snap back
    float zoom = 0.2 + 4.0 * (sin(time) + 1.0); 
