    float b = 1.5 / zoom;
    uv *= b;

    // Fern fractal logic
    vec2 p = uv;
    float d = 0.0;
    float col = 0.0;

    // Iterative fern construction
    for (int i = 0; i < 6; i++) {
        float scale = pow(0.6, float(i));
        vec2 q = p;
        // Quantum wobble
        q.x += sin(q.y * 10.0 + time * 2.0) * 0.05 * scale;

        // Mandelbrot-ish fern iteration
        p = abs(p) - vec2(0.4, 0.2);
        p.x *= 1.0;
        p.y *= 0.8;

        float s = sin(length(q) * 10.0 - time * 5.0);
        d += abs(sin(length(p) * 10.0 + time * 2.0));
    }

    // Combine zoom dynamics with fractal detail
    float pattern = smoothstep(0.0, 0.5, d * 0.1 + sin(length(uv) * 20.0) * 0.5);

    // Quantum interference rim
    float quantum = sin(length(p0) * 100.0 - iTime * 10.0) * sin(length(p0) * 100.0 + iTime * 10.0);
    float rim = smoothstep(0.8, 1.0, abs(quantum));

    // Color mapping: Black -> Yellow -> Orange -> White
    vec3 colorA = vec3(0.05, 0.02, 0.0); // Deep ember
    vec3 colorB = vec3(1.0, 0.8, 0.1);   // Sulfur yellow
    vec3 colorC = vec3(1.0, 0.3, 0.0);   // Burning orange
    vec3 colorD = vec3(1.0, 1.0, 1.0);   // White hot

    // Mix colors based on intensity and zoom
    vec3 finalColor = mix(colorA, colorB, smoothstep(0.0, 0.5, pattern));
    finalColor = mix(finalColor, colorC, smoothstep(0.5, 0.8, pattern));
    finalColor = mix(finalColor, colorD, smoothstep(0.8, 1.0, pattern + rim * 0.3));

    // Add timelapse "speed" motion blur effect via brightness modulation
    float speedMod = 1.0 - (sin(time) + 1.0) * 0.2;
    finalColor *= speedMod + 0.5;

    fragColor = vec4(finalColor, 1.0);
}

float hash(float n) { return fract(sin(n) * 43758.5453); }
float noise(vec2 x) {
