// Radiographic Pyre Bloom
// Interprets SHC through an X-ray lens: bone-structure ferns burning through a glass plate.

float hash21(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}

float fbm(vec2 x) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    for (int i = 0; i < 5; ++i) {
        v += a * hash21(x * 2.0);
        x = x * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

// Barnsley Fern approximation
vec2 barnsley(vec2 p, float iter) {
    vec2 res = vec2(0.0);
    float density = 0.0;
    vec2 pt = vec2(0.0);

    // Iterate to find density at point p
    // We reverse the logic: project p back through transformations
    // Or simpler: forward iterate a point and check distance to p

    // For visual density, we use a raymarching-like approach on the fractal
    // But for a "bone" look, we map the fern function directly

    float d = 1000.0;

    // 4 main branches of the fern
    // 1. Stem (y -> y/2)
    vec2 q = vec2(p.x, p.y * 0.85 + 0.04 * p.x + 1.6);
    float dd = length(p - q);
    d = min(d, dd);

    // 2. Left leaf
    q = vec2(0.2 * p.x - 0.26 * p.y + 0.0, 0.23 * p.x + 0.22 * p.y + 1.6);
    d = min(d, length(p - q));

    // 3. Right leaf
    q = vec2(-0.15 * p.x + 0.28 * p.y + 0.0, 0.26 * p.x + 0.24 * p.y + 0.44);
    d = min(d, length(p - q));

    // 4. Main stem base
    q = vec2(0.0, 0.16 * p.y);
    d = min(d, length(p - q));

    // Recursion for self-similarity
    vec2 scale = vec2(0.95);
    vec2 center = vec2(0.0, 1.6);
    for(int i=0; i<6; i++) {
        p = (p - center) / scale;
        center = vec2(0.0, 1.6);
        scale *= vec2(0.95);
        // Re-evaluate distance in local space
        vec2 q1 = vec2(p.x, p.y * 0.85 + 0.04 * p.x + 1.6);
        vec2 q2 = vec2(0.2 * p.x - 0.26 * p.y + 0.0, 0.23 * p.x + 0.22 * p.y + 1.6);
        vec2 q3 = vec2(-0.15 * p.x + 0.28 * p.y + 0.0, 0.26 * p.x + 0.24 * p.y + 0.44);
        vec2 q4 = vec2(0.0, 0.16 * p.y);

        d = min(d, length(p - q1));
        d = min(d, length(p - q2));
        d = min(d, length(p - q3));
        d = min(d, length(p - q4));
    }

    return vec2(d, d);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    vec2 p = uv;

    // Time loop: 2.0 seconds
    float t = iTime;
    float loopT = mod(t, 2.0);
    float burnCycle = sin(loopT * 3.14159); // 0 to 1 to 0

    // X-ray background noise (film grain)
    float grain = fbm(p * 15.0 + vec2(t * 0.1, 0.0));
    vec3 baseColor = vec3(0.02, 0.04, 0.08); // Deep X-ray blue/black

    // Transform to fern space
    vec2 fp = p * 2.2 - vec2(0.0, 0.5);

    // Calculate fern density
    float d = barnsley(fp, 6.0).x;

    // Soften edges for "bone" look
    float soft = 1.0 / (1.0 + d * 15.0);
    soft = smoothstep(0.0, 0.5, soft);

    // "Combustion" effect: The fern is the bone structure, but the heat (noise) erodes it
    // Heat is highest at the tips (where d is small)
    float heat = fbm(p * 30.0 + vec2(t * 0.5, 0.0));
    float burn = (1.0 - soft) * burnCycle * heat;

    // X-ray Color Palette
    // Bone: Cyan/White
    // Burning: Orange/Red
    // Background: Black/Blue

    vec3 colorBone = vec3(0.6, 0.9, 1.0); // X-ray Cyan
    vec3 colorBurn = vec3(1.0, 0.4, 0.0); // Combustion Orange
    vec3 colorAsh = vec3(0.2, 0.1, 0.0);  // Ash

    // Mix based on burn intensity
    vec3 finalColor = mix(colorBone, colorBurn, burn);
    finalColor = mix(finalColor, colorAsh, burn * 0.5);

    // Apply density mask
    finalColor *= soft;

    // Add film grain
    float noiseVal = grain * 0.05;
    finalColor += vec3(noiseVal);

    // Vignette for X-ray plate look
    float vig = 1.0 - length(uv) * 0.5;
    finalColor *= vig;

    // Final composite
    vec3 result = baseColor + finalColor * 1.5;

    // Gamma correction for X-ray film look
    result = pow(result, vec3(0.9));

    fragColor = vec4(result, 1.0);
}

vec2 hash2(vec2 p) {
    vec3 p3 = fract(vec3(p) * 0.1031);
    p3 += dot(p3, p3.yzx + 33.33);
    return fract((p3.xx + p3.yz) * p3.z);
}

float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n = mix(mix(hash2(i).x, hash2(i + vec2(1.0, 0.0)).x, f.x),
                  mix(hash2(i + vec2(0.0, 1.0)).x, hash2(i + vec2(1.0, 1.0)).x, f.x), f.y);
    return n;
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    float rot = 30.0;
    for(int i = 0; i < 4; i++) {
        v += a * noise(p);
        p = mat2(cos(rot), -sin(rot), sin(rot), cos(rot)) * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

vec2 fernMap(vec2 uv, float t) {
    float r = length(uv) * 2.0;
    float a = atan(uv.y, uv.x);
    float scale = 0.5 + 0.5 * sin(t * 6.28318);
    vec2 p = uv * scale;

    float twist = fbm(p * 5.0 + vec2(t, 0.0)) * 2.0;
    float spiral = a + (r * 10.0) + twist;

    float leaflets = sin(spiral * 15.0 + r * 3.0);
    leaflets = smoothstep(-0.5, 0.5, leaflets);

    return p * leaflets;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - iResolution.xy * 0.5) / iResolution.y;
    float t = iTime;

    float loopT = fract(t * 0.5);

    vec3 color = vec3(0.95, 0.88, 0.75);

    float d = length(fernMap(uv, loopT));

    float strand = noise(uv * 8.0 + vec2(loopT * 5.0, 0.0));
    float detail = fbm(uv * 15.0 - vec2(loopT * 2.0, 0.0));

    float threshold = 0.3 + 0.1 * sin(loopT * 12.56636);

    float fernVal = (detail * (1.0 - d * 0.5));

    float ink = smoothstep(threshold - 0.02, threshold + 0.02, fernVal + strand * 0.2);

    vec3 inkColor = mix(vec3(0.1), vec3(0.4, 0.15, 0.0), 0.2);

    color = mix(color, inkColor, ink * 0.95);

    float grain = step(0.99, fract(uv.x * 200.0 + t * 0.1));
    color += grain * 0.05;

    fragColor = vec4(color, 1.0);
}

vec2 rot(vec2 p, float a) {
    float c = cos(a), s = sin(a);
    return vec2(p.x * c - p.y * s, p.x * s + p.y * c);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// 2D Fractal Brownian Motion for texture noise
float fbm(vec2 p) {
    float v = 0.0, a = 0.5;
    vec2 shift = vec2(100.0);
    for (int i = 0; i < 4; i++) {
        v += a * hash(p * float(i + 1));
        p *= 2.0;
        a *= 0.5;
    }
    return v;
}

// The "Shadow Puppet" Shape Function
// Combines a base pot silhouette with a fractal fern bloom
float sdPot(vec2 p, float time) {
    // Base pot shape (bowl)
    vec2 pp = p;
    float bowl = length(pp) - 0.6;

    // Fractal Fern logic
    vec2 q = pp;
    float d = 0.0;
    float scale = 0.25;
    float iterations = 6.0;
    float growth = sin(time * 3.14159) * 0.4 + 0.6; // Pulsing growth

    for (float i = 0.0; i < iterations; i++) {
        q = abs(q) - vec2(1.0, 0.0); // Folding
        q = q * rot(vec2(0.0), 0.2) + scale;
        // Accumulate fern detail
        d += (1.0 - length(q)) * exp(-length(pp * 2.0));
    }

    // Merge fern into pot shape
    return mix(bowl, d * growth, clamp(length(pp) * 1.5, 0.0, 1.0));
}

void main() {
    vec2 uv = (gl_FragCoord.xy - iResolution.xy * 0.5) / iResolution.y;
    // Center the pot
    uv.x += 0.1; 

    // Normalize time for 2s loop
    float t = mod(iTime, 2.0) / 2.0;

    // Procedural Pottery Texture (Clay)
    float clay = 1.0 - fbm(uv * 3.0 + vec2(t * 0.1));
    vec3 baseColor = vec3(0.45, 0.25, 0.15) * clay;

    // Shadow Puppet Silhouette
    float potShape = sdPot(uv, t);

    // Threshold for sharp shadow puppet cutout
    float shadow = step(0.2, potShape);

    // "Cold Fusion" Glow Logic
    // Hot spots (Red/Orange) + Cold spots (Blue/Cyan)
    float fusionGlow = smoothstep(0.0, 0.1, potShape - 0.15);
    fusionGlow = pow(fusionGlow, 2.5);

    // Color mixing: Ember + Fusion Cold
    vec3 ember = vec3(1.0, 0.6, 0.2);
    vec3 fusion = vec3(0.0, 0.8, 1.0);
    vec3 glowColor = mix(ember, fusion, sin(t * 3.0) * 0.5 + 0.5);

    vec3 finalColor = baseColor;

    // Apply Shadow (darkens everything behind pot)
    finalColor *= mix(0.8, 1.0, shadow);

    // Apply Glow inside the fern structure
    finalColor += glowColor * fusionGlow * (1.5 - length(uv));

    // Rim light for the pot silhouette
    float rim = 1.0 - smoothstep(0.3, 0.4, potShape);
    finalColor += vec3(0.8, 0.5, 0.2) * rim * shadow * 0.5;

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    float t = iTime;
    // Loop logic: 2 seconds
    float loop = mod(t, 2.0);
    float speed = 1.0 - loop; // "Pitch drop" slows down over time

    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);
    uv.x *= 1.2;

    // Base oscillation (The "Voice")
    float freq = 20.0 * speed + 5.0;
    float phase = loop * 10.0;
    float wave = sin(uv.x * freq + phase) * sin(uv.y * freq + phase * 0.5);

    // Fractal Fern/Spore generation
    vec2 p = uv * 6.0;
    float f = 0.0;
    float a = 0.0;

    for(int i = 0; i < 4; i++) {
        p = fract(p * 1.5) - 0.5;
        float d = length(p);
        float s = 0.02 / d + 0.5 * sin(3.0 * d * 10.0 * speed);
        f += s;
        a += s * (0.1 / (d * d + 0.01));
        p = p * 1.1 - 0.1;
    }

    // Combine wave and fractal
    f = f * 0.5 + wave * 2.0;
    f = smoothstep(0.0, 1.0, f);

    // Color Palette: Sulfur, Ember, Violet
    vec3 c1 = vec3(0.8, 0.95, 1.0); // Cold high pitch
    vec3 c2 = vec3(1.0, 0.6, 0.0); // Sulfur orange
    vec3 c3 = vec3(1.0, 0.2, 0.0); // Deep red ember

    // Mix based on "pitch" (loop position)
    vec3 col = mix(c1, c2, loop);
    col = mix(col, c3, clamp(loop * 3.0, 0.0, 1.0));

    // Add a "heavy gas" glow
    float glow = 1.0 - exp(-2.0 * f * speed);
    vec3 finalColor = col * (f + 0.2 * glow) * (1.0 - 0.5 * length(uv));

    // Oscilloscope trace line effect
    float trace = smoothstep(0.4, 0.6, abs(sin(uv.y * 50.0 - loop * 10.0)) * (0.1 + speed * 0.9));
    finalColor += vec3(1.0, 0.8, 0.6) * trace * 0.5;

    fragColor = vec4(finalColor, 1.0);
}

float hash(float n) { return fract(sin(n * 12.9898) * 43758.5453); }

vec3 fern(float t, vec2 uv) {
    // Scaled coordinates for fern
    vec2 p = uv * 3.0;
    float r = length(p);

    // Mandelbrot-like fern iteration logic
    vec2 c = p;
    float iter = 0.0;
    float max_iter = 15.0 + sin(t * 3.14159 * 2.0) * 5.0; // Pulsing depth

    vec2 z = vec2(0.0);
    float col = 0.0;

    for(float i = 0.0; i < 25.0; i++) {
        vec2 z2 = z * z;
        z = vec2(z2.x - z2.y, 2.0 * z.x * z.y) + c;
        float len = dot(z, z);
        if(len > 4.0) {
            iter = i + 1.0 - log(log(len)) / log(2.0);
            break;
        }
    }

    // Color mapping: Red -> Orange -> Green (Fire/Fern hybrid)
    vec3 base = mix(vec3(0.8, 0.1, 0.0), vec3(0.0, 1.0, 0.4), smoothstep(0.0, max_iter, iter));
    col = clamp(iter / max_iter, 0.0, 1.0);

    // Add "Extinguisher" nozzle shape via simple masking
    float dist = length(p - vec2(0.0, 0.5));
    float nozzle = smoothstep(0.6, 0.4, dist);
    base *= (0.7 + 0.3 * nozzle);

    return base * col;
}

vec3 vhsDistort(vec2 uv, float t) {
    // VHS Tracking artifacts: vertical jitter based on sine waves
    float scan = sin(t * 6.0 + uv.y * 50.0) * 0.005;
    float jitter = sin(t * 15.0 + uv.y * 20.0) * 0.002;

    vec2 p = uv;
    p.y += scan + jitter;

    // Chromatic Aberration (RGB separation)
    vec3 col = vec3(0.0);

    // Red Channel
    col.r = fern(t, p + vec2(scan * 0.1, 0.0)).r;
    // Green Channel
    col.g = fern(t, p).g;
    // Blue Channel
    col.b = fern(t, p - vec2(scan * 0.1, 0.0)).b;

    // Add Scanlines and noise
    float scanlines = step(0.95, fract(uv.y * iResolution.y));
    float noise = hash(floor(uv.y * iResolution.y) * 123.0 + floor(t * 10.0));

    col *= 0.95 + 0.05 * noise; // Slight signal noise
    col *= 1.0 - scanlines * 0.3; // Dark scanlines

    // VHS "Bleed" or overdrive effect
    col = smoothstep(0.0, 1.2, col);

    return col;
}

void main() {
    // Normalize UVs to center
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Time loop: 2.0 seconds
    float t = iTime;
    float loopT = mod(t, 2.0);

    // Animate the fern fractal slightly
    float anim = sin(loopT * 3.14159) * 0.2;
    vec2 animatedUV = uv + vec2(anim * 0.1, 0.0);

    // Apply VHS distortion to the coordinates
    vec3 col = vhsDistort(animatedUV, loopT);

    // Add a "Kitchen" ambient glow (dim red background)
    col += vec3(0.05, 0.0, 0.0) * (1.0 - length(uv));

    // Final brightness adjustment
    col = pow(col, vec3(1.0 / 1.8)); // Gamma correction

    fragColor = vec4(col, 1.0);
}

float hash21(vec2 p) { return fract(1e4 * sin(17.0 * p.x + 0.1 * p.y) * cos(13.0 * p.x + 0.3 * p.y)); }

// Iterative Signed Distance Field for a fractal tree to avoid recursion limits
float sdfTreeIter(vec2 p, float maxDepth) {
    float d = 0.0;
    vec2 q = p;
    float scale = 1.0;

    for (float i = 0.0; i < maxDepth; i++) {
        d = length(q) - 1.0;
        if (d > 0.0) return d * scale;

        q.y += 1.0;
        q = vec2(-q.y, q.x); // Rotate -90 deg
        scale *= 0.7;
        if (scale < 0.05) break;
    }
    return d * scale;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 uv2 = uv * 2.0 - 1.0;
    uv2.x *= iResolution.x / iResolution.y;

    float t = iTime;
    float loopT = t * 0.5; // 2 second loop

    // Rising tide effect
    float tide = sin(loopT * 6.28); 
    float waterLevel = uv2.y + tide * 0.8 + 0.2;

    // Base noise for risograph grain
    float grain = hash21(floor(uv * 50.0) + t * 20.0);

    // Fractal Fern geometry (Iterative)
    float dTree = sdfTreeIter(uv2 * 2.0 + vec2(0.0, -1.0), 8.0);
    float treeMask = smoothstep(0.02, 0.0, dTree) * 0.8;
    treeMask = pow(treeMask, 1.2);

    // Water surface distortion
    vec2 wUV = uv2;
    wUV.y = uv2.y - waterLevel;
    float wave = sin(wUV.x * 30.0 + t * 10.0) * 0.02;
    float water = smoothstep(0.05, -0.05, wUV.y);
    water *= 0.5 + 0.5 * sin(wUV.x * 20.0 + t * 5.0);

    // Risograph Overprint Simulation (Cyan and Magenta channels)
    vec2 shiftC = vec2(sin(t * 2.0) * 0.003, cos(t * 2.5) * 0.003);
    vec2 shiftM = vec2(cos(t * 2.0) * 0.004, sin(t * 2.3) * 0.004);

    float layerC = smoothstep(0.0, 0.02, dTree) * (1.0 - water) + (water > 0.0 ? water * 0.5 : 0.0);
    float layerM = smoothstep(0.0, 0.02, dTree * 0.9) * (1.0 - water) + (water > 0.0 ? water * 0.4 : 0.0);

    // Shift coordinates for overprint effect
    float finalC = step(0.01, hash21(uv + shiftC + vec2(0.0, tide * 2.0)));
    float finalM = step(0.01, hash21(uv + shiftM + vec2(0.0, tide * 2.2)));

    // Combine layers with "ink bleed" logic
    vec3 col = vec3(0.05, 0.05, 0.05); // Paper background

    // Cyan Layer (Tree + Water)
    col += vec3(0.0, 0.8, 0.9) * layerC * finalC;

    // Magenta Layer (Tree + Water, slightly shifted)
    col += vec3(0.9, 0.0, 0.4) * layerM * finalM;

    // Overlay harsh grain
    col += vec3(grain * 0.1);

    // Vignette for "documentary" feel
    float dist = distance(uv, vec2(0.5));
    col *= 1.0 - smoothstep(0.4, 0.7, dist) * 0.6;

    fragColor = vec4(col, 1.0);
}

float hash(float n) {
    return fract(sin(n) * 43758.5453123);
}

float noise(vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    float n = p.x + p.y * 57.0;
    return mix(mix(hash(n + 0.0), hash(n + 1.0), f.x),
               mix(hash(n + 57.0), hash(n + 58.0), f.x), f.y);
}

float fbm(vec2 x) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 5; i++) {
        v += a * noise(x);
        x *= 2.0;
        a *= 0.5;
    }
    return v;
}

vec3 fern(vec2 uv) {
    vec2 p = uv * 4.0 - 2.0;
    float scale = 1.0;
    float detail = 0.0;
    int iter = 8;

    vec2 q = p;
    for(int i=0; i<iter; i++) {
        if(length(q) < 0.1) {
            float s = sin(q.y) * cos(q.x);
            q = q * 1.5 + vec2(0.1, 0.3) * s;
        }
        detail += pow(length(q), 0.2) * scale;
        scale *= 0.8;
        q *= 2.0;
    }
    return vec3(detail, detail * 1.5, detail * 0.5);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 st = uv - 0.5;

    float t = iTime;
    float loopT = sin(t * 3.14159 * 2.0); 

    vec3 col = fern(st * 3.0);

    float wool = fbm(st * 8.0 + vec2(t, -t));
    col.x += wool * 0.1;

    vec3 metal = vec3(0.05, 0.05, 0.08);

    float heat = max(0.0, col.x - 0.4);
    heat = pow(heat, 2.5) * (0.5 + loopT * 0.5); 

    float n = fbm(st * 10.0);

    // WebGL2 compatible derivatives
    float dx = dFdx(n);
    float dy = dFdy(n);

    vec3 lightDir = vec3(0.5, 0.5, 1.0);
    vec3 normal = normalize(vec3(dx, dy, 0.8));
    float diff = max(0.0, dot(normal, lightDir));

    vec3 cold = metal + wool * vec3(0.05, 0.02, 0.02);
    vec3 warm = vec3(1.0, 0.3, 0.0) * heat; 
    vec3 hot  = vec3(1.0, 0.8, 0.6) * heat * heat; 

    vec3 finalColor = mix(cold, warm, smoothstep(0.0, 1.5, heat));
    finalColor += hot * 2.0;

    finalColor += vec3(0.1, 0.1, 0.1) * pow(diff, 4.0) * (1.0 + wool);

    float vig = 1.0 - length(st) * 1.2;
    finalColor *= smoothstep(0.2, 1.0, vig);

    fragColor = vec4(finalColor, 1.0);
}

float hash(float p) {
    return fract(sin(p) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(dot(i, vec2(12.9898, 78.233)));
    float b = hash(dot(i + vec2(1.0, 0.0), vec2(12.9898, 78.233)));
    float c = hash(dot(i + vec2(0.0, 1.0), vec2(12.9898, 78.233)));
    float d = hash(dot(i + vec2(1.0, 1.0), vec2(12.9898, 78.233)));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p, float scale) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    for (int i = 0; i < 5; i++) {
        v += a * noise(p * scale);
        p *= 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

float fern(vec2 uv) {
    vec2 p = uv * 2.0;
    p -= vec2(0.5);

    float val = 0.0;
    for (int i = 0; i < 6; i++) {
        float scale = pow(2.0, float(i) * 0.45);
        float angle = (i % 2 == 0) ? 0.5 : -0.5;

        vec2 q = p;
        float cx = cos(angle);
        float sx = sin(angle);
        float nx = q.x * cx - q.y * sx;
        float ny = q.y * cx + q.x * sx;

        q.x = nx * 0.6;
        q.y = ny;
        q *= scale;

        val += 0.5 * fbm(q, 1.5);
    }
    return val;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    float t = mod(iTime, 2.0);
    float loop = sin(t * 3.14159); 

    float f = fern(uv);
    float intensity = clamp(f * 3.0 + 0.5 * noise(uv * 5.0 + t), 0.0, 1.0);

    float dist = length(uv);
    float vignette = 1.0 - smoothstep(0.5, 1.5, dist);

    vec3 col = vec3(0.0);

    vec3 living = vec3(0.05, 0.4, 0.15);
    vec3 burning = vec3(1.0, 0.4, 0.0);
    vec3 ash = vec3(0.9, 0.9, 0.95);
    vec3 hot = vec3(1.0, 0.8, 0.6);

    float burnStage = smoothstep(0.0, 1.0, intensity) * loop;

    if (burnStage < 0.3) {
        col = mix(living, burning, (burnStage / 0.3) * 0.5);
    } else if (burnStage < 0.6) {
        float flicker = sin(uv.x * 50.0 + t * 20.0) * 0.1;
        col = mix(burning, hot, (burnStage - 0.3) / 0.3 + flicker);
    } else {
        col = mix(hot, ash, (burnStage - 0.6) / 0.4);
        col *= 1.0 + intensity * 0.2;
    }

    float glass = 0.05 + 0.15 * sin(uv.y * 10.0 + t * 5.0);
    col += vec3(0.02, 0.03, 0.05) * glass * vignette;

    vec3 bg = vec3(0.02, 0.02, 0.04);
    col = mix(bg, col, vignette * intensity * 2.0);

    col += col * col * 0.5;

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);

    float t = mod(iTime, 2.0);
    float phase = sin(t * 3.14159);

    // Rotate the entire cake
    float angle = t * 2.0 * 3.14159;
    float s = sin(angle);
    float c = cos(angle);
    vec2 p = vec2(uv.x * c - uv.y * s, uv.x * s + uv.y * c);

    // 1. Woven Textile Base
    float weaveScale = 30.0;
    vec2 weaveUV = p * weaveScale;
    float warp = sin(weaveUV.x) * cos(weaveUV.y);
    float weft = cos(weaveUV.x) * sin(weaveUV.y);

    // Hard edges for the weave structure
    float fabric = (abs(warp) + abs(weft)) * 0.5;
    float thread = step(0.25, fabric) - step(0.75, fabric);

    // 2. Candle Wax Fractures (SDFs)
    vec2 center = vec2(0.0);
    float r = 0.25;
    float candleMask = 0.0;
    float candleAngleStep = 2.0 * 3.14159 / 5.0;

    for (int i = 0; i < 5; i++) {
        float a = float(i) * candleAngleStep;
        vec2 cOff = vec2(cos(a), sin(a)) * r;
        vec2 d = p - cOff;
        float dC = length(d) - 0.04;

        // Drip effect: elongates downwards based on time
        float drip = max(d.y - (phase * 0.08), d.x * 0.1);
        float candle = dC - drip;
        // Sharp fracture edges
        candleMask += smoothstep(-0.005, 0.005, candle);
    }

    // 3. Strawberry Voxels
    float strawberry = 0.0;
    for (int i = 0; i < 3; i++) {
        float a = float(i) * 2.0 * 3.14159 / 3.0 + t * 0.5;
        vec2 sOff = vec2(cos(a), sin(a)) * (r + 0.05);
        vec2 sd = p - sOff;
        float dist = length(sd) - 0.06;
        strawberry += smoothstep(0.02, 0.0, dist);
    }

    // Color Palette
    vec3 colBase = vec3(0.92, 0.90, 0.88); // Cream
    vec3 colThread = vec3(0.15, 0.05, 0.02); // Dark weave
    vec3 colWax = vec3(0.98, 0.85, 0.65); // Gold/Wax
    vec3 colBerry = vec3(0.8, 0.0, 0.1); // Crimson

    // Composition
    vec3 col = colBase;

    // Apply weave
    col = mix(col, colThread, thread * 0.8);

    // Apply strawberries (glitchy overlay)
    if (strawberry > 0.5) {
        col = mix(col, colBerry, strawberry);
    }

    // Apply candles (fracture overlay)
    if (candleMask > 0.1) {
        col = mix(col, colWax, candleMask);
        // Add a dark fracture line inside the wax
        col *= 1.0 - step(0.01, abs(length(p) - r)) * 0.2;
    }

    // Vignette
    float vig = 1.0 - length(p) * 0.8;
    col *= smoothstep(0.0, 1.0, vig);

    fragColor = vec4(col, 1.0);
}

void main() {
    float loopT = fract(iTime * 0.5); 
    float t = 2.0 * loopT;
    float dt = t;

    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / min(iResolution.x, iResolution.y);

    // Voxelizing the cross-section
    float freq = 4.0;
    // Fix: Ensure p is vec3 by adding z component or casting
    vec3 p = fract(vec3(uv * freq + vec2(dt, -dt), 0.0));
    p.y = 1.0 - p.y; // Flip Y for standard image coords

    // Cake geometry: Sponge + Frosting + Strawberries
    vec3 col = vec3(0.0);
    // Fix: Ensure center is vec3
    float dist = distance(p, vec3(0.5, 0.5, 0.5));

    // Sponge layer
    if (dist < 0.35 && p.y > 0.15) {
        col = vec3(0.9, 0.85, 0.5); 
    } 
    // Frosting top
    else if (p.y > 0.85 && p.y < 1.0 && dist < 0.4) {
        col = vec3(0.95, 0.2, 0.4);
        // Strawberry Voxels (hard logic)
        if (mod(p.x, 0.2) < 0.05 && mod(p.y - 0.8, 0.2) < 0.05) {
            col = vec3(1.0, 0.05, 0.2);
        }
    }
    // Candles (vertical lines in slice)
    if ((p.x > 0.3 && p.x < 0.35 && p.y > 0.8 && p.y < 0.95) ||
        (p.x > 0.65 && p.x < 0.7 && p.y > 0.8 && p.y < 0.95)) {
        col = vec3(1.0, 0.5, 0.8);
        // Wick
        if (p.y > 0.94) col = vec3(0.1, 0.0, 0.0);
    }

    // Voxelize the result (hard edges)
    col = floor(col * 16.0) / 16.0;

    // Shadow Puppet Theater Logic
    float angle = iTime;
    float flicker = sin(iTime * 15.0) * 0.1 + cos(iTime * 7.0) * 0.1 + 0.5;
    flicker = pow(flicker, 2.0); // Pulse effect

    // The "Shadow" is a scaled, hard-edged version of the cake mask
    vec2 proj = uv * (1.0 + flicker * 0.3);
    proj.x *= cos(angle); 
    proj.y *= sin(angle);

    // Create the hard shadow mask
    float mask = smoothstep(0.45, 0.55, distance(proj, vec2(0.0, 0.0))) - 
                 smoothstep(0.3, 0.35, distance(proj, vec2(0.0, 0.0)));

    // Combine: The cake slice is the light source, the shadow is the puppet
    vec3 finalCol = vec3(0.15, 0.12, 0.1); // Parchment dark

    // Add the "Lit" cake slice
    finalCol += col * 0.9;

    // Apply the shadow overlay (puppetry)
    float shadowAlpha = 1.0 - smoothstep(0.2, 0.8, mask);
    // Hard cut for shadow
    shadowAlpha = step(0.1, shadowAlpha); 

    finalCol = mix(finalCol, vec3(0.0), shadowAlpha * flicker);

    // Add "Strawberry" glow on the shadow edge
    if (shadowAlpha > 0.9 && shadowAlpha < 1.0) {
        finalCol += vec3(1.0, 0.2, 0.4) * 0.5;
    }

    // Quantize final output for that "slice" look
    finalCol = floor(finalCol * 8.0) / 8.0;

    fragColor = vec4(finalCol, 1.0);
}

float mod2p(float x, float m) { return x - m * floor(x / m); }

vec3 stainedGlass(float t, vec3 a, vec3 b, vec3 c, vec3 d) {
    vec3 col = a + b * cos(6.283 * (c * t + d));
    col = floor(col * 12.0) / 12.0;
    return col;
}

float sdCylinder(vec3 p, vec2 h) {
    vec2 d = abs(vec2(length(p.xz), p.y));
    return length(max(d - h, 0.0)) + min(max(d.x - h.x, d.y - h.y), 0.0);
}

float sdSphere(vec3 p, float r) {
    return length(p) - r;
}

float map(vec3 p) {
    float angle = iTime * 2.0;
    float s = sin(angle); 
    float c = cos(angle);
    mat2 rot = mat2(c, -s, s, c);
    p.xz *= rot;

    vec2 cakeRadius = vec2(0.7, 0.8);
    float cake = sdCylinder(p, cakeRadius);

    float r = length(p.xz);
    float theta = atan(p.z, p.x);
    float z = p.y;
    float t_grid = mod2p(theta, 6.28314);
    float u = mod2p(r * 5.0 + t_grid, 2.0);
    float v = mod2p(z * 4.0 - iTime, 2.0);
    float distToGrid = length(vec2(u - 1.0, v - 1.0));

    float strawberry = 10.0;
    if (distToGrid < 0.6) {
        float offset = 0.15;
        vec3 offsetVec = vec3(p.x, p.y, p.z);
        offsetVec.xz *= (1.0 / length(p.xz)) * offset * 1.1;
        strawberry = sdSphere(p - offsetVec, 0.15);
    }

    float topZ = 0.75;
    float distToTop = abs(p.y - topZ);
    if (distToTop < 0.1 && length(p.xz) < 0.5) {
        float candle = sdCylinder(p, vec2(0.12, 0.2)) - 0.01;
        strawberry = min(strawberry, candle);
    }

    float surface = min(cake, strawberry);

    vec3 latticeP = p;
    latticeP.xz *= mat2(cos(iTime * 1.5), -sin(iTime * 1.5), sin(iTime * 1.5), cos(iTime * 1.5));

    float grid = length(vec2(
        mod2p(latticeP.x, 0.3) - 0.15,
        mod2p(latticeP.z, 0.3) - 0.15
    ));
    float vert = mod2p(latticeP.y, 0.4) - 0.2;
    float glassCut = length(vec2(grid, vert));

    if (cake < 0.05) {
        return min(surface, max(glassCut - 0.01, -0.1));
    }
    return surface;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec3 ro = vec3(0.0, 0.0, 2.2);
    vec3 rd = normalize(vec3(uv, -1.0));

    float t = 0.0;
    for (int i = 0; i < 60; i++) {
        vec3 p = ro + rd * t;
        float d = map(p);
        if (d < 0.001) break;
        t += d;
        if (t > 10.0) break;
    }

    vec3 col = vec3(0.05, 0.05, 0.08);
    if (t < 10.0) {
        vec3 p = ro + rd * t;
        vec3 n = vec3(
            map(p + vec3(0.01, 0.0, 0.0)) - map(p - vec3(0.01, 0.0, 0.0)),
            map(p + vec3(0.0, 0.01, 0.0)) - map(p - vec3(0.0, 0.01, 0.0)),
            map(p + vec3(0.0, 0.0, 0.01)) - map(p - vec3(0.0, 0.0, 0.01))
        );
        n = normalize(n);
        vec3 light = normalize(vec3(0.5, 1.0, 0.5));
        float diff = clamp(dot(n, light), 0.1, 1.0);

        float r = length(p.xz);
        float theta = atan(p.z, p.x);
        float z = p.y;
        float t_g = mod2p(theta, 6.28314);
        float u = mod2p(r * 5.0 + t_g, 2.0);
        float v = mod2p(z * 4.0 - iTime, 2.0);
        float distToGrid = length(vec2(u - 1.0, v - 1.0));

        if (distToGrid < 0.5 && p.y < 0.8) {
            col = stainedGlass(diff, vec3(0.1, 0.0, 0.0), vec3(0.8, 0.0, 0.0), vec3(1.0), vec3(0.0, 0.2, 0.4));
        } else if (p.y > 0.7 && length(p.xz) < 0.15) {
            col = stainedGlass(diff, vec3(0.4, 0.4, 0.0), vec3(0.6, 0.5, 0.0), vec3(1.0), vec3(0.0, 0.0, 0.0));
        } else {
            col = stainedGlass(diff, vec3(0.1, 0.1, 0.1), vec3(0.8, 0.8, 0.8), vec3(1.0), vec3(0.0, 0.0, 0.0));
        }
    }

    float vig = 1.0 - length(uv) * 0.5;
    col *= vig;

    fragColor = vec4(col, 1.0);
}

vec2 mapCycl(float t) {
    return vec2(cos(t), sin(t));
}

// Hard quantization for "cathode ray" feel
vec3 quantColor(vec3 c, float steps) {
    return vec3(floor(c * steps) / steps);
}

// The main SDF-like distance field for the trace path
float getTraceDist(vec2 uv) {
    float time = iTime;
    float period = 2.0;

    // Normalize time for loop
    float t = mod(time, period) / period; 

    // Spiral structure: radius shrinks as we go up (y)
    float spiralRadius = 0.8 - (uv.y + 0.5) * 1.2;
    float angle = t * 6.2832 * 4.0 - (uv.y * 2.0); // Spin + vertical twist

    // Base spiral coordinates
    vec2 p = vec2(spiralRadius * cos(angle), spiralRadius * sin(angle));

    // Map to screen space with perspective tilt
    vec2 screenPos = uv + p * 0.3;

    // Modulate radius to create "strawberry bumps" (3 bumps per layer)
    float bumps = sin(angle * 3.0 - time * 2.0) * 0.15;
    screenPos.x += bumps * cos(angle);
    screenPos.y += bumps * sin(angle) * 0.5;

    // Add "Candle Flame" oscillation at the top layers
    float height = uv.y + 0.5;
    float flameAmp = smoothstep(0.2, 0.0, height) * 0.08;
    float flicker = sin(time * 15.0 + screenPos.y * 10.0) * flameAmp;
    screenPos.x += flicker;

    // Map to a tight ring for the oscilloscope trace look
    // We want the trace to be a single line wrapping the shape
    float dist = length(screenPos - uv);

    // Add a "twist" to the thickness to mimic velocity
    float thickness = 0.02 + 0.01 * sin(time * 10.0);

    return dist - thickness;
}

void main() {
    // Normalize coordinates -1 to 1
    vec2 uv = (gl_FragCoord.xy - iResolution.xy * 0.5) / iResolution.y;

    // Stretch for cake aspect ratio
    uv.x *= 1.3;

    float d = getTraceDist(uv);

    // Color palette: Deep Red to Electric Amber
    vec3 colBlack = vec3(0.02);
    vec3 colRed = vec3(0.9, 0.05, 0.1);
    vec3 colAmber = vec3(1.0, 0.6, 0.1);

    // Gradient based on vertical position (Bottom = Red/Strawberry, Top = Amber/Flame)
    vec3 baseCol = mix(colRed, colAmber, smoothstep(-0.3, 0.3, uv.y + 0.2));

    // Add a slight blue tint for the "cold" CRT glass feel
    baseCol += 0.05 * vec3(0.2, 0.4, 0.8);

    // Create the trace line with a glow falloff
    float glow = 0.15 / (d * d + 0.001);
    glow = pow(clamp(glow, 0.0, 1.0), 1.5);

    // Hard posterization step for "digital oscilloscope" look
    float intensity = smoothstep(0.03, -0.01, d); // Invert d for line

    vec3 finalColor = mix(colBlack, baseCol, intensity * glow);

    // Add a scanline effect
    float scanline = 1.0 - sin(gl_FragCoord.y * 0.02) * 0.1;
    finalColor *= scanline;

    // Quantize color depth for retro CRT feel
    finalColor = quantColor(finalColor, 4.0);

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    // Coordinate normalization
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Time setup: 2.0s loop
    float t = iTime; 
    float loop = t * 0.5; // 360 degrees in 2 seconds
    float fastT = t * 4.0;

    // Rotate view around Y-axis (in 2D, this is just polar rotation)
    float angle = loop;
    float sa = sin(angle);
    float ca = cos(angle);

    // Polar coordinates for the cake layers
    float r = length(uv);
    float a = atan(uv.y, uv.x);

    // --- SDF Construction: The Cake Vortex ---
    // We define a "cake" as a stack of cylinders, but we distort them into a vortex
    // by adding a rotational component to the radial distance based on height (simulated via Z).

    vec2 p = vec2(uv.x * ca - uv.y * sa, uv.x * sa + uv.y * ca); // Rotate world
    float dist = 0.0;

    // 1. Cake Body (Cylinders)
    // Instead of smooth steps, we use hard bands to create a "layered" schematic look
    float h = 0.5; // height per layer
    float layers = 3.0;
    // Create a "vortex" effect: as r increases, the angle shifts
    float vortexAngle = a * 2.0 + t * 0.5;
    float zSim = mod(r * 2.0 + vortexAngle, 1.0) - 0.5;

    // Distance to nearest cake layer ring
    // We map r to a 1D space, wrap it, and find distance to layer centers
    float layerSpace = r - 0.5;
    float layerDist = abs(mod(layerSpace, 1.0) - 0.5) - 0.2; // 0.2 is layer thickness

    // 2. Strawberries (Spherical spikes on the surface)
    // Place them in a spiral pattern
    float spiralR = r + 0.2; // Slightly outside the cake
    float spiralA = a + t;
    float numStraw = 6.0;
    float strawAngle = mod(spiralA, 2.0 * 3.14159 / numStraw) - 3.14159 / numStraw;
    float strawDist = length(vec2(strawAngle * 10.0, spiralR - 0.8)) - 0.1;

    // 3. Candles (Tall thin cylinders on top)
    float candleR = length(vec2(0.0, 0.0)); // Center
    // Actually, let's put candles on the top layer ring
    float topLayerR = 0.9;
    float candDist = length(vec2(r - topLayerR, (a - t) * 10.0));
    candDist = abs(candDist - 0.02) - 0.01; // Thin ring of candles

    // Combine SDFs (Union with minimum)
    // We want distinct features: Body, Strawberries, Candles
    float dBody = layerDist;
    float dStraw = strawDist;
    float dCandle = candDist;

    // Use smooth min to blend but keep hard edges for schematic look
    // Actually, for schematic, hard min is better.
    float d = min(dBody, min(dStraw, dCandle));

    // --- Schematic Annotation Layer ---
    // Add dimension lines and grid
    float grid = 0.01;
    float g1 = fract(uv.x * 20.0) - 0.5;
    float g2 = fract(uv.y * 20.0) - 0.5;
    float gridDist = min(abs(g1), abs(g2)) - 0.005;

    // Dimension lines rotating
    float dimAngle = mod(a + fastT, 0.5) - 0.25;
    float dimDist = abs(dimAngle) - 0.01;

    // --- Coloring & Rendering ---
    // Palette: Navy (bg), Orange (strawberry), White (lines), Cyan (grid)

    vec3 bg = vec3(0.05, 0.05, 0.15); // Deep Navy
    vec3 strawCol = vec3(1.0, 0.3, 0.0); // Safety Orange
    vec3 cakeCol = vec3(0.9, 0.9, 1.0); // Off-white
    vec3 gridCol = vec3(0.2, 0.8, 0.9); // Cyan

    vec3 col = bg;

    // Render Cake Body
    if (dBody < 0.05) {
        col = mix(col, cakeCol, 0.8);
    }

    // Render Strawberries
    if (dStraw < 0.15) {
        col = mix(col, strawCol, 1.0);
        // Add a "schematic" outline to strawberries
        if (dStraw < 0.01) col = vec3(1.0);
    }

    // Render Candles
    if (dCandle < 0.05) {
        col = mix(col, vec3(0.8, 0.1, 0.8), 1.0); // Pinkish candle wax
        // Flame flicker
        float flicker = sin(fastT * 10.0 + r) * 0.5 + 0.5;
        col = mix(col, vec3(1.0, 0.8, 0.0), flicker * 0.5);
    }

    // Render Grid/Annotations on top
    if (gridDist < 0.0) {
        col = mix(col, gridCol, 0.5);
    }
    if (dimDist < 0.0) {
        col = mix(col, vec3(0.8, 0.8, 0.8), 0.5);
    }

    // Hard Quantization / Posterization for "Blueprint" look
    // Only 3-4 color bands allowed
    col = floor(col * 4.0) / 4.0;

    // Vignette for focus
    float vignette = 1.0 - length(uv) * 0.8;
    col *= smoothstep(0.2, 1.0, vignette);

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = iTime * 1.5; // Speed for 2s loop feel

    // 1. Coordinate Setup: Cylindrical Spin
    float spin = sin(t) * 0.2; // Wobble
    float angle = t * 2.0;     // Rotation speed
    float ca = cos(angle + spin);
    float sa = sin(angle + spin);

    // Map 2D screen to 3D cylindrical coordinates
    // x -> cylinder angle, y -> cylinder height
    float cylY = uv.y * 1.8 + 0.5; // Stretch height
    float cylX = uv.x * 4.0 + 0.5; // Wrap around

    // Wrap UV for cylinder illusion
    float wrap = fract(cylX - angle * 0.2) - 0.5;
    float depth = 1.0 - smoothstep(0.0, 0.4, abs(wrap)); // Fake depth falloff

    // 2. The Cake Body: Lattice Grid
    // Create a hard-edged grid pattern
    float grid = step(0.95, abs(fract(wrap * 8.0) - 0.5) + abs(fract(cylY * 10.0) - 0.5));

    // 3. Strawberry Voxels: Quantized blobs
    float strb = smoothstep(0.0, 0.02, abs(fract(wrap * 4.0 + sin(cylY * 2.0 + t)) - 0.5));
    float strb2 = step(0.8, strb + sin(t * 4.0)); // Glitching on/off
    float strawberry = strb2 * (1.0 - length(vec2(wrap - 0.2, cylY - 0.8))); // Localized cluster

    // 4. The Candles: Sharp Prisms
    vec3 candlePos = vec3(-0.3, 0.2, 0.0), c2 = vec3(0.0, 0.2, 0.0), c3 = vec3(0.3, 0.2, 0.0);
    // Project 3D candle positions onto our 2D unwrapped cylinder space
    float d1 = abs(wrap - (candlePos.x * 0.5));
    float d2 = abs(wrap - (c2.x * 0.5));
    float d3 = abs(wrap - (c3.x * 0.5));

    // Candle flame flicker (hard quantization, not soft noise)
    float flicker = step(0.0, fract(sin(t * 10.0) * 0.5) - 0.1); 
    float candleCore = max(d1, max(d2, d3));
    candleCore = 1.0 - smoothstep(0.0, 0.05, candleCore);
    float flame = candleCore * (0.8 + flicker * 0.4) * step(cylY, 0.8 + flicker * 0.2);

    // 5. Color Composition
    vec3 col = vec3(0.0);

    // Base Glass (Teal/Black)
    col += vec3(0.02, 0.08, 0.12) * depth;

    // Lattice Lines (White/Cyan)
    if (grid > 0.9) col += vec3(0.2, 0.4, 0.4) * depth;

    // Strawberries (Deep Red)
    if (strawberry > 0.0) {
        col += vec3(0.9, 0.1, 0.2) * strawberry * (1.0 - strawberry * 0.5);
    }

    // Candles (Orange/White)
    if (flame > 0.0) {
        vec3 fireCol = vec3(1.0, 0.6, 0.1);
        // Add a hard "caustic" band from the flame
        float caustic = step(0.8, abs(sin((cylY + t) * 10.0) + flicker));
        col += fireCol * flame * (1.0 + caustic * 0.5);
    }

    // 6. Glass Refraction & Hard Quantization
    // Simulate a lens distortion via polar warping
    float r = length(uv);
    float p = atan(uv.y, uv.x);
    float warp = p + sin(t * 3.0) * 0.02 / max(0.1, r);

    // Hard Posterization for "digital glass" look
    col = floor(col * 20.0) / 20.0;

    // Vignette
    float v = 1.0 - smoothstep(0.5, 1.2, r);
    col *= v;

    // Final output with slight chromatic shift based on time
    float shift = sin(t) * 0.05;
    vec3 finalColor = col;
    finalColor.r = col.g; // Simple glitch channel swap for style

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    uv = uv * 2.0 - 1.0;
    uv.x *= iResolution.x / iResolution.y;

    float t = mod(iTime, 2.0);
    float t2 = t * 6.2831853;

    vec2 p = uv * 4.0;
    float dist = length(p);

    vec4 col = vec4(0.05, 0.05, 0.06, 1.0);

    float rCake = 0.9;
    float angle = t2;

    vec2 rp = vec2(
        p.x * cos(angle) - p.y * sin(angle),
        p.x * sin(angle) + p.y * cos(angle)
    );

    float lattice = abs(fract(rp.x * 12.0) - 0.5) + abs(fract(rp.y * 12.0) - 0.5);
    float cakeMask = step(rCake - 0.05, dist) * step(dist, rCake + 0.05);

    vec3 cakeColor = mix(vec3(0.1, 0.9, 1.0), vec3(1.0, 0.0, 0.6), sin(lattice * 10.0) * 0.5);
    col += vec4(cakeColor, 1.0) * cakeMask;

    for (float i = 0.0; i < 1.0; i += 0.2) {
        float sAngle = angle + 1.0 + i * 6.2831853;
        vec2 sCenter = vec2(cos(sAngle), sin(sAngle)) * (rCake * 0.6);
        float sDist = length(p - sCenter);
        float sShape = 1.0 - smoothstep(0.14, 0.17, sDist);
        col += vec4(vec3(1.0, 0.1, 0.1) * 2.0, 1.0) * sShape * cakeMask;
    }

    for (float i = 0.0; i < 1.0; i += 0.333) {
        float cAngle = angle + i * 6.2831853;
        vec2 cBase = vec2(cos(cAngle), sin(cAngle)) * (rCake * 0.3);

        float candDist = length(p - cBase);
        float candBody = 1.0 - smoothstep(0.02, 0.035, candDist);
        col += vec4(vec3(1.0, 0.5, 0.0) * 1.5, 1.0) * candBody;

        float pAngle = angle * 4.0;
        float pRad = 0.12;
        vec2 flameTip = cBase + vec2(cos(pAngle), sin(pAngle)) * pRad + vec2(0.0, 0.05);

        vec2 vecToTip = flameTip - cBase;
        float len = length(vecToTip);
        if (len > 0.001) {
            vec2 dir = vecToTip / len;
            vec2 toQ = p - cBase;
            float proj = dot(toQ, dir);
            float distToLine = abs(toQ.x * dir.y - toQ.y * dir.x);

            float flameShape = 1.0 - smoothstep(0.03, 0.05, distToLine);
            float taper = smoothstep(0.0, len, proj) * smoothstep(len, 0.0, proj); 
            flameShape *= taper;

            col += vec4(vec3(1.0, 1.0, 0.3) * 3.0, 1.0) * flameShape;
        }
    }

    vec2 reflUv = vec2(p.x, -p.y * 1.5);
    float reflDist = length(reflUv);
    float reflMask = step(rCake - 0.1, reflDist) * step(reflDist, rCake + 0.1);

    if (reflMask > 0.5) {
        float quant = floor(reflUv.y * 40.0) / 40.0;
        float glitch = step(0.5, fract(quant));
        col += vec4(vec3(cakeColor * 0.15), 1.0) * glitch * 0.5;
    }

    fragColor = col;
}

float sdBox(vec3 p, vec3 b) {
    vec3 q = abs(p) - b;
    return length(max(q, 0.0)) + min(max(q.x, max(q.y, q.z)), 0.0);
}

float map(vec3 p) {
    // Lattice structure
    vec3 cell = floor(p / 2.5);
    vec3 local = mod(p, 2.5) - 1.25;

    // Time-based fracture wave
    float t = mod(iTime, 2.0);
    float wave = sin((p.y + cell.y) * 2.0 - t * 15.0);
    float stress = step(0.8, abs(wave));

    // Pipe geometry with dynamic displacement
    vec3 displacement = vec3(0.0);
    if (stress > 0.5) {
        displacement.x = sin(local.z * 10.0 + t * 20.0) * 0.1 * stress;
        displacement.y = cos(local.x * 10.0 - t * 20.0) * 0.1 * stress;
    }

    vec3 q = local + displacement;
    vec3 box = vec3(0.35 + stress * 0.05); // Fixed: ensure box is a vec3

    float d = sdBox(q, box);

    // Neon glow based on stress
    float glow = smoothstep(0.8, 1.0, stress) * 0.2;
    return d - glow;
}

vec3 getNormal(vec3 p) {
    const float eps = 0.001;
    const vec2 h = vec2(0, eps);
    return normalize(vec3(map(p+h.xyy) - map(p-h.xyy),
                          map(p+h.yxy) - map(p-h.yxy),
                          map(p+h.yyx) - map(p-h.yyx)));
}

float raymarch(vec3 ro, vec3 rd) {
    float dO = 0.0;
    for (int i = 0; i < 60; i++) {
        vec3 p = ro + rd * dO;
        float dS = map(p);
        dO += dS;
        if (dO > 100.0 || dS < 0.001) break;
    }
    return dO;
}

void main() {
    // Aspect ratio correction
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Camera setup
    vec3 ro = vec3(0.0, 0.0, -6.0);
    vec3 rd = normalize(vec3(uv, 1.0));

    // Raymarching
    float dist = raymarch(ro, rd);
    vec3 col = vec3(0.05, 0.03, 0.02); // Dark void

    vec3 p = vec3(0.0); // Declare p for grain calculation

    if (dist < 99.0) {
        p = ro + rd * dist;
        vec3 n = getNormal(p);

        // Lighting: Neon Cyan vs Sepia
        vec3 lightDir = normalize(vec3(1.0, 1.0, 1.0));
        float diff = clamp(dot(n, lightDir), 0.0, 1.0);
        float spec = pow(max(dot(reflect(-lightDir, n), rd), 0.0), 32.0);

        // The "Neon Lattice" color logic
        vec3 neon = vec3(0.2, 0.95, 1.0); // Cyan
        vec3 silver = vec3(0.7, 0.7, 0.65);

        float stress = 0.0;
        // Re-evaluate stress for coloring without raymarch overhead
        vec3 cell = floor(p / 2.5);
        float wave = sin((p.y + cell.y) * 2.0 - mod(iTime, 2.0) * 15.0);
        stress = step(0.8, abs(wave));

        vec3 base = mix(silver, neon, stress * 0.8);

        col = base * diff + neon * spec * 0.8;

        // Depth fog for "Daguerreotype" atmosphere
        float fog = 1.0 / (1.0 + dist * 0.4);
        col = mix(vec3(0.02, 0.01, 0.0), col, fog);
    }

    // Daguerreotype / Chemical Processing
    // 1. Grayscale-ish tint with color bleeding
    col = col * 0.7 + col.r * 0.15 + col.b * 0.1; // Sepia bias

    // 2. Hard Posterization / Quantization
    col = floor(col * 16.0) / 16.0;

    // 3. Chemical Grain (High contrast noise)
    // Use a fixed vector for noise seed if p is zero, otherwise use p
    vec3 noisePos = (length(p) < 0.1) ? vec3(12.9898, 78.233, 45.543) : p;
    float noise = fract(sin(dot(noisePos, vec3(12.9898, 78.233, 45.543))) * 43758.5453);

    // Additive grain for light areas, subtractive for dark
    float grainFactor = 1.0;
    if (dist < 99.0) {
        grainFactor = 1.0 / (1.0 + dist);
    }
    col += (noise - 0.5) * 0.05 * grainFactor;

    // 4. Vignette (Lens edge darkening)
    float vig = 1.0 - length(uv) * 0.6;
    col *= smoothstep(0.0, 0.5, vig);

    // 5. Final Contrast Crush (Daguerreotype look)
    col = pow(col, vec3(0.9));

    fragColor = vec4(col, 1.0);
}

float quantize(float v) {
    return floor(v * 8.0) / 8.0;
}

float sdHex(vec2 p, float r) {
    vec2 q = abs(p);
    return length(q) + (sqrt(3.0) - 1.0) * max(q.x, q.y) - r;
}

vec3 rotateY(vec3 p, float a) {
    float c = cos(a), s = sin(a);
    return vec3(p.x * c - p.z * s, p.y, p.x * s + p.z * c);
}

float getScene(vec3 p) {
    // 2-second loop: full rotation (2 * PI)
    float angle = iTime * 3.14159 * 2.0; 
    vec3 q = p;
    // Corrected: pass a 2-component vector to the 2-component result of rotation logic
    // We rotate the XZ plane manually to avoid GLSL vector assignment confusion
    float cx = q.x * cos(angle) - q.z * sin(angle);
    float cz = q.x * sin(angle) + q.z * cos(angle);
    vec2 q2 = vec2(cx, cz);

    float d = 100.0;
    float layerH = 0.4;
    float stackHeight = 6.0;
    float baseR = 2.5;

    float y = p.y;
    if (y < -0.5 || y > stackHeight + 0.5) {
        return 100.0;
    }

    float layerIdx = floor(y / layerH);
    float layerY = mod(y, layerH);

    // Tapering radius
    float r = baseR - layerIdx * 0.15;
    if (r < 0.5) r = 0.5;

    // Hexagonal prism distance
    float dist = sdHex(q2, r);

    // Combine with height to make a slab
    // Slab is from 0.1 to 0.3 in local layer coords (thickness 0.2)
    float slabTop = 0.3;
    float slabBot = 0.1;
    // Distance to slab volume
    float slabD = max(dist, max(layerY - slabTop, slabBot - layerY));

    // Add "glitch icing" on top of each layer
    // Only active near the top of the layer
    if (layerY > slabTop - 0.1) {
        float icingH = 0.0;
        // Quantized noise based on angle and time
        float angleUV = atan(q2.x, q2.y) * 4.0 + iTime;
        float n = fract(angleUV);
        n = quantize(n); // Hard steps

        // Create spikes
        if (n > 0.5) {
            icingH = 0.3;
        } else {
            icingH = -0.1;
        }

        // Vertical glitch lines
        if (fract(q2.x * 10.0) < 0.05) {
            icingH = 0.5;
        }

        // Modify the top surface distance
        float icingTop = slabTop + icingH;
        if (layerY > icingTop) {
            slabD = max(slabD, layerY - icingTop);
        }
    }

    d = slabD;
    return d;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Isometric setup
    vec3 ro = vec3(0.0, 2.0, 6.0);
    vec3 rd = normalize(vec3(uv, -1.5));

    float t = 0.0;
    float maxDist = 20.0;
    vec3 p;
    float d = 0.0;

    for (int i = 0; i < 64; i++) {
        p = ro + rd * t;
        d = getScene(p);
        if (d < 0.001) break;
        t += d;
        if (t > maxDist) break;
    }

    vec3 col = vec3(0.08, 0.08, 0.12); // Deep berry background

    if (d < 0.001) {
        // Normals
        float h = 0.01;
        vec3 normal = normalize(vec3(
            getScene(p + vec3(h, 0.0, 0.0)) - getScene(p - vec3(h, 0.0, 0.0)),
            getScene(p + vec3(0.0, h, 0.0)) - getScene(p - vec3(0.0, h, 0.0)),
            getScene(p + vec3(0.0, 0.0, h)) - getScene(p - vec3(0.0, 0.0, h))
        ));

        vec3 lightDir = normalize(vec3(cos(iTime * 2.0), 2.0, sin(iTime * 2.0)));
        float diff = max(0.0, dot(normal, lightDir));

        // Palette: Berry, White, Electric Blue
        vec3 c1 = vec3(0.8, 0.1, 0.3); // Berry
        vec3 c2 = vec3(0.9, 0.9, 0.95); // White
        vec3 c3 = vec3(0.1, 0.6, 1.0); // Electric Blue

        // Mix based on height and quantized angle for glitch effect
        // Recalculate angle for coloring
        float angleUV = atan(p.x, p.z) + iTime;
        float glitch = quantize(fract(angleUV * 4.0));

        vec3 baseCol = mix(c1, c2, diff);
        if (glitch > 0.6) {
            baseCol = mix(baseCol, c3, 0.8);
        }

        // Add specular
        vec3 halfDir = normalize(lightDir + (-rd));
        float spec = pow(max(0.0, dot(normal, halfDir)), 20.0);
        col = baseCol + vec3(spec);

        // Final quantization on color for that "digital icing" look
        col = vec3(quantize(col.x), quantize(col.y), quantize(col.z));
    }

    fragColor = vec4(col, 1.0);
}

void main() {
    // Normalize UVs to center, aspect correct
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec3 col = vec3(0.0);

    // --- Animation Parameters ---
    float t = iTime;
    float loopT = mod(t, 2.0);

    // Slow rotation of the "cake" (turntable effect)
    float rot = t * 1.5;
    // Flame breathing (flicker)
    float breath = sin(t * 5.0) * 0.15 + 0.85; 

    // --- Voxel Space Construction ---
    vec3 p = vec3(uv.x * 1.5, uv.y * 1.5, -1.0);

    // Rotate around Y (turntable spin)
    float c = cos(rot), s = sin(rot);
    p.xz = vec2(p.x * c - p.z * s, p.x * s + p.z * c);

    // --- SDF: The Voxel Flame ---
    // Base cylinder (candle wick area)
    vec3 c1 = abs(p);
    float dCyl = length(max(vec3(0.2, 0.2, -0.1), vec3(0.0))) - 0.05; // Thin wick

    // Main flame body (elongated cone-ish shape, voxelized)
    vec3 flameP = p;
    flameP.y -= 0.2; // Lift flame slightly
    flameP.z += 0.5; // Push back slightly

    float h = flameP.y + breath * 0.3; // Height varies with breath
    float w = 0.3 * (1.0 - flameP.y / h); // Taper

    // Hard SDF for flame volume
    float dFlame = max(length(flameP.xz) - w, abs(flameP.y - h/2.0) - w*0.2);

    // --- Voxelization Step (The Core Technique) ---
    // Quantize space to create the voxel grid look
    float voxelSize = 0.12;
    vec3 pVox = floor(p / voxelSize) * voxelSize + 0.5 * voxelSize;
    float dist = length(p - pVox); // Distance to nearest voxel center

    // --- Topographic Logic ---
    // We want to render the "surface" of the flame as a set of hard bands.
    // Instead of raymarching, we project the SDF value directly into band indices.
    float dObj = min(dCyl, dFlame);

    // Create "layers" based on distance from the geometric center of the voxel
    float dVoxel = max(abs(p.x - pVox.x), max(abs(p.y - pVox.y), abs(p.z - pVox.z)));

    // Map distance to a band index
    float bands = step(0.0, 0.0) + step(0.0, 0.0); // Init
    float bandCount = 12.0;
    float bandWidth = 0.15;

    // Calculate which band we are in
    float dNorm = dVoxel / (voxelSize * 0.5);
    float band = floor(dNorm * bandCount);

    // Create hard edges
    float bandEdge = mod(band, 2.0);

    // --- Coloring ---
    // Base: Deep Black
    // Voxel Faces: White (the candle/wax structure)
    // Contour Lines: Neon Orange

    vec3 bg = vec3(0.05, 0.05, 0.1); // Very dark blue-black
    vec3 wax = vec3(0.95, 0.95, 0.95);
    vec3 flame = vec3(1.0, 0.6, 0.05); // Neon Orange

    // Determine if we are "inside" the voxel shape or just near it
    // We want the voxels that make up the flame to be visible
    float isVoxel = smoothstep(voxelSize * 0.45, voxelSize * 0.5, dVoxel);

    // Combine: 
    // If we are in the geometric volume of the flame/wick (dObj < threshold)
    // and we are on a voxel surface (dVoxel approx 0.5*voxelSize)
    float volumeMask = smoothstep(0.05, 0.0, dObj); 
    float voxelMask = 1.0 - smoothstep(0.0, 0.05, abs(dVoxel - voxelSize*0.5));

    // Final Composition
    vec3 finalColor = bg;

    // 1. The Voxel Structure (White/Grey)
    finalColor += wax * volumeMask * voxelMask * 0.2;

    // 2. The Topographic Contours (The "Lines")
    // We trigger lines when the distance from the voxel center hits a quantized threshold
    float lineDist = abs(dVoxel - (floor(dVoxel * 10.0) + 0.5) * 0.1);
    float lines = smoothstep(0.0, 0.01, abs(dVoxel - (mod(dVoxel * 5.0, 1.0) * 0.2 + 0.1)));

    // Hacky but effective contour generation: 
    // Map the raw SDF value of the flame to a stepped index
    float contourVal = floor(dFlame * 8.0);
