        float cDist = 2.0;

        // Define Cake Layers (Cylinders)
        // Bottom Tier
        float layer1 = length(cakeP.xy) - 1.5;
        layer1 = max(layer1, cakeP.z - 0.5); // Top
        layer1 = max(layer1, -cakeP.z - 0.5); // Bottom

        // Middle Tier
        float layer2 = length(cakeP.xy) - 1.0;
        layer2 = max(layer2, cakeP.z - 0.5);
        layer2 = max(layer2, -cakeP.z - 0.5);
        layer2 = max(layer2, abs(cakeP.z) - 0.4); // Hollow center for tier stack

        // Top Tier
        float layer3 = length(cakeP.xy) - 0.6;
        layer3 = max(layer3, cakeP.z - 0.5);
        layer3 = max(layer3, -cakeP.z - 0.5);

        // Combine Tiers (Union)
        float cake = min(layer1, min(layer2, layer3));

        // --- 2. Slice Plane Extrusion ---
        // A moving plane cuts through the cake
        float planeZ = sin(t * 3.14159) * 0.8; // Oscillates -0.8 to 0.8
        float planeD = cakeP.z - planeZ;

        // Create the "Slice" effect: if we are within the cake volume AND near the plane
        // We render the cross-section.
        // Use a hard quantized "icing" thickness
        float sliceThickness = 0.05;
        bool isSlice = abs(planeD) < sliceThickness;
        bool isInside = cake < 0.0; // Inside cake

        vec3 col = vec3(0.0); // Default void (black)

        if (isInside && isSlice) {
            // Icing color (Crimson/White)
            // Determine "height" of the slice to vary color
            float h = abs(cakeP.z);
            float icing = step(h, 0.8); 

            // Posterization for hard edges
            float bands = step(0.3, h) * 0.5 + step(0.6, h) * 0.5;

            col = vec3(0.95) * (1.0 - bands) + vec3(0.9, 0.1, 0.1) * bands;

            // Add "Drip" effect via domain warp on the slice
            vec2 dripUV = cakeP.xy * 2.0;
            float drip = sin(dripUV.y * 20.0 + t) * 0.5;
            drip = smoothstep(0.0, 0.2, abs(drip));
            col += drip * 0.3; // Highlight
        } else if (!isInside && planeD > -0.5 && planeD < 0.5) {
            // Shadow outline of the slice plane outside the cake
             col = vec3(0.1, 0.0, 0.0) * 0.5;
        }

        // --- 3. Shadow Puppet Projection ---
        // The light source is behind the cake, casting a shadow on the stage
        // Calculate shadow from a point light at (0,0, 3.0)
        vec3 lightPos = vec3(0.0, 0.0, 3.0);
        vec3 lightDir = normalize(stageP - lightPos);
        vec3 lightToCam = normalize(ro - stageP);

        // Simple raymarch shadow check along the light ray
        // We check if the cake blocks the light at this point
        float shadowD = 0.0;
        // Reconstruct cake space for shadow check
        vec3 sCakeP = cakeP; 
        // We are at stageP, moving towards lightPos
        // Check intersection with cake geometry
        // Optimization: Just check distance to cake center roughly
        float distToCake = length(sCakeP.xy);
        float zDist = abs(sCakeP.z);

        bool blocked = (distToCake < 1.6 && zDist < 1.5); // Rough bounding box

        if (blocked) {
            // If the point on stage is "behind" the cake relative to light
            // We darken it heavily, unless it's the illuminated slice
            if (!isInside || !isSlice) {
                col *= 0.1; // Deep shadow
            }
        }

        // Apply hard posterization to final output for "glitchy" shadow puppet feel
        col = floor(col * 10.0) / 10.0;

        // Vignette for theater feel
        float vig = 1.0 - smoothstep(1.5, 3.0, length(stageP.xy) * 0.5);
        col *= vig;

        fragColor = vec4(col, 1.0);
    } else {
        // Background: Dark theater
        fragColor = vec4(vec3(0.02), 1.0);
    }
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / min(iResolution.x, iResolution.y);

    // Isometric projection setup
    // Transform UV to isometric screen space
    float u = uv.x;
    float v = uv.y;
    float iso_x = (u - v) / 1.732;
    float iso_y = (u + v) / 1.732;

    // Time looped at 2.0s
    float t = mod(iTime, 2.0);
    float pulse = sin(t * 3.14159 * 2.0); 

    // Voxel grid resolution
    float res = 6.0; 

    // Map screen to 3D world coordinates (approximate inverse isometric)
    vec3 w = vec3(iso_x * 4.0, iso_y * 4.0, 0.0);

    // Grid sampling
    vec3 g = floor(w * res);
    vec3 local = w * res;

    // Determine if this voxel exists (Cylinder body)
    float dist2d = length(vec2(local.x, local.y));
    bool isBody = dist2d < 4.5;

    // Smiley logic in grid space (Centered on body)
    // Eyes: Two blocks above center
    bool isEye = isBody && abs(local.x) > 1.2 && abs(local.x) < 2.2 && local.y > 0.5 && local.y < 1.5;

    // Mouth: Arc below center
    bool isMouth = isBody && abs(local.x) < 3.2 && local.y > -2.0 && local.y < -0.8;
    if (local.y > -1.5 && local.y < -1.0 && abs(local.x) < 0.5) isMouth = false; // Mouth gap

    // If not part of the structure, discard
    if (!isBody && !isEye && !isMouth) {
        fragColor = vec4(0.0);
        return;
    }

    // Animation: Voxel Displacement
    // Base amplitude for body, higher for face features
    float amp = isBody ? 0.2 : 0.5;

    // Direction of expansion: Radial from center
    vec3 dir = normalize(vec3(local.x, local.y, 0.0));
    if (length(dir) < 0.1) dir = vec3(0.0, 1.0, 0.0); // Fallback for center

    // Apply pulse displacement
    vec3 animPos = w + dir * (amp * pulse);

    // Re-map displaced position back to screen space to check coverage
    // We need to see if the displaced voxel covers the current pixel.
    // Since we are doing a cutaway, we render the "top" and "front" faces.
    // Simplified: Check if the pixel is within the bounds of the displaced voxel.

    // Convert 3D back to 2D isometric for the displaced voxel
    float dx = animPos.x;
    float dy = animPos.y;

    float iso_dx = (dx - dy) / 1.732;
    float iso_dy = (dx + dy) / 1.732;

    // Scale back to UV
    vec2 displacedUV = vec2(iso_dx / 4.0, iso_dy / 4.0);

    // Voxel size in UV space
    float voxelSize = 1.0 / res / 4.0 * 1.732; // Approx scaling

    // Check if current UV is inside this displaced voxel (soft box)
    vec2 diff = abs(uv - displacedUV);
    float inside = smoothstep(voxelSize * 0.9, voxelSize * 0.5, -max(diff.x, diff.y));

    if (inside < 0.01) {
        fragColor = vec4(0.0);
        return;
    }

    // Coloring: Burnt Orange Palette
    // Base: Dark Umber -> Flame: Bright Orange -> Core: White
    float intensity = smoothstep(0.0, 1.0, pulse);

    vec3 colorA = vec3(0.15, 0.05, 0.0); // Deep burnt
    vec3 colorB = vec3(0.8, 0.3, 0.05);  // Orange
    vec3 colorC = vec3(1.0, 0.9, 0.7);   // White hot

    vec3 finalColor = mix(colorA, colorB, intensity);

    // Boost face features to be brighter
    if (isEye || isMouth) {
        finalColor = mix(finalColor, colorC, intensity * 0.8);
    }

    // Hard quantization for "Voxel" look (posterization)
    // Divide color by steps and multiply back
    int steps = 8;
    finalColor = floor(finalColor * float(steps)) / float(steps);

    // Add a slight shadow/depth based on Z (simulated by Y in isometric)
    // Lower voxels (negative Y in local) are darker
    float depthDim = 1.0 - (local.y * 0.05);
    finalColor *= depthDim;

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    float t = iTime;
    float loop = mod(t, 2.0);
    float pulse = sin(loop * 6.2831); 

    // SDF: Head
    float headR = 0.42 + pulse * 0.02;
    float distHead = length(uv) - headR;

    // SDF: Eyes
    vec2 e1 = uv - vec2(-0.25, 0.1);
    vec2 e2 = uv - vec2(0.25, 0.1);
    float rE = 0.08 + pulse * 0.01;
    float dE1 = length(e1) - rE;
    float dE2 = length(e2) - rE;

    // SDF: Mouth (Arc)
    float rM = length(uv) - 0.25;
    float angle = atan(uv.x, -uv.y);
    float mouthMask = smoothstep(0.4, 1.0, angle) * smoothstep(2.8, 2.2, angle);
    float dM = abs(rM) - mouthMask * (0.05 + pulse * 0.02);

    // Combine Flame Zones (Union)
    // Add vertical "rise" to simulate flame shape
    float rise = uv.y * 0.15;
    float f1 = dE1 - rise;
    float f2 = dE2 - rise;
    float fM = dM - rise * 1.5;
    float flameDist = min(min(f1, f2), fM);

    vec3 col = vec3(0.0);

    if (distHead <= 0.0) {
        // Inside Head
        if (flameDist <= 0.0) {
            // FLAME
            float intensity = 0.9 + pulse * 0.1;
            col = vec3(intensity);

            // Hard quantization / banding effect
            float bands = step(0.5, fract(flameDist * 15.0 + t));
            col *= vec3(bands);

            // Tapering top
            float topFade = smoothstep(0.8, 1.2, uv.y);
            col *= (1.0 - topFade * 0.5);
        } else {
            // SOLID FACE (Cyanotype Blue)
            col = vec3(0.02, 0.04, 0.28); 
        }
    } else {
        // Background (Deep Cyanotype Blue)
        col = vec3(0.01, 0.03, 0.22);
    }

    // Final vignette
    col *= 1.0 - 0.2 * length(uv);

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    float t = iTime * 3.14159;

    // 2-second loop: Pulse function
    float pulse = sin(t * 3.14159); // 0 to pi in 2s

    // Grid/Voxel coordinates
    vec2 grid = floor(uv * 20.0 + 0.5);
    vec2 local = fract(uv * 20.0) - 0.5;

    // Distance to a "Smile" curve in grid space
    // y = x^2 - 1.2 (parabola), but we invert for a smile
    float smile_dist = grid.y - (grid.x * grid.x * 0.6 - 0.8);

    // Distance to "Eyes" (two blobs)
    float eye1 = length(grid - vec2(-3.0, 4.0));
    float eye2 = length(grid - vec2(3.0, 4.0));
    float eye_dist = min(eye1, eye2);

    // Combine features
    float d = min(smile_dist, eye_dist);

    // Pulse the "flame" size and opacity based on the grid position
    // Only voxels close to the curve become visible
    float activation = 1.0 - smoothstep(-0.4, 0.4, d);

    // Animate the "burn" intensity
    float intensity = activation * (0.8 + 0.2 * sin(t * 6.283 + grid.x * 0.2));

    // Add a "voxel" border effect for hard edges
    float voxel_mask = 1.0 - step(0.95, length(local) * 2.0); // Keep center square
    voxel_mask *= 1.0 - step(0.0, length(local) - 0.45); // Cut corners if needed for octagon

    // Combine: Only show if close to shape AND in center of voxel cell
    float final_val = activation * intensity * voxel_mask;

    // X-Ray Film Look: Negative Cyan/Black
    // High contrast posterization for "Hard Edge" feel
    float posterized = step(0.1, final_val) * 0.2 + step(0.5, final_val) * 0.4 + step(0.9, final_val) * 0.4;

    // Add a "burn" flicker based on time and position
    float flicker = sin(t * 10.0 + grid.x * grid.y * 0.5) * 0.05;

    // Color: Base black, Cyan glow for X-ray negative look
    vec3 color = vec3(0.0, 0.0, 0.0); // Background

    // If active, add cyan/blue x-ray emission
    color += vec3(0.8, 1.0, 1.0) * posterized;

    // Add a subtle red "exposure" halo for the x-ray film feel
    color += vec3(0.9, 0.6, 0.6) * (1.0 - posterized) * 0.1;

    // Final hard quantization (posterization) on the output
    color = step(0.2, color) * 0.3 + step(0.5, color) * 0.3 + step(0.9, color) * 0.4;

    fragColor = vec4(color + flicker, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = mod(iTime, 2.0); // 2s loop

    // Coordinate setup for polar/kaleidoscopic feel
    vec2 p = uv * 1.8;
    float dist = length(p);
    float ang = atan(p.y, p.x);

    // 1. Voxel Lattice (The "Ringing Voxel" structure)
    // Create a grid of squares that scales with time (Pulse)
    float pulse = 1.0 + 0.3 * sin(t * 3.14159 * 2.0); // Ringing expansion
    vec2 grid = p * pulse * 4.0;
    float gx = abs(fract(grid.x) - 0.5);
    float gy = abs(fract(grid.y) - 0.5);
    float vox = (1.0 - step(0.3, gx) - step(0.3, gy)) * -1.0; // Inverted logic for holes

    // 2. The Smile Cutout
    // Define a sector in polar coords where the voxels are missing (The Smile)
    float smileMask = smoothstep(1.0, -1.0, cos(ang)) * smoothstep(0.8, -0.8, sin(ang));
    // Restrict smile to a ring
    float ringMask = smoothstep(0.6, 0.5, dist) - smoothstep(0.5, 0.4, dist);

    // Combine: Voxels exist unless in the smile ring
    float coreShape = vox * (1.0 - ringMask) + ringMask; 
    // Hard quantization for "Field Guide" look
    float finalCore = step(0.0, coreShape);

    // 3. Flame Spikes (The "Impact/Flame")
    // Generate spikes between voxel rows using hard angles
    float spikes = 0.0;
    float r = dist * pulse * 6.0;
    int ring = int(r);
    float phase = mod(float(ring), 2.0); // Alternating rows

    if (phase > 0.99) {
        // Jagged flame geometry
        float f = abs(mod(ang * 4.0, 3.14159) - 1.5708) * 0.2;
        spikes = smoothstep(0.15, 0.0, f) * smoothstep(0.8, 0.0, dist - 0.4);
        spikes += smoothstep(0.15, 0.0, abs(mod(ang * 8.0, 3.14159) - 1.5708)) * 0.5;
    }

    // 4. Palette & Composition
    // Safety Yellow, Soot Black, Paper White
    vec3 paper = vec3(0.95, 0.94, 0.90);
    vec3 ink = vec3(0.05, 0.05, 0.08);
    vec3 warning = vec3(1.0, 0.9, 0.0);
    vec3 flame = vec3(1.0, 0.2, 0.0);

    vec3 col = paper;

    // Draw the Voxels (Black on Yellow)
    if (finalCore > 0.5) {
        col = warning; // Base voxel is warning yellow
        // Darken edges for 3D feel
        col *= mix(1.0, 0.6, vox + 0.5);
    }

    // Draw the Spikes (Flame)
    if (spikes > 0.0) {
        col = mix(col, flame, spikes);
        // Add "Impact" glitch lines
        float glitch = step(0.5, sin(ang * 20.0 + t * 10.0));
        col = mix(col, ink, glitch * 0.2);
    }

    // Overlay a "Field Guide" border
    float border = smoothstep(0.6, 0.55, dist) - smoothstep(0.55, 0.5, dist);
    if (border > 0.0) col = ink;

    // Final Posterization
    float poster = floor(dot(col, vec3(0.299, 0.587, 0.114)) * 8.0) / 8.0;
    col = mix(paper, warning, poster) * 0.8 + ink * 0.2;

    // Re-apply colors based on mask logic for crispness
    if (finalCore > 0.5) col = vec3(1.0, 0.85, 0.0) * 0.8 + ink * 0.2;
    if (spikes > 0.4) col = vec3(0.1, 0.1, 0.1); // Hard black spikes

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = iTime;
    float loopT = mod(t, 2.0) / 2.0;
    float p = sin(6.28318 * loopT);

    // Isometric projection
    float x = (uv.x - uv.y * 0.57735) * 1.5;
    float z = (uv.x * 0.57735 + uv.y) * 0.866;
    float y = uv.y * 0.2 - 0.5;

    // Cylinder parameters
    float radius = 0.4 + p * 0.1;
    float colDist = length(vec2(x, z)) - radius;
    float topDist = z - (1.5 + p * 0.2);
    float distCyl = max(colDist, -z);
    float distCylCapped = max(distCyl, topDist);

    // Slice plane logic
    float faceY = y + 0.2;
    float faceX = x;
    float sliceThick = 0.02;
    bool inSlice = abs(faceY) < sliceThick;

    // Face primitives (in X-Y plane)
    float faceR = radius * 0.8;
    float dFaceCircle = length(vec2(faceX, faceY)) - faceR;

    vec2 eyePos = vec2(-0.15, 0.2) * radius;
    float dEyeL = length(vec2(faceX, faceY) - eyePos) - faceR * 0.12;
    float dEyeR = length(vec2(faceX, faceY) + eyePos) - faceR * 0.12;
    float dEyes = min(dEyeL, dEyeR);

    vec2 smilePos = vec2(0.0, -0.1) * radius;
    float smileR = radius * 0.35;
    float dSmileRaw = length(vec2(faceX, faceY) - smilePos) - smileR * 0.05;
    // Create arc by intersecting circle with a half-plane approximation
    float dSmile = max(dSmileRaw, -vec2(faceX, faceY).y + 0.1 * radius);

    float finalDist = distCylCapped;
    vec3 finalColor = vec3(0.0);

    // Colors
    vec3 cBlack = vec3(0.02, 0.0, 0.0);
    vec3 cOrange = vec3(1.0, 0.35, 0.0);
    vec3 cWhite = vec3(1.0, 0.95, 0.9);
    vec3 cEye = vec3(0.0, 0.0, 0.1);

    if (inSlice) {
        // Render the cross-section face
        float dObj = dFaceCircle;

        // Composite: Circle (base) - Eyes (holes) - Mouth (cut)
        // We want the face to be white, eyes black, mouth black.
        // Distance to the union of (Face Circle) and (Eyes) and (Mouth) is complex.
        // Instead, we calculate which region we are in.

        bool onFace = dObj < 0.02 && dObj > -0.02;
        bool onEye = dEyes < 0.02 && dEyes > -0.02;
        bool onMouth = dSmile < 0.02 && dSmile > -0.02;

        if (onFace && !onEye && !onMouth) {
            // Face background
            float glow = 0.5 + 0.5 * sin(12.56 * loopT);
            finalColor = mix(cOrange, cWhite, glow);
        } else if (onEye) {
            finalColor = cEye;
        } else if (onMouth) {
            finalColor = cBlack;
        } else {
            // Transparent/Background
            finalColor = cBlack;
        }
    } else {
        // Render Cylinder Surface
        if (finalDist < 0.02 && finalDist > -0.02) {
            float zNorm = z / 2.0;
            vec3 colBase = mix(cBlack, cOrange, smoothstep(-0.5, 0.5, zNorm));
            colBase = mix(colBase, cWhite, smoothstep(0.8, 1.2, zNorm));
            finalColor = colBase;
        } else {
            finalColor = cBlack;
        }
    }

    // Isometric Grid Overlay (Subtle)
    float grid = abs(mod(x + z + t, 0.2)) < 0.005 ? 0.1 : 0.0;
    finalColor += vec3(grid);

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    // 2-second loop compression
    float t = mod(iTime, 2.0);

    // Aspect correction and centering
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Polar coordinate system for kaleidoscopic folding
    float r = length(uv);
    float ang = atan(uv.y, uv.x);

    // Hexagonal symmetry (6 slices)
    float sector = mod(ang + 3.14159, 2.0 * 3.14159 / 6.0);
    float angSym = sector - 3.14159 / 6.0;

    // Reconstruct polar to cartesian within the sector
    vec2 uvK = vec2(r * cos(angSym), r * sin(angSym));

    // --- SDF Construction for "Flame-Smile" ---

    // Pulse parameters
    float pulse = sin(t * 3.14159);
    float scale = 1.0 + 0.2 * pulse;

    // Define feature positions
    vec2 eyeL = vec2(-0.15, 0.25) * scale;
    vec2 eyeR = vec2(0.15, 0.25) * scale;
    vec2 mouthC = vec2(0.0, 0.5) * scale;
    float mouthR = 0.4 * scale;
    float mouthW = 0.06 * scale;

    // Calculate distances
    float dLeft = length(uvK - eyeL) - 0.06 * scale;
    float dRight = length(uvK - eyeR) - 0.06 * scale;
    float dMouth = abs(length(uvK - mouthC) - mouthR) - mouthW;

    // Flame body SDF (approximate cone/tear drop)
    float dBody = r - (0.6 * scale);

    // Hard sector masking
    // Only draw within the 30-degree wedge
    bool inSector = (abs(uvK.x) < 0.35 * r && uvK.y > -0.2 * r);

    float dFinal = 1.0; // Default background

    if (inSector) {
        // Combine features: Smile parts are "holes" or distinct objects
        // We want the smile to be white, flame orange, background black

        // Determine closest feature
        float dFace = min(dLeft, dRight);
        dFace = min(dFace, dMouth);

        // Logic:
        // If very close to face features -> White
        // If inside flame body -> Orange/Cyan
        // Else -> Black

        if (dFace < 0.0) {
            dFinal = 0.0; // Face features
        } else if (r < 0.65 * scale && r > 0.1) {
            dFinal = r - (0.2 * scale); // Inside flame body
        } else {
            dFinal = 1.0; // Background
        }
    }

    // --- Coloring & Posterization ---

    vec3 colBg = vec3(0.02, 0.01, 0.02);
    vec3 colCore = vec3(1.0, 0.9, 0.4);
    vec3 colBody = vec3(1.0, 0.3, 0.0);
    vec3 colEdge = vec3(0.0, 0.8, 1.0);
    vec3 colFace = vec3(1.0, 1.0, 1.0);

    vec3 color = colBg;

    // Hard quantization steps for "Timelapse" feel
    // Step 1: Face
    if (dFinal < 0.05) {
        color = colFace;
    }
    // Step 2: Core
    else if (dFinal < 0.15) {
        color = colCore;
    }
    // Step 3: Body
    else if (dFinal < 0.25) {
        color = colBody;
    }
    // Step 4: Edge
    else if (dFinal < 0.30) {
        color = colEdge;
    }

    // Add a hard strobe effect based on time
    if (mod(iTime, 0.2) < 0.05) {
        color *= 0.5; // Strobe dim
    }

    // Hard posterization on luminance
    float lum = dot(color, vec3(0.299, 0.587, 0.114));
    lum = floor(lum * 3.0) / 3.0;
    color *= (lum + 0.1); // Preserve some contrast

    fragColor = vec4(color, 1.0);
}

void main() {
    // Normalize coordinates
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Isometric projection transform
    vec2 p = uv;
    p.x *= 1.5;
    p = p * vec2(1.0, -1.0); // Flip Y for isometric view
    p.y -= 0.5;

    // Camera setup for cutaway view
    vec3 ro = vec3(0.0, 0.0, -4.0); // Ray origin
    vec3 rd = normalize(vec3(p, 1.2)); // Ray direction

    // Time variables
    float t = iTime;
    float loop = fract(t * 0.5); // 2.0s loop
    float pulse = sin(loop * 6.283) * 0.2 + 0.8;
    float rot = loop * 6.283;

    // Object definition: Inverted Flame Ring (Torus SDF)
    vec3 p3 = vec3(0.0);

    // Rotate the world (ring) around Y
    mat3 mRotY = mat3(
        cos(rot), 0.0, -sin(rot),
        0.0, 1.0, 0.0,
        sin(rot), 0.0, cos(rot)
    );

    // Animate the ring shape (breathing/flame effect)
    float rInner = 1.2 + sin(t * 3.0) * 0.1;
    float rOuter = 0.4 - sin(t * 3.0) * 0.05;

    vec3 pLocal = p3;
    pLocal = mRotY * pLocal; // Apply rotation

    // Raymarching
    float d = 100.0;
    float tAcc = 0.0;
    for(int i = 0; i < 60; i++) {
        vec3 pos = ro + rd * tAcc;

        // Apply rotation to position for SDF calc
        vec3 q = mRotY * pos;

        // Torus SDF
        vec2 ba = vec2(length(q.xz) - rInner, q.y);
        float dist = length(ba) - rOuter;
        d = min(d, dist);

        if(d < 0.001) break;
        tAcc += d;
        if(tAcc > 20.0) break;
    }

    // Cutaway logic: Slice the object
    // If we are "above" a certain plane in local space, we see the cut
    vec3 posSlice = ro + rd * tAcc;
    vec3 qSlice = mRotY * posSlice;

    // Define a hard cut plane
    float planeDist = abs(qSlice.y - (pulse * 0.5));
    bool isCut = (planeDist < 0.2);

    // Dithering pattern
    float noise = fract(sin(dot(gl_FragCoord.xy, vec2(12.9898, 78.233))) * 43758.5453);
    float ditherVal = 0.5; // Threshold

    // Coloring: Inverted Flame
    vec3 col = vec3(0.0); // Default black

    if(d < 0.001) {
        // On surface
        vec3 qSurf = mRotY * (ro + rd * tAcc);
        float distFromCenter = length(qSurf);

        // Quantized bands based on Y position in local space
        float bandY = qSurf.y + sin(t * 10.0);
        int bandIdx = int(floor(bandY * 5.0));
        float bandVal = fract(bandY * 5.0);

        // Palette: Inverted (Dark center, Bright rim)
        // 0 = Black, 0.3 = Cyan, 0.6 = Orange, 1.0 = White
        vec3 c1 = vec3(0.0, 0.0, 0.0);
        vec3 c2 = vec3(0.0, 0.9, 1.0);
        vec3 c3 = vec3(1.0, 0.6, 0.1);

        vec3 finalCol = mix(c1, c2, smoothstep(0.0, 0.4, bandVal));
        finalCol = mix(finalCol, c3, smoothstep(0.4, 0.8, bandVal));
        finalCol = mix(finalCol, vec3(1.0), smoothstep(0.8, 1.0, bandVal));

        // Hard Dithering
        if(noise < bandVal * 0.5) {
            col = finalCol * 0.2; // Deep shadow
        } else {
            col = finalCol;
        }

        // Apply "Inverted" logic: make the inside darker
        if(length(qSurf.xz) < rInner * 0.5) {
            col *= 0.1;
        }
    }

    // Render the Cutaway Slice (The internal lattice)
    if(isCut) {
        float sliceY = qSlice.y;
        float sliceDist = abs(sliceY - pulse * 0.5);

        if(sliceDist < 0.15) {
            // Lattice pattern
            vec2 grid = vec2(floor(qSlice.x * 8.0), floor(qSlice.z * 8.0));
            float gridVal = fract(grid.x) * fract(grid.y);
            float pattern = sin(gridVal * 10.0 + t * 2.0);

            // Inverted flame palette for slice
            vec3 sliceCol = mix(vec3(0.0, 0.2, 0.4), vec3(1.0, 0.5, 0.0), pattern);

            // Dither the slice
            if(noise < pattern * 0.4) {
                sliceCol *= 0.05;
            }

            // Distance fog for the slice
            col = mix(col, sliceCol, 1.0 - smoothstep(0.0, 0.05, sliceDist));
        }
    }

    // Background
    if(d > 0.001) {
        col = vec3(0.02, 0.02, 0.03); // Deep dark background
    }

    fragColor = vec4(col, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    float t = iTime;
    float period = 2.0;
    float timePhase = t / period * 6.283185;

    float stepSize = 0.4;
    float lineWidth = 0.025;
    float glow = 0.06;

    float split = cos(timePhase) * 1.2;

    // Inlined calculation for main lattice to avoid function syntax issues in strict GLSL ES contexts
    vec3 qMain = vec3(uv, 0.0);
    qMain.x += split * sign(qMain.x);
    qMain.y += sin(qMain.x * 5.0 - timePhase) * 0.3;
    qMain.z += cos(qMain.y * 5.0 + timePhase) * 0.3;

    vec3 cellMain = floor(qMain / stepSize);
    vec3 localMain = mod(qMain, stepSize) - 0.5 * stepSize;
    vec3 dBoxMain = abs(localMain) - lineWidth;
    float dMain = length(max(dBoxMain, 0.0));

    float n = 1.0 - smoothstep(lineWidth - glow, lineWidth + glow, dMain);
    vec3 neonColor = vec3(0.0, 0.9, 1.0);

    // Shadow calculation
    vec2 shadowUV = uv + vec2(0.15, 0.15);
    vec3 qShadow = vec3(shadowUV, 0.0);
    qShadow.x += split * sign(qShadow.x);
    qShadow.y += sin(qShadow.x * 5.0 - timePhase) * 0.3;
    qShadow.z += cos(qShadow.y * 5.0 + timePhase) * 0.3;

    vec3 cellShadow = floor(qShadow / stepSize);
    vec3 localShadow = mod(qShadow, stepSize) - 0.5 * stepSize;
    vec3 dBoxShadow = abs(localShadow) - lineWidth;
    float dShadow = length(max(dBoxShadow, 0.0));

    float s = 1.0 - smoothstep(lineWidth - glow, lineWidth + glow, dShadow);
    vec3 shadowColor = vec3(1.0, 0.2, 0.4);

    vec3 col = mix(vec3(0.0), neonColor, n);
    col = mix(vec3(0.0), shadowColor, s * 0.5);

    vec2 floorUV = uv * 10.0;
    float floorGrid = 1.0 - smoothstep(0.0, 0.02, min(abs(fract(floorUV.x) - 0.5), abs(fract(floorUV.y) - 0.5)));
    col += vec3(0.8, 0.6, 0.2) * floorGrid * 0.15;

    col = floor(col * 16.0) / 16.0;

    float vignette = 1.0 - length(uv) * 0.6;
    col *= clamp(vignette, 0.0, 1.0);

    fragColor = vec4(col, 1.0);
}

float sdHexPrism(vec3 p, float s) {
    vec3 q = abs(p);
    vec2 d = q.xy - vec2(s, s * sqrt(3.0) * 0.5);
    vec2 k = max(d, vec2(0.0));
    float hex = length(d) - length(k);
    return max(q.z * s * 0.5, hex);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    float t = iTime;
    // 2-second loop: 0 -> 1 -> 0
    float loopT = sin(t * 3.14159) * 0.5 + 0.5; 

    // Camera setup
    vec3 ro = vec3(0.0, 0.0, -4.0 + loopT * 0.5);
    vec3 rd = normalize(vec3(uv * 1.5, 1.0));

    float d = 100.0;
    vec3 col = vec3(0.0);
    vec3 pos = vec3(0.0);
    vec3 n = vec3(0.0);

    // Raymarching loop
    for(int i=0; i<80; i++) {
        pos = ro + rd * d;

        // Base shape: Hex Prism
        float h = sdHexPrism(pos, 0.8);

        // Fracture Effect: Add noise-based displacement to the surface
        float noiseVal = sin(pos.x * 5.0 + t) * sin(pos.y * 5.0 - t) * sin(pos.z * 5.0);
        float distortion = noiseVal * (loopT * 0.6);

        // Wireframe Effect: Use fractional parts of distance
        float wire = sin(h * 20.0 - loopT * 10.0);

        // Hit check
        if (h < 0.02) {
            // Normal calculation
            float eps = 0.001;
            float h1 = sdHexPrism(pos + vec3(eps, 0.0, 0.0), 0.8);
            float h2 = sdHexPrism(pos + vec3(0.0, eps, 0.0), 0.8);
            float h3 = sdHexPrism(pos + vec3(0.0, 0.0, eps), 0.8);
            n = normalize(vec3(h1 - h, h2 - h, h3 - h));

            vec3 lightDir = normalize(vec3(0.5, 0.8, -0.3));
            float dif = max(dot(n, lightDir), 0.0);
            float spec = pow(max(dot(reflect(-lightDir, n), -rd), 0.0), 32.0);

            float wireStrength = 1.0 - abs(wire);

            // Base Metal Color
            vec3 metal = mix(vec3(0.3, 0.25, 0.2), vec3(0.8, 0.7, 0.6), dif);

            // Wireframe Color
            vec3 wireColor = mix(vec3(0.0, 0.4, 1.0), vec3(1.0, 0.4, 0.2), loopT);

            // Emboss/Groove: Darken areas that are "inside" the fracture
            float groove = smoothstep(0.0, 0.5, distortion);

            col = metal * (1.0 - wireStrength) + wireColor * wireStrength + vec3(spec);
            col *= (1.0 - groove * 0.4); 

            break;
        }

        d = h;
        if(d < 0.02) break;
        d -= loopT * 0.1; 
    }

    // Post-process: Quantization/Posterization for "Printed Metal" look
    float quant = 0.04;
    col = floor(col / quant) * quant;

    // Vignette
    float vig = 1.0 - length(uv) * 0.3;
    col *= vig;

    // Gamma correction
    col = pow(col, vec3(0.45));

    fragColor = vec4(col, 1.0);
}

float mod2(float x) { return x - floor(x * 0.5) * 2.0; }

// Hard, quantized SDF for alpine peaks
float sdMountains(vec2 p, float time) {
    // Base jagged terrain
    float y = sin(p.x * 1.5) * 0.6 + sin(p.x * 3.0 + 1.2) * 0.3;
    y += sin(p.x * 6.0 - time) * 0.1;

    // Add "field guide" layering by quantizing height
    return length(vec2(p.x, p.y - y));
}

// Jet SDF (Simplified fuselage + wing)
float sdJet(vec2 p) {
    vec2 b = abs(p);
    float fuselage = length(vec2(b.x - 0.15, b.y - 0.05)) - 0.08;
    float wing = max(b.y - 0.02, abs(b.x) - 0.15) - 0.02;
    return length(max(vec2(fuselage, wing), vec2(-0.05))) - 0.05;
}

// Glitch vector field for the wake
vec2 glitchField(vec2 p, float t) {
    float g = step(0.9, fract(t * 50.0 + p.x * 0.5));
    vec2 d = vec2(0.02, 0.0);
    if (g > 0.5) d = vec2(-0.02, 0.0);

    // Quantization for the "glitch map" look
    p.x = floor(p.x * 20.0) / 20.0 + d.x;
    return p;
}

void main() {
    // Normalize coordinates, aspect correct
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Loop time 0->2 (Fixed: use fract for GLSL ES compatibility)
    float t = fract(iTime / 2.0) * 2.0;

    // Jet motion path: Diagonal ascent
    vec2 jetPos = vec2(-1.2 + t * 2.0, -0.6 + t * 1.0);

    // Camera pan to follow jet slightly
    uv.x -= jetPos.x * 0.15;
    uv.y -= jetPos.y * 0.15;

    // --- RENDER SCENE ---

    // 1. Mountains (Field Guide Style)
    float distM = sdMountains(uv, t * 0.5);
    float height = uv.y + 0.2; // Base level

    // Topographic bands
    float bandIndex = floor(height * 2.0 + sin(uv.x * 3.0) * 0.2);
    vec3 colMountain = vec3(0.92, 0.90, 0.88); // Cream paper
    vec3 colLine = vec3(0.2, 0.4, 0.4); // Teal ink

    // Draw bands
    float bandDist = abs(height - bandIndex / 2.0) - 0.01;
    vec3 finalCol = colMountain;

    if (bandDist < 0.02) {
        // Draw the line
        float alpha = 1.0 - smoothstep(0.0, 0.02, bandDist);
        finalCol = mix(colMountain, colLine, alpha);

        // Add "glitch" artifacts to lines if behind jet
        if (uv.y < height - 0.1) {
            vec2 gUV = glitchField(uv, t);
            float gVal = sin(gUV.x * 20.0 + t * 20.0);
            finalCol += vec3(gVal * 0.1, -gVal * 0.1, 0.0);
        }
    }

    // 2. The Jet
    vec2 localUV = uv - jetPos;
    localUV.x *= 1.3; // Aspect stretch

    float distJet = sdJet(localUV);

    if (distJet < 0.02) {
        // Whiskey Amber Jet
        float edge = 1.0 - smoothstep(0.0, 0.02, distJet);
        vec3 colJet = vec3(1.0, 0.65, 0.15); // Amber
        vec3 colDetail = vec3(0.1, 0.1, 0.2); // Cockpit/Shadow

        // Hard geometric detail on fuselage
        if (abs(localUV.y) < 0.04 && localUV.x < -0.05) {
             colDetail = vec3(0.0, 0.0, 0.8); // Cockpit tint
        }

        finalCol = mix(finalCol, colJet, edge);
        finalCol = mix(finalCol, colDetail, step(0.01, abs(localUV.y)) * edge * 0.3);
    }

    // 3. The Glitch Wake
    if (localUV.x < -0.2 && localUV.x > -2.0) {
        float wakeY = abs(localUV.y) - 0.05;
        if (wakeY < 0.15) {
            float wakeX = localUV.x;
            // Fragment the wake
            float g = fract(wakeX * 40.0 + t * 100.0);
            vec2 disp = vec2(g - 0.5, g - 0.5) * 0.05;
            vec2 samplePos = uv + disp;

            // Color shift the wake based on glitch
            vec3 wakeCol = vec3(0.8, 0.2, 0.0) * (1.0 - step(0.05, wakeY));
            if (fract(wakeX * 10.0) < 0.5) wakeCol.r = 0.0; // Glitch cut
            if (fract(wakeX * 10.0) > 0.8) wakeCol.g = 0.0;

            // Composite wake over mountains
            finalCol = mix(finalCol, wakeCol, 0.4 * (1.0 - step(0.05, wakeY)));
        }
    }

    // 4. Sky (Paper texture)
    finalCol += vec3(0.05, 0.05, 0.1) * sin(uv.x * 100.0) * 0.02; // Grain

    // Final Posterization for "Field Guide" print look
    finalCol = floor(finalCol * 8.0) / 8.0;

    fragColor = vec4(finalCol, 1.0);
}

float hash21(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float smin(float a, float b, float k) {
    float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);
    return mix(b, a, h) - k * h * (1.0 - h);
}

float sdBox(vec3 p, vec3 b) {
    vec3 q = abs(p) - b;
    return length(max(q, 0.0)) + min(max(q.x, max(q.y, q.z)), 0.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec3 ro = vec3(0.0, 0.2, 0.0);
    vec3 rd = normalize(vec3(uv, -2.0));

    float t = mod(iTime, 2.0);
    float speed = 8.0;
    float zOff = -t * speed;

    vec2 noiseUV = uv * 0.8 + vec2(t * 0.2, t * 0.1);
    float n = hash21(floor(noiseUV * 2.0)) + hash21(floor(noiseUV * 5.0));
    float viscous = sin(n * 3.0 + t * 3.0) * 0.15 + cos(n * 5.0 - t * 2.0) * 0.05;
    rd.x += viscous * 0.05;
    rd.y += viscous * 0.05;

    vec3 p;
    float tRay = 0.0;
    float dSdf = 0.0;
    float cloudVal = 0.0;
    float terrainH = 0.0;
    vec3 col = vec3(0.0);

    for(int i = 0; i < 40; i++) {
        p = ro + rd * tRay;

        vec3 localP = p - vec3(0.0, 0.0, zOff);
        vec3 boxSize = vec3(1.0, 0.1, 10.0);
        float lattice = sdBox(mod(localP, vec3(2.0, 0.5, 20.0)) - vec3(1.0, 0.25, 10.0), boxSize);

        float cloudDist = 10.0 - p.z - zOff;
        if(cloudDist > 0.0 && cloudDist < 30.0) {
            vec3 cP = p;
            cP.x *= 1.5; cP.z *= 0.8;
            float cNoise = sin(cP.x * 5.0 + t) * sin(cP.z * 2.0) * sin(cP.y * 10.0);
            float cNoise2 = sin(cP.x * 8.0 - t) * sin(cP.z * 4.0) * sin(cP.y * 5.0);
            float cloudSdf = -0.5 + (cNoise + cNoise2) * 0.4;
            cloudVal = max(cloudVal, cloudSdf - cloudDist * 0.5);
        }

        float terrainDist = p.z - zOff - 40.0;
        if(terrainDist < 50.0 && terrainDist > 0.0) {
            vec2 tp = vec2(p.x * 0.5, p.y * 0.5) + t * 0.5;
            terrainH = sin(tp.x * 3.0) * 2.0 + sin(tp.y * 4.0) * 1.0;
            terrainH += sin(tp.x * 12.0 + tp.y * 7.0) * 0.5;
        }

        dSdf = min(lattice, max(cloudVal, terrainH - p.y));

        if(dSdf < 0.02 || tRay > 100.0) break;
        tRay += dSdf;
    }

    float skyMix = smoothstep(0.0, 20.0, p.y);
    col = mix(vec3(0.05, 0.02, 0.0), vec3(0.3, 0.15, 0.0), skyMix);

    if(tRay < 100.0 && abs(dSdf) < 0.05) {
        vec3 localP = p - vec3(0.0, 0.0, zOff);
        float dL = sdBox(mod(localP, vec3(2.0, 0.5, 20.0)) - vec3(1.0, 0.25, 10.0), vec3(1.0, 0.1, 10.0));
        float dC = cloudVal;
        float dT = terrainH - p.y;

        if(dL < 0.05) {
            vec3 latticeCol = vec3(0.0, 0.8, 1.0) * 1.5;
            float rim = pow(1.0 - dot(rd, vec3(0.0, 1.0, 0.0)), 3.0);
            col = latticeCol * (0.2 + 0.8 * rim);
        } else if (dC > 0.0) {
            float alpha = smoothstep(-0.5, 0.5, dC);
            vec3 cloudCol = vec3(1.0, 0.6, 0.1) * alpha * 0.8;
            col += cloudCol;
        } else if (dT < 0.02) {
            vec3 terrainCol = vec3(0.1, 0.4, 0.2) * 0.5;
            col = mix(col, terrainCol, 0.8);
        }
    }

    float fog = 1.0 - exp(-0.04 * tRay);
    col = mix(col, vec3(0.02, 0.01, 0.02), fog);

    float vignette = 1.0 - dot(uv, uv) * 0.5;
    col *= vignette;

    fragColor = vec4(col, 1.0);
}

vec2 hash2(vec2 p) {
    return fract(sin(p) * 1e4);
}

float sdFiord(vec2 p) {
    float f = 0.0;
    float s = 1.0;
    for(int i=0; i<4; i++) {
        p *= 1.9;
        f += abs(sin(p.y * 0.8 + p.x * 0.5)) * s * 0.4;
        s *= 0.5;
    }
    return f - 0.4 + sin(p.x * 0.1 + iTime) * 0.1;
}

float sdJet(vec2 p) {
    vec2 b = p;
    float wing = abs(b.x) - abs(b.y * 2.0 + 0.1);
    float fuselage = abs(b.x) - 0.02;
    return max(wing, fuselage) - 0.02;
}

float sdWake(vec2 p, vec2 pos, float t) {
    vec2 d = p - pos - vec2(t * 2.0, 0.0);
    float w = abs(d.x) - d.y * 0.5;
    return w - 0.15;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    float t = mod(iTime, 2.0);
    float phase = sin(t * 3.14); 
    vec2 jetPos = vec2(phase * 1.8, sin(phase) * 0.5);
    vec2 uvMap = uv - jetPos;

    float dLand = sdFiord(uvMap * 2.0 + vec2(sin(iTime*0.5), cos(iTime*0.5)));
    float dJet = sdJet(uvMap);
    float dWake = sdWake(uvMap, jetPos, t);

    float d = dLand;
    d = min(d, dWake);
    d = min(d, dJet);

    vec3 color = vec3(0.0, 0.0, 0.05);

    if (d < 0.0) {
        color = vec3(1.0, 0.6, 0.1) * 1.5;
    } else if (dWake < 0.0 && dLand > 0.0) {
        color = vec3(1.0, 0.8, 0.2);
    } else if (dLand < 0.0) {
        float stepVal = floor(-d * 50.0);
        float intensity = 0.4 + step(stepVal, 20.0) * 0.3 + step(stepVal, 40.0) * 0.3;
        color = vec3(1.0, 0.5, 0.0) * intensity;
    }

    float grain = hash2(uv * 200.0 + iTime).x;
    color += grain * 0.05;

    color = max(color, vec3(0.0));
    fragColor = vec4(floor(color * 255.0) / 255.0, 1.0);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(mix(hash(i + vec2(0, 0)), hash(i + vec2(1, 0)), u.x),
               mix(hash(i + vec2(0, 1)), hash(i + vec2(1, 1)), u.x), u.y);
}

float fbm(vec2 x) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 5; i++) {
        v += a * noise(x);
        x *= 2.02;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Looping time factor: 0 to 1 over 2 seconds
    float t = mod(iTime, 2.0) * 0.5;

    // Domain warp for "Turbulent Amber Vortex"
    vec2 q = vec2(0.0);
    q.x = fbm(uv + t * 2.0);
    q.y = fbm(uv + vec2(t * 2.0, -t * 2.0));
    vec2 p = uv + q * 0.6;

    // Sumi-e Fiord Background (Layered Brush Strokes)
    float ink = 0.0;

    // Layer 1: Deep dark water/walls
    float n1 = fbm(p * 3.0 - t * 2.0);
    ink += step(0.4, n1) * 0.3;

    // Layer 2: Mid-tone turbulence
    float n2 = fbm(p * 6.0 + vec2(1.0, 0.0));
    ink += step(0.45, n2) * 0.4;

    // Layer 3: Fine grain
    float n3 = fbm(p * 12.0 - vec2(0.0, 1.0));
    ink += step(0.5, n3) * 0.3;

    // "Jet" Trajectory - Sine wave across screen
    float jetX = t * 4.0 - 1.0; // Moves -1 to 1
    float jetY = sin(t * 4.0 + 1.5) * 0.3;

    // Jet Shape: A sharp, tapered tear
    vec2 jetPos = vec2(jetX, jetY);
    vec2 dist = abs(p - jetPos);
    float distVal = dist.x * 0.8 + dist.y * 1.5;

    // Jet Wake: Crystallized Amber trail
    float wake = smoothstep(0.05, 0.0, distVal);

    // Sumi-e Edges on the Jet (Hard contrast)
    float jetMask = step(0.02, distVal); // Outer sharp edge

    // Color Composition
    // Base: Dark Ink (Near black)
    vec3 inkColor = vec3(0.02, 0.01, 0.02) * (ink + 0.5);

    // Mid: Amber/Whiskey tones
    vec3 amber = vec3(1.2, 0.65, 0.15) * (1.0 - ink);

    // Highlight: White/Smoke for the jet's leading edge
