    float dist = abs(p.y) + abs(p.x) * 0.3;
    float bands = floor(dist * 8.0) - floor(dist * 8.0 - 0.1); // Hard edges
    float terrain = sin(p.x * 4.0 + dist * 2.0) * 0.1 + 0.2;
