    float distD = abs(d.y) + abs(d.x) * 0.3;
    float bandsD = floor(distD * 8.0) - floor(distD * 8.0 - 0.1);
    float terrainD = sin(d.x * 4.0 + distD * 2.0) * 0.1 + 0.2;
