        }
        if (loopT > 0.8) {
            displacement = vec2(0.02, -0.1) * 1.5; 
        }
        bowPos += displacement;
    }

    float dBowSnap = length(abs(bowPos) - rBow) - 0.04;
    float dKey = min(dShaft, dBowSnap);

    // Rust Color
    vec3 rustCol = vec3(0.4, 0.15, 0.05);
    vec3 ironCol = vec3(0.15, 0.1, 0.08);
    float rustNoise = sin(keyP.x * 20.0) * sin(keyP.y * 30.0);
    rustNoise = smoothstep(-1.0, 1.0, rustNoise);
    vec3 keyCol = mix(ironCol, rustCol, 0.6 + 0.4 * rustNoise);

    float spec = max(0.0, -keyP.y * 0.5 + 0.1);
    keyCol += spec * 0.3;

    // Convert bool to float for math operations
    float isKey = float(dKey < 0.0);

    vec3 col = bgCol; 
    if (dKey < 0.0) {
        col = keyCol;
    }

    // --- Foreground: Embossed Metal Plate ---
    vec2 plateUV = uv;
    float grid = sin(plateUV.x * 40.0) * cos(plateUV.y * 40.0);
    grid = abs(grid) - 0.5;
    float plateMask = step(0.0, grid); 

    vec3 plateColor = vec3(0.1, 0.08, 0.05);
    // Emboss shading
    float embossVal = pow(plateMask, 2.0) * 0.5;
    plateColor += embossVal * vec3(0.2, 0.2, 0.2);

    // Plate Alpha: Strong everywhere, slightly less over the key to show depth
    float plateAlpha = 0.85 - (isKey * 0.2);

    col = mix(col, plateColor, plateAlpha);

    // Final vignette and grain
    float vignette = 1.0 - length(uv) * 0.8;
    col *= vignette;

    float grain = fract(sin(dot(uv, vec2(12.9898, 78.233) + t)) * 43758.5453);
    col += (grain - 0.5) * 0.1;

    fragColor = vec4(col, 1.0);
}

void main() {
    // Normalized coordinates centered at 0,0
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Time loop: 2 seconds, but we compress the "snap" event into a specific window
    float t = mod(iTime, 2.0);

    // The "Give Up" moment: The structure holds tension until t=0.8, then snaps at 0.9
    // We use a steep sigmoid to simulate the sudden release of structural load
    float snap = smoothstep(0.85, 0.95, t);

    // Base state: Intact Crane (Abstracted as two triangles meeting at center)
    // We define the left and right wings relative to the center spine
    float leftWingX = -0.6 * (1.0 - snap); // Retracts/holds until snap
    float rightWingX = 0.6 * (1.0 - snap);

    // The "Crumple" motion: Once snap happens, wings fall and rotate
    // Heavy, non-bouncy physics for "giving up"
    float fall = smoothstep(0.9, 1.5, t); 

    // Deformation: The wings twist and fold as they collapse
    float twist = fall * 1.2; // Rotation angle
    float collapse = 1.0 - (1.0 - fall) * 0.2; // Compression

    // Calculate screen space for the "shadow"
    vec2 p = uv;

    // Transform the left half
    vec2 leftP = p - vec2(leftWingX, 0.0);
    // Apply the collapse rotation
    float cosT = cos(twist);
    float sinT = sin(twist);
    vec2 rotL = vec2(leftP.x * cosT - leftP.y * sinT, 
                     leftP.x * sinT + leftP.y * cosT);
    vec2 finalLeft = rotL * collapse;

    // Transform the right half (mirror logic)
    vec2 rightP = p - vec2(rightWingX, 0.0);
    // Opposite rotation direction for symmetry before collapse
    vec2 rotR = vec2(rightP.x * cosT - rightP.y * sinT, 
                     rightP.x * sinT + rightP.y * cosT);
    vec2 finalRight = rotR * collapse;

    // Shadow Puppet Geometry: Simple angular shapes representing the crane parts
    // Using signed distance-like logic for sharp, paper-cut edges

    // Left Wing Shape (Triangle-ish)
    float dL = max(max(finalLeft.x, -finalLeft.y - 0.8), finalLeft.x + finalLeft.y - 0.5);
    if (finalLeft.x < -0.1) dL = max(dL, -finalLeft.x - 1.5); // Clip outer edge

    // Right Wing Shape
    float dR = max(max(-finalRight.x, -finalRight.y - 0.8), -finalRight.x + finalRight.y - 0.5);
    if (finalRight.x > 0.1) dR = max(dR, finalRight.x - 1.5);

    // Central Body (The spine that gives way)
    // It shrinks and fades as the load is released
    float spine = length(uv) - (0.4 * (1.0 - snap));

    // Combine shapes with union logic (min)
    float dist = min(min(dL, dR), spine);

    // Sharp edge for paper cut feel
    float alpha = 1.0 - smoothstep(-0.02, 0.02, dist);

    // Texture: Grainy parchment background
    // Procedural noise for paper texture
    float n = fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453);
    float paper = 0.85 + 0.15 * n; // Warm, dusty background

    // Lighting: The shadow is cast against a light source behind
    // The "Give Up" is represented by the shadow becoming less distinct as it collapses
    float shadowColor = 0.05; // Near black

    // Mix: Background + Shadow
    vec3 color = vec3(paper) * mix(vec3(1.0), vec3(shadowColor), alpha);

    // Add a slight vignette to focus on the center stage
    float vig = 1.0 - length(uv) * 0.6;
    color *= mix(vec3(1.0), vec3(0.1), vig * vig);

    // Subtle "dust" particles rising from the snap point (only active after snap)
    float dust = 0.0;
    if (t > 0.9) {
        float dTime = t - 0.9;
        dust = sin(uv.x * 15.0 + dTime * 20.0) * 0.05 * (1.0 - dTime);
    }

    color += vec3(dust);

    fragColor = vec4(color, 1.0);
}

vec2 rot(vec2 st, float a) {
    float s = sin(a), c = cos(a);
    return vec2(st.x*c - st.y*s, st.x*s + st.y*c);
}

float distToLine(vec2 p, vec2 a, vec2 b) {
    return length(cross(vec3(b-a, 0.0), vec3(p-a, 0.0))) / length(b-a);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    uv *= 4.0; // Microscopic zoom

    float t = mod(iTime, 2.0);
    float loop = smoothstep(0.0, 0.5, t) * 2.0; // 0 to 1 over 1 sec

    // The anchor line structure: Braided fibers
    float fiberCount = 7.0;
    vec2 p = uv;

    // Animate the stretching/giving up
    float stretch = 1.0 + loop * 0.8; 
    p.x *= stretch;

    // Twist the braid as it stretches
    float twist = 3.0 - loop * 2.5; 

    float d = 1000.0;

    for (float i = -2.0; i <= 2.0; i++) {
        float angle = i * 0.8 + uv.y * twist * 0.1;
        vec2 center = vec2(0.0, uv.y * 0.5);
        float radius = 0.15 + i * 0.02 + loop * 0.1;
        vec2 fiberPos = center + rot(vec2(cos(angle * 3.0), sin(angle * 3.0)) * radius, angle * 0.5);

        // Add noise to fibers for texture
        float noiseVal = sin(fiberPos.x * 50.0 + t * 5.0) * sin(fiberPos.y * 50.0 - t * 3.0) * 0.02;
        fiberPos += noiseVal;

        float dist = length(p - fiberPos);

        // Tensile thinning effect
        float thickness = 0.04 / stretch + loop * 0.01;
        if (loop > 0.8) thickness *= 0.5; // Necking down before break

        d = min(d, smoothstep(0.0, thickness, dist));
    }

    // The "Giving Up" moment: The Core Failure
    // A glowing, molten core that expands as the line fails
    float coreD = length(uv * stretch);
    float failureZone = smoothstep(0.1, 0.15, loop); // 1.0 at end of loop

    // Fracture lines where fibers snap
    float fracture = 0.0;
    if (loop > 0.7) {
        float snapAngle = atan(uv.y, uv.x) + 1.5;
        float snapDist = length(uv) - 0.05;
        fracture = smoothstep(0.02, 0.0, length(snapDist)) * smoothstep(0.5, 0.0, loop - 0.7);
    }

    // Color composition
    vec3 baseColor = vec3(0.05, 0.1, 0.15); // Dark steel
    vec3 fiberColor = vec3(0.2, 0.3, 0.45) * (1.0 - loop * 0.3);
    vec3 coreColor = mix(vec3(0.0), vec3(1.0, 0.6, 0.0), smoothstep(0.0, 0.5, loop)); // Heating up
    vec3 fractureColor = vec3(1.0, 0.4, 0.1);

    vec3 col = baseColor;

    // Accumulate fibers
    col += fiberColor * smoothstep(0.8, 0.95, d);

    // Add the core glow (the material giving up structurally)
    col += coreColor * (1.0 - smoothstep(0.0, 0.08, coreD)) * failureZone;

    // Add fracture sparks/lines
    col += fractureColor * fracture * 2.0;

    // Vignette for microscopic feel
    float vign = 1.0 - smoothstep(0.0, 0.5, length(uv));
    col *= vign;

    // Bloom/Glow for the failing core
    float bloom = dot(col, vec3(0.5)) * (1.0 - smoothstep(0.0, 0.05, coreD)) * 2.0;
    col += vec3(bloom * 0.5);

    fragColor = vec4(col, 1.0);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec3 palette(float t) {
    // Cold silicon to hot amber to dull charcoal (surrender)
    vec3 a = vec3(0.1, 0.3, 0.6);
    vec3 b = vec3(0.6, 0.3, 0.1);
    vec3 c = vec3(0.4, 0.5, 0.4);
    vec3 d = vec3(0.05, 0.05, 0.05);
    // Smoothstep-like mix for the surrender gradient
    return mix(a, b, smoothstep(0.0, 0.5, t)) + 
           mix(b, c, smoothstep(0.5, 0.8, t)) * 0.5 +
           mix(c, d, smoothstep(0.8, 1.0, t)) * 0.8;
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    // Aspect correction
    vec2 p = uv * 2.0 - 1.0;
    p.x *= iResolution.x / iResolution.y;

    // Time loop 0.0 to 1.0 over 2 seconds
    float t = fract(iTime / 2.0);
    float surrender = t; // 0.0 = rigid, 1.0 = melted

    // Base grid coordinates
    vec2 grid = floor(p * 20.0) + 0.5;
    vec2 local = fract(p * 20.0);

    // The "Giving Up" distortion: 
    // As t increases, rigid grid points sag into viscous blobs.
    // We use a hash to determine unique melting paths for each cell.
    float noiseVal = hash(grid);

    // Calculate a sag vector that grows with time
    vec2 sag = vec2(0.0);
    if (surrender > 0.2) {
        sag = vec2(cos(noiseVal * 6.28), sin(noiseVal * 6.28)) * 0.3 * (surrender - 0.2);
    }

    // Shift coordinates by the sag
    vec2 distorted = local - sag * surrender;

    // Calculate distance to nearest "melted" center (now offset)
    float d = length(distorted - 0.5);

    // Create the circuit lines that are dissolving
    float lineWidth = 0.05 * (1.0 - surrender * 0.7); // Lines get thinner then disappear
    float distToLine = length(distorted - 0.5) - 0.15;

    // If surrender is high, the lines become droplets
    float shape;
    if (surrender < 0.5) {
        // Rigid grid phase with slight wobble
        float x = abs(local.x - 0.5);
        float y = abs(local.y - 0.5);
        shape = max(x, y) - lineWidth * 0.5;
    } else {
        // Melting phase: The grid turns into a soft blob
        shape = d - (0.2 + 0.2 * (1.0 - surrender));
    }

    // Add thermal noise to the surface texture
    float noise = hash(grid + t * 10.0) * 0.1;

    // Color logic based on surrender state
    vec3 col = palette(surrender + noise);

    // Opacity and contrast
    float alpha = 1.0 - smoothstep(0.0, 0.15, abs(shape));

    // If melted, make it glossy and soft; if rigid, sharp and matte
    if (surrender > 0.5) {
        alpha *= smoothstep(0.3, 0.0, d); // Soft blob
        col *= 0.8 + 0.2 * noise; // Hot glow variation
    } else {
        alpha *= step(0.0, 0.05); // Hard edges
        col *= 0.8; // Dimmer silicon
    }

    // Background: Dark, hot void
    vec3 bg = vec3(0.02, 0.01, 0.05) + vec3(0.1, 0.05, 0.0) * surrender;

    fragColor = vec4(mix(bg, col, alpha), 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    vec2 p = (uv - 0.5) * 2.0;

    // Loop logic: 2 seconds. Fast ramp up, sudden snap, slow cool down.
    float t = iTime;
    // Create a "snap" profile: tension builds, then instant release
    float cycle = mod(t, 2.0);
    float tension = smoothstep(0.0, 1.8, cycle);
    float snap = step(1.8, cycle);
    float release = smoothstep(1.8, 2.0, cycle) * 2.0;

    // Geometry distortion: The grid stretches as tension rises
    // The "snap" happens at t=1.8, breaking the diagonal symmetry
    float x = p.x * (1.0 + tension * 0.2);
    float y = p.y * (1.0 + tension * 0.15);

    // Add a diagonal shear that accelerates at the snap moment
    float shear = tension * 0.3 + release * 0.5;
    vec2 distorted = vec2(x, y) + vec2(shear * p.y, shear * p.x);

    // Voronoi-ish cell structure representing concrete blocks
    // Using a lattice pattern with noise for texture
    float gridX = step(0.5, fract(distorted.x * 4.0));
    float gridY = step(0.5, fract(distorted.y * 4.0));

    // Add subtle noise for concrete texture
    float noise = sin(distorted.x * 10.0 + t) * cos(distorted.y * 10.0 - t);

    // The Fracture: A diagonal line that appears only after snap
    // It's defined by the distance to the diagonal x=y
    float distDiag = abs(distorted.x - distorted.y);
    float fractureWidth = 0.05 + release * 0.2; // Fracture widens as release happens
    float fracture = smoothstep(fractureWidth, 0.0, distDiag); // 1.0 inside fracture, 0.0 outside

    // Color Palette
    vec3 coldConcrete = vec3(0.2, 0.22, 0.25);
    vec3 hotConcrete = vec3(0.8, 0.3, 0.05);
    vec3 molten = vec3(1.0, 0.6, 0.1);
    vec3 voidBlack = vec3(0.0, 0.0, 0.0);

    // Mix base concrete color based on tension/heat
    vec3 baseColor = mix(coldConcrete, molten, tension * 0.8);
    baseColor = mix(baseColor, hotConcrete, snap * 0.6);

    // Apply grid lines (dark mortar)
    float gridLine = smoothstep(0.45, 0.55, fract(distorted.x * 4.0)) + 
                     smoothstep(0.45, 0.55, fract(distorted.y * 4.0));
    vec3 mortarColor = mix(coldConcrete, hotConcrete, tension);
    baseColor = mix(baseColor, mortarColor, gridLine);

    // Apply the fracture
    // As the snap occurs, the fracture turns black (void), absorbing the light
    vec3 fractureColor = mix(baseColor, voidBlack, fracture * (1.0 - release)); 
    // The fracture glows orange at the edges during release
    float edgeGlow = smoothstep(fractureWidth * 0.5, fractureWidth, distDiag);
    fractureColor = mix(fractureColor, molten * 1.5, edgeGlow * (1.0 - release));

    // Final composition
    vec3 finalColor = mix(baseColor, fractureColor, (1.0 - smoothstep(0.0, 0.9, release)));

    // Add noise texture
    finalColor += noise * 0.05;

    // Vignette for focus
    float vignette = 1.0 - length(p) * 0.4;
    finalColor *= vignette;

    fragColor = vec4(finalColor, 1.0);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for(int i = 0; i < 4; ++i) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

float helix(vec2 uv, float z) {
    float r = 0.25;
    float freq = 5.0;
    float phase = z * 6.28;

    vec2 p = uv * 3.0 - vec2(1.0);
    float arm1 = sin(phase + z * freq);
    float arm2 = sin(phase + z * freq + 3.14159);

    float d1 = distance(p, vec2(arm1 * r, arm2 * r * 0.5));
    float d2 = distance(p, vec2(arm2 * r, -arm1 * r * 0.5));

    return min(d1, d2);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    uv.x *= iResolution.x / iResolution.y;
    uv -= 0.5;

    float t = iTime;
    float loopT = fract(t / 2.0);

    // Collapse logic: 0.0 to 0.4 builds, 0.4 to 1.0 gives up
    float giveUp = smoothstep(0.35, 0.55, loopT);

    // Vertical scroll
    float z = -uv.y * 2.0 + t * 1.5;

    float h = helix(uv, z);

    // Distort geometry as it gives up
    if (giveUp > 0.0) {
        float smear = (giveUp - 0.0) * 1.5;
        uv.y += sin(uv.x * 15.0 + t * 20.0) * smear * 0.05;
        h += fbm(uv * 8.0) * smear * 0.15;
        h *= (1.0 - smear * 0.8);
    }

    // Risograph layers
    vec3 cyan = vec3(0.0, 0.8, 0.8);
    vec3 mag = vec3(0.9, 0.1, 0.6);
    vec3 blk = vec3(0.1, 0.1, 0.12);

    float c1 = step(0.01, h);
    float c2 = step(0.012, h + 0.005); // Offset
    float c3 = step(0.008, h - 0.005); // Offset

    vec3 color = mix(blk, cyan, c1 * 0.6);
    color = mix(color, mag, c2 * 0.6);
    color = mix(color, blk, c3 * 0.6);

    // Replace structure with muddy noise when giving up
    vec3 mud = vec3(0.0);
    if (giveUp > 0.5) {
        float n = fbm(uv * 12.0 + vec2(t * 3.0, 0.0));
        mud = mix(vec3(0.05), vec3(0.02), step(0.45, n));
        // Glitch lines
        mud += vec3(0.05, 0.0, 0.0) * sin(uv.x * 60.0 + t * 30.0) * 0.5;
    }

    float structureMask = 1.0 - smoothstep(0.5, 0.8, giveUp);
    vec3 finalInk = mix(mud, color, structureMask);

    // Paper base
    vec3 paper = vec3(0.96, 0.94, 0.91) + vec3(0.0, 0.02, -0.01) * noise(uv * 30.0) * 0.05;

    // Halftone grain overlay
    float grain = step(0.5, noise(uv * 50.0 + vec2(t, 0.0)));
    finalInk += vec3(grain * 0.05);

    // Composite
    vec3 result = mix(paper, finalInk, step(0.01, length(finalInk)));

    // Vignette for focus
    float dist = length(uv);
    result *= 1.0 - smoothstep(0.8, 1.2, dist) * 0.3;

    fragColor = vec4(result, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = mod(iTime, 2.0) / 2.0;

    // 1. The "System Core" Geometry (The Subject)
    vec2 p = uv * 2.0;
    float d = 0.0;

    // A rotating, complex geometric shape representing the OS
    float a = atan(p.y, p.x);
    float r = length(p);

    // Create a star-like structure
    float star = length(p) - 0.6 * abs(sin(a * 5.0 + 2.0 * iTime));

    // Add internal circuit-like details
    float grid = sin(p.x * 20.0) * sin(p.y * 20.0);
    float core = star;

    // 2. The "Bleaching" Mechanism (Give Up)
    // A wave of destruction moves from the center outward or vice versa
    // Here: The core is losing its "ink" to the white background
    float dissolve = smoothstep(0.8, 1.2, r * (1.0 - t)); 

    // 3. The "Woodblock" Texture (Thread Loss)
    // Procedural noise simulating rough paper and ink bleed
    float n = sin(p.x * 100.0) + sin(p.y * 100.0) + sin((p.x + p.y) * 100.0);
    n = fract(n * 0.1);

    // The "Unraveling" effect: as time passes, the sharp edges turn into noise
    float threadLoss = smoothstep(0.0, t * 2.0, n);

    // 4. Composition
    float ink = 0.0;

    // Define the core area
    if (core < 0.05) {
        ink = 1.0;
    }

    // Apply the "giving up" logic
    // The core shrinks and its edges get eaten by the noise
    float erosion = smoothstep(0.0, 0.2, core - (t * 0.5));
    ink *= erosion;

    // Mix with the unraveling texture: 
    // Where the thread is lost, we switch to white noise/grain
    float finalInk = ink * (1.0 - threadLoss * 0.8);

    // 5. Woodblock Print Aesthetic (High Contrast)
    // Hard threshold to simulate ink on paper
    float print = step(0.4, finalInk);

    // 6. The "Bleached" Look (Overexposure)
    // Add a subtle vignette of pure white that expands
    float vignette = 1.0 - smoothstep(0.0, 1.0, length(uv) - (0.5 + t * 0.5));

    vec3 col = vec3(0.0); // Pure Black Ink

    // Add the "System" accent (Crimson) to the core before it dies
    if (core < 0.04 && t < 0.5) {
        col = mix(vec3(0.0), vec3(0.9, 0.1, 0.1), print);
    } else {
        col = vec3(print);
    }

    // The "Bleach" washes everything to white
    // As time goes, the black ink becomes white grain
    vec3 finalColor = mix(col, vec3(1.0, 1.0, 0.95), t * 0.4 + threadLoss * 0.6);

    // Final grain pass to simulate rough paper fibers
    float grain = fract(sin(dot(uv * 200.0, vec2(12.9898, 78.233)))) * 0.1;
    finalColor += grain;

    // Clamp
    fragColor = vec4(finalColor, 1.0);
}

void main() {
    // Map pixel to grid coordinate (0.0 - 1.0)
    vec2 uv = gl_FragCoord.xy / iResolution.xy;

    // Loop time: 2 seconds cycle
    float t = mod(iTime, 2.0);

    // Create a grid of "tubes" (horizontal and vertical lines)
    vec2 grid = abs(fract(uv * 20.0) - 0.5) - 0.4;
    float tubeMask = smoothstep(0.0, 0.05, grid.x) + smoothstep(0.0, 0.05, grid.y);
    tubeMask = smoothstep(0.05, 0.06, tubeMask); // Sharpen edges

    // Timelapse "Decay" Logic
    // t=0: Bright, unstable plasma. t=1: Collapse into purple/dark spots. t=2: Dead.
    // We accelerate the death at the end for dramatic effect
    float life = smoothstep(1.8, 0.0, t); 

    // Add noise to the grid to simulate gas density loss (flickering)
    // The noise frequency increases as the tube dies (turbulence)
    float noiseFreq = 15.0 + 50.0 * (1.0 - life);
    vec2 noiseUV = uv * noiseFreq + vec2(t * 2.0, -t * 3.0);
    float n = sin(noiseUV.x) * sin(noiseUV.y) * sin(noiseUV.x * 2.13);
    float gasDensity = smoothstep(0.5, 0.9, life - n * 0.5);

    // Color Shift: White -> Cyan -> Purple -> Black
    // Dead state
    vec3 cDead = vec3(0.02); 

    // Dying state (Purple/Bruise)
    vec3 cDying = vec3(0.3, 0.1, 0.6) * pow(gasDensity, 3.0);

    // Alive state (Neon Cyan/White core)
    vec3 cAlive = mix(vec3(1.0, 1.0, 0.9), vec3(0.0, 0.8, 1.0), 0.6) * pow(gasDensity, 0.8);

    // Composite based on life stage
    vec3 color;
    if (life < 0.1) {
        color = cDead;
    } else if (life < 0.4) {
        // The collapse phase: violent mixing of dying gas
        color = mix(cDying, cAlive, gasDensity * 2.0);
        // Add "dark spots" where gas fails
        color *= smoothstep(0.2, 0.0, n - 0.3);
    } else {
        // Stable but fading
        color = cAlive;
        // Slight flicker
        color *= 0.98 + 0.02 * sin(t * 40.0 + uv.x * 10.0);
    }

    // Apply the tube mask (glow only happens inside the glass)
    // Add a bloom effect that shrinks as the tube dies
    float glow = tubeMask * (1.0 - abs(grid.x - 0.5)) * (1.0 - abs(grid.y - 0.5));
    float bloomAmount = smoothstep(0.0, 0.5, life);
    float glowFinal = smoothstep(0.0, 1.5, glow * 2.0); // Soften the tube

    // Final composition: Dead background + Glowing tube
    vec3 finalColor = cDead + (color - cDead) * glowFinal;

    // Vignette to emphasize the "darkness taking over"
    float vignette = 1.0 - length(uv - 0.5) * 0.8;
    finalColor *= vignette;

    // Gamma correction for neon feel
    finalColor = pow(finalColor, vec3(0.4545));

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    float t = iTime * 1.5; 

    // Loop factor: 0.0 to 1.0 over 2 seconds
    float cycle = fract(iTime / 2.0); 
    float loop = 4.0 * abs(0.5 - cycle); 

    // Tension increases until snap point
    float tension = loop; 
    float timeToSnap = 1.0 - tension;

    // Create a central "necking" zone where the rope is thinnest
    float neck = 1.0 - clamp(abs(uv.x) * 3.0 - 0.1, 0.0, 1.0);
    neck = pow(neck, 3.0) * (1.0 - timeToSnap * 2.0); 

    // Fiber lattice generation
    float y = abs(uv.y) * 10.0 + t * 0.5;
    float x = abs(uv.x) * 20.0;

    // Distort fibers based on tension
    float fiberOffset = sin(x * 0.1 + y * 0.05) * (1.0 + tension * 0.5);
    float fiberWidth = 0.02 + neck * 0.02;

    // Create the "snapping" chaos
    float chaos = 0.0;
    if (tension > 0.85) {
        float dist = length(uv);
        float recoil = (t - 1.0) * 10.0; 

        // Unraveling pattern
        chaos = sin(x * 20.0 - recoil * 5.0) * cos(y * 20.0 + recoil * 5.0);
        chaos *= smoothstep(0.0, 0.05, dist) * (1.0 - smoothstep(0.0, 0.02, dist)); 

        // Fraying strands
        float strands = abs(fract(x * 5.0 + recoil * 2.0)) - 0.5;
        // Fixed: Use max(float, float) instead of max(float, vec2) or mismatched types
        strands = max(0.0, 0.01 - abs(strands) - dist * 0.5);
        chaos += strands;
    }

    // Base fiber structure
    float fibers = 1.0 - smoothstep(fiberWidth, fiberWidth + 0.002, abs(sin(x + fiberOffset) + 0.5));
    fibers *= smoothstep(fiberWidth * 2.0, 0.0, abs(uv.y - sin(x * 0.1) * 0.05)); 

    // Combine structure and chaos
    float finalIntensity = fibers * (1.0 - chaos) + chaos;

    // Color grading: Stress -> Snap
    vec3 colorStress = vec3(0.2, 0.3, 0.9) + tension * vec3(0.0, 0.3, 0.5); 
    vec3 colorSnap   = vec3(1.0, 0.6, 0.1); 

    vec3 color = mix(colorStress, colorSnap, smoothstep(0.88, 0.95, tension));

    // Post-process: Add micro-cracks and stress lines
    float stressLines = sin(uv.y * 100.0 + tension * 5.0) * sin(uv.x * 100.0 - tension * 5.0);
    stressLines = smoothstep(0.95, 1.0, abs(stressLines)) * 0.3;

    color += vec3(stressLines * tension * (1.0 - timeToSnap));

    // Final output with vignette
    vec3 finalCol = color * finalIntensity + vec3(0.05, 0.05, 0.1) * (1.0 - length(uv) * 0.5);

    // Clamp and gamma correct
    // Fixed: max(vec3, float) works, but let's ensure types are explicit if needed.
    // In GLSL ES 3.0, max(vec3, float) is valid (scalar broadcast).
    fragColor = vec4(pow(max(vec3(0.0), finalCol), vec3(1.0/2.2)), 1.0);
}

void main() {
    float t = mod(iTime, 2.0);
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // 1. NOISE FUNCTIONS
    float hash(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
    float noiseFunc(vec2 p) {
        vec2 i = floor(p);
        vec2 f = fract(p);
        f = f * f * (3.0 - 2.0 * f);
        float n = mix(mix(hash(i), hash(i + vec2(1.0, 0.0)), f.x),
                      mix(hash(i + vec2(0.0, 1.0)), hash(i + vec2(1.0, 1.0)), f.x), f.y);
        return n;
    }

    float fbm(vec2 p) {
        float v = 0.0;
        float a = 0.5;
        vec2 shift = vec2(100.0);
        for(int i = 0; i < 5; i++) {
            v += a * noiseFunc(p);
            p *= 2.0 + shift;
            a *= 0.5;
        }
        return v;
    }

    // 2. BLACKBOARD BASE
    float boardGrain = fbm(uv * 40.0 + t * 0.2);
    vec3 bg = vec3(0.05, 0.05, 0.08) + vec3(0.1, 0.1, 0.12) * boardGrain * 0.4;
    bg += vec3(0.0, 0.0, 0.1) * smoothstep(0.5, 1.0, abs(uv.y));

    // 3. DIELECTRIC BREAKDOWN
    vec2 origin = vec2(-0.3, -0.6);
    vec2 target = vec2(0.4, 0.6);

    float dist = length(uv - origin);

    float charge = (t * 1.5); 
    float threshold = 0.35 + (1.0 - t) * 0.6; 

    float arcVal = 0.0;
    vec2 p = uv * 2.5; 

    vec2 dir = normalize(target - origin);
    float angle = atan(dir.y, dir.x);

    for(int i = 0; i < 4; i++) {
        vec2 q = p + vec2(10.0 + float(i) * 5.0, 10.0);
        float n = noiseFunc(q * (0.1 + float(i) * 0.05) - t * 2.0);
        float branch = smoothstep(threshold - 0.1, threshold + 0.1, n * 1.5);
        float branchWidth = smoothstep(1.0, 0.0, abs(n - 0.5) * 4.0);
        arcVal += branch * branchWidth * (0.4 + 0.2 * float(i));
        p *= 0.8;
    }

    float trunk = smoothstep(dist + 0.05, dist, charge * 0.8) * (1.0 - smoothstep(0.0, 1.0, t));
    float electricField = max(trunk * 0.5, arcVal);

    // 4. RENDERING
    float chalkIntensity = smoothstep(0.0, 0.6, electricField);
    chalkIntensity *= smoothstep(1.0, 0.0, abs(noiseFunc(uv * 60.0 + t * 5.0) - 0.5) * 4.0);

    vec3 chalkColor = vec3(1.0, 1.0, 1.0);
    vec3 glow = vec3(0.8, 0.9, 1.1) * electricField * 0.2;

    vec3 finalColor = bg;
    finalColor += chalkColor * chalkIntensity;
    finalColor += glow;

    float wetness = fbm(uv * 80.0 + t * 3.0);
    finalColor -= vec3(0.02, 0.02, 0.03) * wetness * 0.2;

    if (t > 1.95) {
        float fade = smoothstep(1.9, 2.0, t);
        finalColor = mix(finalColor, bg, fade);
    }

    fragColor = vec4(finalColor, 1.0);
}

vec2 rot(vec2 p, float a) {
    float s = sin(a), c = cos(a);
    return vec2(p.x * c - p.y * s, p.x * s + p.y * c);
}

// Fractal Brownian Motion for the wet distortion
float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    // Hard-coded pseudo-random offset to avoid texture dependency
    mat2 m = mat2(cos(12.9898), sin(12.9898), -sin(12.9898), cos(12.9898));
    for(int i = 0; i < 4; i++) {
        vec2 w = p * float(i + 1);
        vec2 d = vec2(dot(w, vec2(127.1, 311.7)), dot(w, vec2(269.5, 183.3)));
        float n = fract(sin(d.x * d.y) * 43758.5453);
        v += a * (n - 0.5);
        p = rot(p, 0.6) * 2.0;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;

    // Time loop: 0.0 to 2.0
    float t = iTime;
    float loop = mod(t, 2.0);

    // Electric charge buildup: sharp spike then exponential decay
    float pulse = exp(-4.0 * loop) * (1.0 - exp(-10.0 * loop));
    float ringFreq = 3.0 + 4.0 * sin(loop * 3.14159);

    // Base geometry: Corona Ringing
    vec2 p = uv;
    // Add wet glass distortion (refraction)
    float noise = fbm(p * 15.0 + vec2(loop * 2.0, loop * -1.5));
    p += noise * 0.15;

    float r = length(p);

    // The Corona Field: Sine waves on a toroidal decay
    // High frequency ringing
    float field = sin(r * 25.0 - t * 15.0 + noise * 5.0) * 0.5;
    // Superimpose a secondary interference pattern
    field += sin(r * 8.0 - t * 5.0 + p.x * 3.0) * 0.2;

    // Apply the "Pulse" envelope to the field amplitude
    field = smoothstep(0.0, 1.0, pulse) * field;

    // Topographic Contour Logic
    // We want sharp lines where the field crosses integer thresholds
    // Use fract to get repeating bands, then sharpen the edges
    float bands = fract(field * 4.0 + 0.5);

    // Create razor-thin lines using the derivative of the field
    // Invert so lines are bright on dark
    float threshold = 0.02;
    float lines = 1.0 - step(threshold, abs(bands - 0.5));
    lines = smoothstep(0.0, 0.05, lines);

    // Color Palette: Electric Blue/White on Deep Black/Wet Glass Grey
    vec3 base = vec3(0.05, 0.06, 0.08); // Deep wet glass black
    vec3 arc = vec3(0.8, 0.9, 1.0);     // Corona white-blue
    vec3 mid = vec3(0.2, 0.3, 0.5);     // Mid-tone wet glass

    // Mix based on the contour intensity and field magnitude
    vec3 col = mix(base, mid, smoothstep(0.0, 1.0, abs(field)));
    col += vec3(1.0) * lines * mix(1.0, 0.5, abs(field)); // Glow on lines

    // Add a vignette to simulate the edge of the wet glass drop
    float vign = 1.0 - smoothstep(0.5, 2.0, length(uv));
    col *= vign;

    fragColor = vec4(col, 1.0);
}

void main() {
    // Aspect ratio corrected coordinates, centered
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);

    // Loop time: 2.0 seconds
    float t = mod(iTime, 2.0);

    // Schematic grid setup
    float gridSize = 4.0;
    vec2 gridUV = abs(mod(uv * gridSize + 0.5, 2.0) - 1.0);

    // Background: Technical Slate
    vec3 col = vec3(0.12, 0.14, 0.20);

    // Grid lines (faint)
    col += 0.05 * smoothstep(0.9, 1.0, gridUV.x) * smoothstep(0.9, 1.0, gridUV.y);

    // Dielectric breakdown event parameters
    // A "step" function build-up followed by a chaotic arc
    float charge = smoothstep(0.0, 0.4, t); // Charge up first 0.4s
    float decay = smoothstep(0.9, 2.0, t); // Fade out

    float stress = charge * 2.5;           // Visual pressure

    // Path generation: A jagged, deterministic "random" walk based on time
    float stepTime = floor(t * 20.0); 
    float r1 = fract(sin(stepTime) * 43758.5453);
    float r2 = fract(sin(stepTime * 4532.342) * 43758.5453);

    // Define the "Arc" geometry
    vec2 p0 = vec2(-1.5, -1.5);
    vec2 p1 = vec2(1.5, 1.5);

    vec2 pt = p0;
    float dist = 10.0;

    // Draw 10 segments of the breakdown
    for (int i = 0; i < 10; i++) {
        vec2 nextP = p1 * (float(i+1) / 10.0);
        float jitter = (r1 * 0.4 + r2 * 0.2) * stress * 0.8;
        pt.y += (r1 - 0.5) * jitter * 2.0;
        pt.x += (r2 - 0.5) * jitter * 2.0;

        vec2 segDir = nextP - pt;
        vec2 toPt = uv - pt;
        float tSeg = dot(toPt, segDir) / dot(segDir, segDir);
        tSeg = clamp(tSeg, 0.0, 1.0);
        vec2 closest = pt + tSeg * segDir;
        float d = length(uv - closest);

        // Active phase logic
        float phaseActive = smoothstep(0.38, 0.45, t);
        float intensity = (t < 0.4) ? (stress * 0.1) : (1.0 - decay);

        if (phaseActive > 0.9 || (phaseActive > 0.0 && t < 0.4)) {
            if (d < 0.04) {
                dist = min(dist, d);
            }
        }
        pt = nextP;
    }

    float core = 1.0 - smoothstep(0.002, 0.01, dist);
    float glow = 1.0 - smoothstep(0.01, 0.08, dist);

    vec3 plasmaColor = mix(vec3(0.8, 0.95, 1.0), vec3(1.0, 1.0, 1.0), core);

    float arcIntensity = smoothstep(0.38, 0.45, t) * (1.0 - decay);
    if (dist < 0.08) {
        col = mix(col, plasmaColor, arcIntensity * core * 1.5);
        col += vec3(0.2, 0.5, 0.8) * arcIntensity * glow * 0.3;
    }

    // Annotations
    vec2 labelPos = vec2(-1.3, -1.3);
    float labelDist = length(uv - labelPos);
    if (labelDist < 0.15 && t > 0.1) {
        float box = smoothstep(0.0, 0.08, abs(uv.x - labelPos.x)) * smoothstep(0.0, 0.08, abs(uv.y - labelPos.y));
        col = mix(col, vec3(1.0, 1.0, 1.0), box * 0.8 * (1.0 - decay));
    }

    vec2 failPos = vec2(1.3, 1.3);
    float failDist = length(uv - failPos);
    if (failDist < 0.12 && t > 0.4) {
        col += vec3(1.0, 0.2, 0.2) * (1.0 - smoothstep(0.0, 0.1, failDist)) * (1.0 - decay) * 2.0;
    }

    // Voltage meter bar
    vec2 meterPos = vec2(-1.4, -1.4);
    float meterBar = smoothstep(0.0, 0.1, uv.x - meterPos.x) * smoothstep(0.0, 0.1, meterPos.y - uv.y);
    float meterFill = smoothstep(0.0, 0.4, t) * (1.0 - decay);
    if (uv.x > meterPos.x && uv.x < meterPos.x + 0.2 && uv.y < meterPos.y + 0.02) {
        if (uv.x - meterPos.x < meterFill * 0.2) {
            col = mix(col, vec3(0.0, 1.0, 0.0), 0.8);
        }
        // Border
        col = mix(col, vec3(0.8, 0.8, 0.8), 0.5 * meterBar);
    }

    fragColor = vec4(col, 1.0);
}

float rand2(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

float noise2(vec2 x) {
    vec2 p = floor(x);
    vec2 f = fract(x);
    f = f*f*(3.0-2.0*f);
    float a = rand2(p);
    float b = rand2(p+vec2(1.0,0.0));
    float c = rand2(p+vec2(0.0,1.0));
    float d = rand2(p+vec2(1.0,1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float distanceField(vec2 p) {
    vec2 pos = p;
    float d = 100.0;
    int iter = 6;
    float t = iTime;

    for(int i=0; i<iter; i++){
        pos = fract(pos * 1.5) - 0.5;
        float d2 = length(pos);
        if(d2 < d) {
            vec2 pr = reflect(pos, normalize(vec2(1.0, 1.0)));
            // Fixed: Cast int i to float for arithmetic
            d = min(d, d2 * (1.0 - 0.3 * sin(t * 3.0 + float(i)))); 
            pos = pr;
        }
    }

    float n = noise2(pos * 3.0 + vec2(iTime * 0.5));
    d *= (1.0 - 0.2 * n);

    return d;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    float grain = noise2(uv * 50.0) * 0.02;
    vec3 bg = vec3(0.05, 0.06, 0.04) + grain;

    float t = mod(iTime, 2.0);
    float dist = distanceField(uv * 4.0);

    vec3 col = vec3(0.0);

    if(dist < 0.15) {
        float f = 1.0 - dist * 7.0;
        f = max(0.0, f);

        vec3 coreColor = vec3(0.9, 0.92, 0.85); 
        vec3 rimColor = vec3(0.2, 0.6, 0.5);    

        vec3 finalColor = mix(rimColor, coreColor, f * f);
        float pulse = sin(t * 6.0) * 0.5 + 0.5;
        float intensity = f * pulse;
        col = finalColor * intensity;
    }

    float sparkDist = distanceField(uv * 8.0 + vec2(t));
    if(sparkDist < 0.05) {
        float s = 1.0 - sparkDist * 12.0;
        s = max(0.0, s);
        col += vec3(0.9, 0.95, 0.98) * s * 0.3 * (0.5 + 0.5 * sin(t * 20.0));
    }

    vec3 result = bg + col;
    float chalkGrain = noise2(uv * 30.0 + t * 0.2) * 0.15;
    result *= 1.0 + chalkGrain;

    float vignette = 1.0 - length(uv) * 0.5;
    result *= vignette;

    fragColor = vec4(result, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / min(iResolution.x, iResolution.y);

    // Loop time: 0 to 1 over 2 seconds
    float t = fract(iTime / 2.0);

    // Create a "snap" timeline: 0.0-0.4 build up, 0.4-0.5 snap, 0.5-1.0 decay
    float snapT = t * 2.0;
    float trigger = smoothstep(0.4, 0.5, snapT); // The moment of rupture
    float decay = 1.0 - smoothstep(0.0, 0.6, t - 0.5); // Exponential-ish decay

    // Parametric oscilloscope trace
    // X is the time base, Y is the signal voltage
    float timeBase = sin(snapT * 6.2832); 

    // The signal: A base carrier + a chaotic burst at the snap moment
    // We use a combination of sin/cos with frequency modulation based on the trigger
    float baseFreq = 12.0;
    float chaosFreq = 45.0;

    // Modulate frequency: High chaos only during the snap, then dampen
    float freqMod = trigger * chaosFreq * (1.0 - decay * 2.0);

    float signal = sin(baseFreq * timeBase + 1.0) 
                 + 0.4 * sin((baseFreq + freqMod) * timeBase * 1.5) 
                 + 0.15 * sin((freqMod * 3.0) * timeBase) 
                 - 0.2 * cos(freqMod * 0.1);

    // Normalize trace to screen space
    vec2 traceUV = vec2(timeBase, signal);
    traceUV.x *= 0.9; // Aspect correction for time
    traceUV.y *= 0.8; // Amplitude correction

    // Distance field to the trace
    float dist = length(uv - traceUV);

    // Add a "ghost" trail effect by offsetting the trace slightly based on time
    // This simulates the persistence of phosphor on the scope
    float trailFade = 1.0 - (snapT * 0.8);
    vec2 trailUV = traceUV * (0.98 - 0.05 * t) + vec2(-0.2, 0.1);
    float trailDist = length(uv - trailUV) * 1.2;

    // Combine trace and trail
    float intensity = max(
        exp(-dist * 15.0), 
        trailFade * exp(-trailDist * 12.0)
    );

    // Color grading: Hot white core -> Cyan edge -> Black
    vec3 color = vec3(0.0);
    if (intensity > 0.0) {
        float core = max(0.0, intensity - 0.3);
        float edge = max(0.0, intensity - 0.05);

        // White hot center
        vec3 whiteHot = vec3(1.0, 0.98, 0.95) * core * 4.0;
        // Cyan cool edge
        vec3 cyanCool = vec3(0.2, 0.8, 1.0) * edge * 0.8;
        // Ambient glow
        vec3 ambient = vec3(0.05, 0.1, 0.12) * intensity * 2.0;

        color = whiteHot + cyanCool + ambient;
    }

    // Vignette to simulate the curved screen of an old scope
    float vig = 1.0 - length(uv) * 0.8;
    color *= max(0.0, vig);

    // Threshold for crispness, but keep glow
    color = max(color, vec3(0.0));

    fragColor = vec4(color, 1.0);
}

void main() {
    // Normalize coordinates, center origin
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    // Slight perspective squash for the "pool" effect
    uv.y *= 0.8;

    // --- Time Looping ---
    // 2-second loop, sharp snap at the start/end
    float t = iTime;
    float loopT = fract(t * 0.5); // 0.0 to 1.0 over 2 seconds
    float snap = smoothstep(0.9, 1.0, loopT); // The retraction phase
    float energy = 1.0 - smoothstep(0.0, 0.2, loopT); // Initial snap
    float cycle = sin(loopT * 6.28318 + 1.57) * 0.5 + 0.5; // Oscillator

    // --- Woodblock Noise (High Freq) ---
    // Procedural noise to simulate paper grain/ink bleed
    vec2 grainUV = uv * 80.0 + vec2(1000.0, -1000.0);
    float noise = fract(sin(dot(grainUV, vec2(12.9898, 78.233))) * 43758.5453);
    // Add a second layer for coarser texture
    noise += 0.5 * fract(sin(dot(grainUV * 2.5, vec2(23.9898, 67.233))) * 43758.5453);
    float grain = smoothstep(0.3, 0.7, noise);

    // --- The Pin ---
    // Static anchor at bottom center
    vec2 pinPos = vec2(0.0, 0.6);
    float distToPin = length(uv - pinPos);
    float pinShape = 1.0 - step(0.04, distToPin); // Sharp circle
    float pinCore = 1.0 - step(0.01, distToPin);  // Highlight

    // --- Discharge Structure ---
    // We create a rising plume that is modulated by time and position
    float h = uv.y; 
    float maxH = 1.2; // Height of the discharge

    // Base shape: a rising cone/taper
    float taper = 1.0 - (h + 0.6) * 0.4;
    float width = abs(uv.x) * (1.5 - h * 0.5);

    // Fractal Jaggedness (Woodcut style branching)
    // Use a combination of sin waves and noise to create "cracks"
    float branch1 = sin(uv.y * 40.0 - loopT * 15.0) * cos(uv.x * 20.0);
    float branch2 = sin(uv.y * 100.0 + loopT * 30.0) * sin(uv.x * 50.0);

    // Combine branches to form the "electric" path
    float electricPath = branch1 + branch2;
    // Mask the electric path to the taper shape
    float discharge = smoothstep(0.4, 0.8, abs(electricPath)) * taper;

    // --- Animation Logic ---
    // The discharge exists only when 'energy' is high and 'snap' is low
    // The shape oscillates wildly during the 'rise' phase
    float animMask = 1.0 - snap;
    // Convert boolean condition to float (0.0 or 1.0) for math operations
    float activeHeight = step(-0.6, h) * step(h, 0.6 + (1.0 - snap) * 0.6 * energy);

    // --- Merge Components ---
    float ink = 0.0;

    // 1. The Pin (Always visible)
    ink += pinShape * 0.8;
    ink += pinCore * 0.4;

    // 2. The Discharge (Active during loop)
    // Multiply activeHeight (0 or 1) with the discharge shape
    if (activeHeight > 0.5) {
        // The discharge intensity is modulated by the cycle to "crackle"
        float crackle = step(0.3, fract(cycle * 50.0 + uv.x * 20.0)) * energy;
        ink += discharge * crackle * animMask;
    }

    // 3. The Mercury Pool (Reflection/Texture)
    // The pool reflects the "ink" above it slightly, but mostly is solid
    if (h <= -0.6) {
        // Add surface tension ripples
        float ripple = sin(uv.x * 30.0 + loopT * 10.0) * 0.02;
        float poolInk = 0.6 + 0.4 * grain; // Darker base
        // The pool is "liquid" so it smears the grain slightly
        ink = poolInk;
    }

    // --- Woodcut Finalization ---
    // Hard threshold to create the "carved" look
    // If ink > threshold, it's BLACK (the cut part), else WHITE (paper)
    float finalVal = step(0.5, ink);

    // Add the grain to the white parts (paper texture) but keep black parts solid
    // Or conversely, let the grain affect the ink density
    vec3 color = vec3(1.0) * (1.0 - finalVal); // White base
    color -= vec3(0.95) * finalVal * (0.9 + 0.1 * grain); // Black ink with slight grain variation

    // Slight vignette for the woodblock frame
    float vignette = 1.0 - length(uv * 0.8);
    color *= smoothstep(0.0, 0.9, vignette);

    fragColor = vec4(color, 1.0);
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    vec2 p = uv * vec2(1.6, 1.0); // Stretch for 4:3 CRT feel

    float t = iTime * 3.14159 * 2.0; // 2s loop at 2Hz base
    float loop = mod(iTime, 2.0);

    // --- Background: CRT Grid ---
    vec2 grid = abs(fract(p * 20.0 + 0.5) - 0.5);
    float gridColor = 0.02;
    if (grid.x < 0.05 || grid.y < 0.05) gridColor = 0.05; // Dim green scan lines
    vec3 bg = vec3(0.02, 0.04, 0.02) * gridColor;

    // --- The Filament Ignition ---
    // A procedural Lissajous figure that distorts based on "heating"
    float timeFactor = loop; // 0.0 to 2.0
    float heat = smoothstep(0.0, 1.5, loop); // Heat ramps up

    // Base shape: A horizontal sine wave (the filament)
    float yBase = sin(p.x * 8.0 + t * 4.0);

    // Ignition Jitter (High freq noise on the trace)
    float jitter = 0.0;
    if (loop < 1.2) {
        // Chaotic phase
        jitter = (fract(sin(p.x * 100.0 + loop * 50.0) * 1000.0) - 0.5) * 0.15 * (1.0 - loop/1.2);
    } else {
        // Settled hum (60Hz equivalent)
        jitter = sin(loop * 20.0) * 0.02 * cos(p.x * 5.0);
    }

    // The Trace Coordinate
    vec2 tracePos = vec2(p.x, yBase + jitter + 0.0);
    float dist = abs(p.y - tracePos.y);

    // Beam Width & Blur
    float width = 0.008 + heat * 0.005; // Gets slightly thicker as it heats
    float traceAlpha = 1.0 - smoothstep(0.0, width, dist);

    // Phosphor Trail (Oscilloscope persistence)
    // Create a slight smear behind the current position
    float smear = max(0.0, 1.0 - (dist - width) * 5.0) * 0.3;

    // --- Coloring: Thermal Gradient ---
    // Cold (dead tube) -> Orange -> White Hot
    vec3 cold = vec3(0.05, 0.05, 0.05);
    vec3 warm = vec3(1.0, 0.6, 0.1); // Orange glow
    vec3 hot  = vec3(1.0, 0.98, 0.9); // White core
    vec3 halo = vec3(0.6, 0.2, 1.0); // Violet halo from gas

    vec3 colorMix = mix(warm, hot, heat * 0.8);

    // Apply beam
    vec3 beam = mix(vec3(0.0), colorMix, traceAlpha);

    // Add the "Ignition" flare at the start
    if (loop < 0.5) {
        beam *= 1.5 + sin(t * 10.0) * 0.5; // Flickering start
        beam += halo * (1.0 - loop/0.5) * 0.2;
    }

    // Combine with background
    vec3 finalCol = bg + beam * (1.0 + smear);

    // Vignette for CRT tube
    float vignette = 1.0 - length(uv) * 1.2;
    finalCol *= max(0.0, vignette);

    // Scanline overlay (fine)
    float scanlines = sin(p.y * 400.0) * 0.05;
    finalCol -= vec3(scanlines);

    fragColor = vec4(finalCol, 1.0);
}

void main() {
    // 2-second loop
    float t = iTime;
    float loop = 2.0;
    float time = mod(t, loop);

    // Aspect ratio correction
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;
    uv.x *= iResolution.x / iResolution.y;

    // Isometric Projection Setup
    vec2 isoUV = uv * 1.5;

    // Map UV to isometric grid coordinates
    float x_iso = isoUV.x - isoUV.y;
    float y_iso = isoUV.x + isoUV.y;

    vec2 grid = vec2(x_iso, y_iso);
    vec2 gridFloor = floor(grid);
    vec2 gridFrac = fract(grid);

    vec3 color = vec3(0.02, 0.02, 0.05); // Dark background

    // Generate Static Snow (High frequency noise)
    vec2 seed = gl_FragCoord.xy;
    float noise = fract(sin(dot(seed, vec2(12.9898, 78.233))) * 43758.5453);
    // Fixed: Use step result directly for float, no ternary
    float snow = step(0.1, noise) * 0.8;

    // Piezo Crackle: Lightning based on time and grid
    float pulse = abs(sin(time * 10.0 + grid.x * 4.0) * cos(time * 12.0 + grid.y * 4.0));
    float threshold = 0.7 + 0.2 * sin(time * 6.0);
    float arc = smoothstep(threshold, threshold + 0.02, pulse);

    // Add a "crackle" jitter
    float jitter = fract(sin(time * 20.0 + dot(grid, vec2(3.4, 9.1))) * 43758.5453);

    // Fixed: Use smoothstep to create a boolean-like float for the condition
    float hasArc = step(0.1, jitter) * step(0.001, arc);

    if (hasArc > 0.5) {
        // Draw the arc
        vec3 arcColor = mix(vec3(0.1, 0.8, 1.0), vec3(1.0, 0.2, 0.9), smoothstep(0.0, 0.2, fract(time * 3.0)));
        color = mix(color, arcColor, arc * 1.5); // Overbrighten for glow
        snow = 0.0; // Arc burns away snow
    }

    // Isometric Face Coloring (Subtle shading)
    float faceVal = gridFrac.x + gridFrac.y;
    if (faceVal <= 1.0) {
        // Top Face
        color = mix(color, vec3(0.15, 0.15, 0.25), 0.3);
        if (snow > 0.5) color = vec3(0.8, 0.8, 0.9); // Snow on top
    } else {
        // Side faces
        color = mix(color, vec3(0.05, 0.05, 0.1), 0.5);
        if (snow > 0.5) color = vec3(0.5, 0.5, 0.6); // Snow on sides
    }

    // Depth cueing / cutaway effect
    // Fade out edges of the "cube" to simulate cutaway
    float dist = length(gridFrac - vec2(0.5));
    if (dist > 0.8) {
        color = vec3(0.0); // Outside the block
    }

    fragColor = vec4(color, 1.0);
}

vec2 hash2(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return -1.0 + 2.0 * fract(sin(p) * 43758.5453123);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    return mix(mix(hash2(i).x, hash2(i + vec2(1, 0)).x, f.x),
               mix(hash2(i + vec2(0, 1)).x, hash2(i + vec2(1, 1)).x, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 4; i++) {
        v += a * noise(p);
        p *= 2.0;
        a *= 0.5;
    }
    return v;
}

float arcPath(vec2 p, float t) {
    float cycle = fract(t * 0.5); 
    float progress = smoothstep(0.0, 0.3, cycle) - smoothstep(0.7, 1.0, cycle);
    if (progress <= 0.0) return 1.0;

    vec2 center = vec2(0.0, 0.0);
    vec2 p2 = p - center;
    float x = p2.x * 0.8;
    float y = p2.y * 1.2;
    float curve = sin(x * 3.14159) * 0.4;

    float dist = abs(y - curve);
    float jitter = noise(p * 50.0 + t * 20.0) * 0.02;

    float core = smoothstep(0.03 + jitter, 0.01, dist);
    return core * progress;
}

float woodGrain(vec2 p) {
    float n = fbm(p * 2.0);
    float g = p.x + n * 0.5;
    float lines = sin(g * 40.0 + fbm(p * 5.0) * 10.0);
    return smoothstep(0.9, 0.95, lines);
}

void main() {
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    uv.x *= 1.2;

    float t = iTime;

    float grain = woodGrain(uv);
    float baseColor = 0.85 + 0.15 * grain;

    float arc = arcPath(uv, t);

    float burn = smoothstep(0.0, 1.0, arc);
    float charred = baseColor * (1.0 - burn * 0.6);

    float glow = smoothstep(0.08, 0.0, abs(arc - 0.5) - 0.05);
    glow = pow(glow, 3.0);

    vec3 wood = vec3(0.5, 0.35, 0.2);
    vec3 char = vec3(0.05, 0.02, 0.01);
    vec3 plasma = vec3(0.4, 0.6, 1.0);
    vec3 hot = vec3(1.0, 0.8, 0.4);

    vec3 finalCol = mix(char, wood, grain);
    finalCol = mix(finalCol, vec3(0.05, 0.0, 0.0), burn * 0.8);
    finalCol += mix(plasma, hot, arc) * glow * 2.5;

    finalCol = floor(finalCol * 16.0) / 16.0;
    finalCol += 0.04;

    // Fixed: Use fract for halftone instead of %
    float d = distance(fract(gl_FragCoord.xy * 0.333333), vec2(0.5));
    if (d < 0.4) finalCol -= 0.1;

    fragColor = vec4(finalCol, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;

    // Normalize to centered UV, keep aspect
    vec2 p = uv * 2.0 - 1.0;
    p.x *= iResolution.x / iResolution.y;

    // 2-second loop factor
    float t = mod(iTime, 2.0);
    float loop = t / 2.0;

    // Steering: The Beam Path (Parabola bending into a hook)
    // The beam enters from bottom left, curves sharply right, then hooks up
    float bend = sin(loop * 3.14159) * 0.8 + 0.2;
    vec2 dir = vec2(1.0, 0.0);

    // Parametric curve for the electron beam
    float u = -p.x * 1.5 - 1.0;
    vec2 curve = vec2(u * 0.5, u * u * bend * 2.0 - 0.5);
    vec2 pos = vec2(-0.8, -0.8) + curve * 0.6;

    // Distance to the curve (approximate)
    vec2 diff = p - pos;
    float d = length(diff);

    // The "Electricity" Core: Hard, jagged edges, not smooth
    // Use high frequency noise on distance to create ionization spikes
    float n = sin(diff.x * 100.0 + t * 50.0) * cos(diff.y * 100.0 + t * 50.0);
    float spike = smoothstep(0.0, 0.5, abs(n));

    // Base beam width with pulsing intensity
    float core = 0.08 * (1.0 + 0.3 * sin(t * 3.14159 * 2.0));
    float beam = 1.0 - smoothstep(core - 0.01, core + 0.1, d);

    // Modulate beam with the "spike" to make it look like cracking energy
    beam *= (1.0 - 0.4 * spike);

    // Daguerreotype Effect:
    // 1. High contrast S-curve (Silver tone)
    // 2. Chemical Noise (Grain)
    // 3. Inverted/High-key lighting

    float grain = fract(sin(dot(p, vec2(12.9898, 78.233) + t)) * 43758.5453);

    // Combine beam with grain, only on the beam
    float signal = beam;

    // Add "hot spots" where the curve bends tightest
    float hotspot = exp(-length(p - vec2(0.2, -0.2)) * 10.0);
    signal += hotspot * 0.5 * (1.0 + 0.5 * sin(t * 20.0));

    // Daguerrotonic Tone Mapping:
    // Map [0, 1] to a silver-grey curve with heavy clipping
    // 0 -> Deep Silver/Black
    // 1 -> Blinding White (bleed)

    float silver = signal * 1.2;

    // Add grain to the whole plate, but stronger where signal is low
    float plateNoise = grain * 0.15 * (1.0 - signal);

    // Final Composition:
    // The background is a textured dark silver
    // The beam is white with grain
    // Everything has a "chemical" look

    vec3 color = vec3(silver - plateNoise);

    // Push contrast to extremes (Daguerreotype look)
    // Values > 1.0 become pure white (blooming)
    // Values < 0.0 become deep shadow

    color = smoothstep(0.0, 0.2, color) * smoothstep(1.2, 0.8, color) * 1.2;

    // Add a vignette that looks like a developing plate edge
    float vignette = 1.0 - smoothstep(0.5, 1.5, length(p * 1.5));
    color *= 1.0 + 0.2 * (1.0 - vignette);

    // Final tone: Cyan/Silver tint for the "vacuum" feel
    color = mix(vec3(0.85, 0.9, 0.95), vec3(1.0, 1.0, 1.0), color.r);

    // Bleed effect for the core
    float bleed = max(0.0, (signal - 0.9) * 5.0);
    color += vec3(bleed, bleed * 0.9, bleed * 0.8);

    fragColor = vec4(color, 1.0);
}

// Static Hair Eruption Engraving
// 19th Century Scientific Plate Style

float rand(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// Hard-edge noise for grain and ink texture (Scalar return)
float noise2d(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = rand(i);
    float b = rand(i + vec2(1.0, 0.0));
    float c = rand(i + vec2(0.0, 1.0));
    float d = rand(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

void main() {
    // Normalized coordinates centered
    vec2 uv = (gl_FragCoord.xy * 2.0 - iResolution.xy) / iResolution.y;
    vec2 p = uv;

    // Time loop: 0 to 1 over 2 seconds
    float t = mod(iTime, 2.0) * 0.5;
    float cycle = sin(t * 6.283) * 0.5 + 0.5;

    // Base paper color (aged white)
    vec3 col = vec3(0.92, 0.90, 0.88);

    // Seed lines for hair
    float dist = length(uv);
    float angle = atan(uv.y, uv.x);

    // Generate thousands of "seeds" using high-freq noise
    float seedDens = 150.0;
    vec2 seedUV = uv * seedDens;
    float n = noise2d(seedUV + vec2(angle * 5.0, t * 2.0));

    // Only render where noise is high (the hair tips)
    if (n > 0.82) {
        // Calculate hair length based on distance from center (longer near center)
        float baseLen = 0.15 * (1.0 - dist * 0.5) + 0.02;

        // Animate length: Eruption phase
        float len = baseLen * cycle * 1.2;

        // Direction of hair (radial + slight wind)
        vec2 dir = vec2(cos(angle), sin(angle));
        dir += vec2(-0.2, 0.5) * 0.1; // Slight upward drift

        // Trace the hair back from the tip to the origin
        // We are rendering a line from (p - dir*len) to p
        // But to make it look like an etching, we only draw the "ink" where the hair exists

        float distAlongHair = length(p - (p - dir * len)); // Distance from base

        // Only draw if we are close to the line defined by dir and len
        // Use a very thin, hard threshold for ink lines
        float crossDist = abs(dot(p - (p - dir * len), vec2(-dir.y, dir.x)));

        if (crossDist < 0.002 && distAlongHair < len && distAlongHair > 0.0) {
            // Tip flicker (static discharge)
            float tip = smoothstep(0.95, 0.99, distAlongHair / len);

            // Hard black ink
            col = vec3(0.05); 

            // Add slight jitter to the line for "grainy ink"
            if (rand(p + t * 10.0) > 0.9) {
                col += 0.1; // Break the line slightly
            }

            // Darken the base (the scalp/ground)
            if (distAlongHair < len * 0.1) {
                col = vec3(0.02);
            }
        }
    }

    // Add overall paper grain texture
    float grain = noise2d(p * 100.0 + t) * 0.15;
    col += grain * 0.1;

    // Vignette for plate focus
    float vig = 1.0 - smoothstep(0.8, 1.2, length(uv));
    col *= vig;

    // Hard threshold for the "engraved" look (no anti-aliasing on the black)
    if (col.r < 0.1) {
        col = vec3(0.0, 0.0, 0.0);
    } else {
        col = mix(vec3(0.92, 0.90, 0.88), col, 0.9);
    }

    fragColor = vec4(col, 1.0);
}

// Circuit Board Dielectric Breakdown - X-Ray Film Interpretation
// Theme: Electricity / Dielectric Rupture

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / min(iResolution.y, iResolution.x);

    // Time loop: 2.0s cycle, mapped to [0, 1] with a sharp attack/decay
    float t = fract(iTime / 2.0);
    // Create a "surge" curve: rises fast, decays slowly, mimicking a spark
    float surge = smoothstep(0.0, 0.3, t) * (1.0 - smoothstep(0.5, 0.9, t)) * (1.0 - t) * 3.0;

    // Coordinate distortion for the "breakdown" effect
    vec2 p = uv;

    // Base grid: The circuit traces (orthogonal, rigid)
    float grid = step(0.48, fract(p.x * 12.0) + fract(p.y * 12.0));

    // Fractal Lightning Generation (Iterated Function System-ish)
    // We create branching cracks radiating from the center
    vec2 c = p * 4.0;
    float f = 0.0;

    // 5 iterations of branching logic
    for(float i = 0.0; i < 5.0; i++) {
        c = fract(c * 1.5) - 0.5;
        float d = length(c) * exp(-length(p) * 2.0); // Distance from center

        // Add noise-driven jitter to the branching, but keep it sharp
        float s = sin(c.x * 10.0 + c.y * 13.0);
        float b = abs(s);

        // The "crack" appears when the surge is high and distance is low
        float crack = smoothstep(0.0, 0.1, b - d * (0.5 + surge * 2.0));
        f += crack * pow(0.6, i); // Fade branches as they get further out
    }

    // Combine grid and cracks
    float structure = max(grid * 0.4, f * 1.5);

    // X-Ray Film Look: Inverted contrast, specific color palette
    // Base: Deep Magenta (Silicon/Substrate)
    // Highlight: Cyan/White (Electrical Arc)

    vec3 filmBase = vec3(0.05, 0.1, 0.15); // Dark purple/grey film
    vec3 arcColor = vec3(0.1, 0.9, 1.0);   // Electric Cyan
    vec3 highlight = vec3(1.0, 1.0, 1.0);  // Pure White

    // Map structure to color
    // Low structure = Film Base
    // Mid structure = Arc Color
    // High structure = Highlight

    vec3 color = mix(filmBase, arcColor, smoothstep(0.0, 0.6, structure));
    color = mix(color, highlight, smoothstep(0.7, 1.0, structure * surge));

    // Add "grain" or "noise" to the x-ray film texture using a high frequency hash
    float noise = fract(sin(dot(gl_FragCoord.xy, vec2(12.9898, 78.233))) * 43758.5453);
    float filmGrain = (noise - 0.5) * 0.08 * (1.0 - structure); // Grain visible in dark areas

    color += filmGrain;

    // Vignette to focus on the breakdown
    float vignette = 1.0 - length(uv) * 0.6;
    vignette = clamp(vignette, 0.2, 1.0);
    color *= vignette;

    // Final intensity boost for the "X-Ray" punch
    color = pow(color, vec3(0.9)); // Slight gamma curve

    fragColor = vec4(color, 1.0);
}

vec2 hash21(vec2 p) {
    p = fract(p * vec2(234.3, 45.6));
    p += dot(p, p + 34.5);
    return -1.0 + 2.0 * fract(p);
}

float rand(float n) {
    return fract(sin(n * 12.9898) * 43758.5453);
}

void main() {
    float t = mod(iTime, 2.0);

    // VHS Tracking Distortion Base
    float trackError = sin(t * 12.0) * 0.05 + cos(t * 37.0) * 0.02;

    vec2 uv = gl_FragCoord.xy / iResolution.xy;

    // Apply horizontal skew based on tracking error
    uv.x += trackError * (0.5 - abs(uv.y - 0.5));
    uv = fract(uv);

    // Create Salt Crystal Lattice (Hexagonal/Grid hybrid)
    vec2 frac = fract(uv * 80.0) - 0.5;
    float crystal = length(frac);
    vec2 frac2 = fract(uv * 80.0 + 0.5);
    float crystal2 = length(frac2 - 0.5);
    float lattice = min(crystal, crystal2);
    float crystalMask = smoothstep(0.3, 0.35, lattice);

    // Electricity: Fractal Streamers
    float noise = 0.0;
    for (int i = 0; i < 4; i++) {
        vec2 p = uv * pow(2.0, float(i)) - vec2(float(i));
        vec2 n = hash21(p);
        noise += length(n - 0.5) * 0.5 * (1.0 / (1.0 + float(i)));
    }

    float pulse = sin(t * 10.0) * 0.5 + 0.5;
    float arcStrength = smoothstep(0.4, 0.45, noise + pulse * 0.2);

    float electric = arcStrength * (1.0 - crystalMask);

    vec3 colSalt = vec3(0.05, 0.02, 0.15);
    vec3 colArc = vec3(0.9, 1.0, 0.2) * (electric * 2.5);
    vec3 colBase = mix(colSalt, colArc, electric);

    // VHS Tracking Artifact Overlay
    float scanline = sin(uv.y * iResolution.y * 4.0) * 0.5 + 0.5;
    float vhsBleed = smoothstep(0.4, 1.0, scanline) * (0.05 + abs(trackError) * 2.0);

    vec3 c = colBase + vhsBleed * vec3(0.8, 0.0, 0.8);

    float staticNoise = rand(floor(uv.x * 100.0 + t * 50.0) + floor(uv.y * 100.0));
    c += staticNoise * abs(trackError) * 0.5;

    c = pow(c, vec3(0.9));

    fragColor = vec4(c, 1.0);
}

// Helper: Pseudo-random noise based on coordinates
float hash(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

// Helper: 2D Value Noise (coarse)
float noise(vec2 x) {
    vec2 i = floor(x);
    vec2 f = fract(x);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

// Helper: Fractal Brownian Motion for texture detail
float fbm(vec2 p) {
    float f = 0.0;
    float amp = 0.5;
    vec2 d = vec2(1.0);
    for(int i=0; i<4; i++) {
        f += amp * noise(p);
        p *= 2.0;
        amp *= 0.5;
    }
    return f;
}

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Time loop 0.0 to 2.0 -> 0.0 to 1.0
    float t = fract(iTime * 0.5);

    // Create the "Triode Grid" structure
    // We use a repeating pattern with distortion to simulate the grid bending under heat
    vec2 gridUV = uv * 6.0;
    float gridX = abs(fract(gridUV.x) - 0.5);
    float gridY = abs(fract(gridUV.y) - 0.5);

    // The "Grid" is the intersection of these bars, but we invert it so bars are dark
    float gridMask = smoothstep(0.05, 0.0, gridX) * smoothstep(0.05, 0.0, gridY);

    // Animate the grid: it vibrates and expands during the flare
    float pulse = sin(t * 3.14159 * 2.0); // 0 to 1 to 0 over the loop
    float expansion = 0.0 + pulse * 0.05;
    gridUV *= (1.0 - expansion);

    // Re-evaluate grid position after expansion
    float gX = abs(fract(gridUV.x) - 0.5);
    float gY = abs(fract(gridUV.y) - 0.5);
    float gBars = smoothstep(0.06, 0.0, gX) * smoothstep(0.06, 0.0, gY);

    // "Ionization" Flare
    // Calculate distance to nearest grid intersection
    float dist = length(vec2(gX, gY));

    // The flare triggers at the midpoint of the loop (t=0.5)
    float flareTrigger = smoothstep(0.4, 0.6, t) * smoothstep(0.6, 0.4, t);

    // Procedural "Sumi-e" Ink Wash
    // Base texture is high-frequency noise + FBM to create wet paper look
    float inkNoise = fbm(uv * 15.0 + t * 0.2);

    // The Flare: Invert logic. High voltage = bright white/blue.
    // The flare "eats" the ink, replacing it with plasma.
    // We use a hard threshold for the electric snap
    float voltage = (0.08 - dist) * flareTrigger * 8.0;
    voltage = max(0.0, voltage);

    // Add jaggedness to the electric arc (like lightning)
    float arcNoise = noise(uv * 20.0 + t * 10.0);
    voltage += arcNoise * 0.1 * flareTrigger;

    // Color mixing
    // Base: Sumi-e Black (with texture)
    vec3 inkColor = vec3(0.05, 0.06, 0.08) * (0.8 + inkNoise * 0.4);

    // The "Ink" gets pushed out or thinned by the electric field
    float inkDensity = mix(1.0, 0.2, smoothstep(0.0, 1.0, voltage));
    inkColor *= inkDensity;

    // The Flare Color: Cyan/White plasma
    vec3 plasmaColor = vec3(0.2, 0.9, 1.0) * (1.0 + voltage * 2.0);

    // Compositing: Hard edge for the electric snap
    vec3 finalColor = mix(inkColor, plasmaColor, smoothstep(0.0, 0.5, voltage));

    // Add a secondary "spark" effect at the very peak of the flare
    if(t > 0.45 && t < 0.55) {
        float spark = sin(uv.x * 30.0 + uv.y * 30.0 + t * 100.0);
        if(spark > 0.9) {
            finalColor = vec3(1.0, 0.8, 0.5); // Hot core
        }
    }

    // Vignette to focus on the center
    float vignette = 1.0 - length(uv) * 0.4;
    finalColor *= vignette;

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / iResolution.xy;
    uv = uv * 2.0 - 1.0;
    uv.x *= iResolution.x / iResolution.y;

    float t = iTime * 3.14159;
    float loopT = fract(iTime / 2.0) * 2.0; // 2s loop factor

    // Loom Grid Definition
    float gridScale = 12.0;
    vec2 gridUV = fract(uv * gridScale) - 0.5;
    vec2 gridPos = floor(uv * gridScale);

    // Warp (Vertical) and Weft (Horizontal) thread modulation
    float warp = sin(t + gridPos.x * 0.5) * 0.02 + 0.01;
    float weft = cos(t + gridPos.y * 0.5) * 0.02 + 0.01;

    // Data Stream (The Electric Arc)
    // Create a traveling wave of "current" across the loom
    float streamX = sin(loopT * 4.0 + uv.y * 2.0 + gridPos.x * 0.1) * 0.5 + 0.5;
    float streamY = cos(loopT * 4.0 + uv.x * 2.0 + gridPos.y * 0.1) * 0.5 + 0.5;

    // Interference pattern where the stream hits the grid
    float interference = (streamX + streamY) * 0.8;

    // Phosphor Bloom Logic
    // Calculate distance to nearest grid intersection (where threads cross)
    float dInter = length(gridUV);

    // Thread thickness based on warp/weft modulation
    float threadWidth = max(warp, weft);

    // Create the woven texture base
    float weave = step(dInter, threadWidth);

    // Add the electric charge
    // The charge is strongest at the intersections when the stream hits
    float charge = smoothstep(0.6, 0.9, interference) * 
                  (1.0 / (dInter * 2.0 + 0.1)); // Inverse distance falloff

    // Color Palette: Phosphor Glow (Black -> Amber -> Magenta -> White)
    vec3 colBase = vec3(0.05, 0.02, 0.1); // Dark background
    vec3 colThread = vec3(0.2, 0.15, 0.3); // Woven fabric color
    vec3 colGlow = vec3(1.0, 0.4, 0.9);    // Magenta/Amber mix
    vec3 colHot = vec3(1.0, 0.9, 1.0);     // White hot

    // Mix colors
    vec3 color = mix(colBase, colThread, weave);

    // Add bloom only where charge is high
    // Use a custom falloff to make it look like a glowing filament
    float bloomInt = max(0.0, charge - 1.5) * 0.5;
    bloomInt = clamp(pow(bloomInt, 0.7), 0.0, 1.0); // Soften the peak

    color += colGlow * bloomInt * 2.0;
    color += colHot * pow(bloomInt, 3.0); // Core whiteness

    // Add CRT scanline artifact for texture
    float scan = sin(uv.y * iResolution.y * 2.0) * 0.5 + 0.5;
    scan = pow(scan, 50.0) * 0.15; // Sharp lines
    color += vec3(0.1, 0.0, 0.1) * scan;

    // Vignette to focus on the loom center
    float vign = 1.0 - length(uv * 0.8);
    color *= vign;

    fragColor = vec4(color, 1.0);
}
